              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <label className="block text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest pl-1">Personalizar Color</label>
                  <div className="flex items-center gap-2">
                    <input 
                      type="color" 
                      value={selectedColor} 
                      onChange={e => setSelectedColor(e.target.value)}
                      className="w-10 h-10 border-0 bg-transparent cursor-pointer rounded-full overflow-hidden shadow-sm transition-transform hover:scale-105"
                    />
                    <Palette size={16} className="text-slate-400 dark:text-slate-600" />
                  </div>
                </div>
                <div className="flex flex-wrap gap-2">
                  {BUDGET_PRESET_COLORS.map(c => (
                    <button 
                      key={c}
                      type="button"
                      onClick={() => setSelectedColor(c)}
                      className={`w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 ${selectedColor === c ? 'border-slate-900 dark:border-white scale-110' : 'border-transparent'}`}
                      style={{ backgroundColor: c }}
                    />
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest pl-1">Categoría</label>
                <div className="relative">
                  <select 
                    value={category} 
                    onChange={e => {
                      setCategory(e.target.value);
                      const isAnother = e.target.value === 'Otra';
                      setIsCustomMode(isAnother);
                      if(!isAnother) {
                        const defaultList = activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
                        const match = defaultList.find(c => c.name === e.target.value);
                        if(match) {
                          setSelectedIcon(match.icon);
                          setSelectedColor(match.color);
                        }
                      }
                    }}
                    className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-black text-slate-800 dark:text-white focus:bg-white dark:focus:bg-slate-900 focus:border-blue-400 dark:focus:border-blue-600 outline-none transition-all appearance-none cursor-pointer"
                    required
                  >
                    {(activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES).map(c => (
                      <option key={c.name} value={c.name} className="dark:bg-slate-900">{c.name}</option>
                    ))}
                    <option value="Otra" className="dark:bg-slate-900">-- Personalizada --</option>
                  </select>
                  <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 dark:text-slate-600 pointer-events-none" size={20} />
                </div>
                {isCustomMode && (
                  <input type="text" placeholder="Nombre de categoría..." className="w-full bg-blue-50 dark:bg-blue-900/20 border-2 border-blue-100 dark:border-blue-900 rounded-2xl p-5 font-black text-blue-900 dark:text-blue-300 outline-none animate-in slide-in-from-top-2" value={customCategory} onChange={e => setCustomCategory(e.target.value)} required />
                )}
              </div>

              <div className="space-y-4">
                <label className="block text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest pl-1">Importe Mensual (€)</label>
                <input 
                  type="number" 
                  value={limit} 
                  onChange={e => setLimit(e.target.value === '' ? '' : Number(e.target.value))} 
                  className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-6 text-center text-4xl font-black text-slate-900 dark:text-white outline-none" 
                  placeholder="0" 
                  required 
                />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => { setIsCreating(false); setIsEditing(null); }} className="flex-1 py-5 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-black rounded-2xl transition-colors">CANCELAR</button>
                <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100 dark:shadow-none flex items-center justify-center gap-2 transition-all active:scale-[0.98]">{isEditing ? <Edit2 size={18}/> : <Plus size={18}/>}{isEditing ? 'GUARDAR' : 'CREAR'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetManager;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  X, 
  UserCheck, 
  AlertCircle, 
  Check, 
  PiggyBank, 
  ChevronDown, 
  Split,
  Camera,
  Loader2,
  Sparkles,
  ArrowRightLeft,
  ArrowRight,
  Ban
} from 'lucide-react';
import { Transaction } from '../types';
import { analyzeReceipt, ScannedTransaction } from '../services/geminiService';

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, theme, currentDate, viewMode } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  // Aura Vision States
  const [isScanning, setIsScanning] = useState(false);
  const [scannedQueue, setScannedQueue] = useState<ScannedTransaction[]>([]);
  const [totalScannedCount, setTotalScannedCount] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const location = useLocation();

  // Form states
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  // Extra states for Transfer
  const [isTransfer, setIsTransfer] = useState(false);
  const [transferTargetId, setTransferTargetId] = useState('');

  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];

    // Si es un ingreso y es un reembolso, las categorías deberían ser las de los gastos originales
    // o la categoría del reembolso vinculado.
    if (type === 'income' && isRefundLink) {
      const selectedRefund = refunds.find(r => r.id === selectedRefundId);
      if (selectedRefund) {
        return [selectedRefund.category]; // La categoría se toma del reembolso vinculado
      }
      // Si no hay un reembolso seleccionado todavía, ofrecemos todas las categorías de gasto
      return Array.from(new Set(budgets.filter(b => b.type === 'expense').map(b => b.category)));
    }

    // Lógica normal para gastos y ingresos no-reembolso
    const budgetList = budgets
      .filter(b => b.type === type)
      .map(b => b.category);
    const uniqueCategories = Array.from(new Set(budgetList));
    return uniqueCategories.length > 0 ? uniqueCategories : ["Sin Presupuesto"];
  }, [type, isRefundLink, selectedRefundId, budgets, refunds]); // Actualizado el array de dependencias

  useEffect(() => {
    // Si la categoría actual no está en las disponibles (por un cambio de tipo/reembolso),
    // o si el campo está vacío, selecciona la primera categoría disponible.
    if (!availableCategories.includes(category) || category === '') {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories, category]); // Asegura que `category` se actualice si las `availableCategories` cambian

  // Efecto para autocompletar la categoría si un reembolso es seleccionado
  useEffect(() => {
    if (type === 'income' && isRefundLink && selectedRefundId) {
      const refundObj = refunds.find(r => r.id === selectedRefundId);
      if (refundObj) {
        setCategory(refundObj.category);
      }
    }
  }, [type, isRefundLink, selectedRefundId, refunds]);


  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory(availableCategories[0] || ''); // Asegura que la categoría se restablece correctamente
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setSelectedSavingId('');
    setMyPartManual('');
    setIsTransfer(false);
    setTransferTargetId('');
    setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    const isSavingType = tx.type === 'expense' && !!tx.savingId;
    setType(isSavingType ? 'saving' : tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setSelectedSavingId(tx.savingId || '');
    setIsAdding(true);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleDeleteFromModal = (id: string) => {
    deleteTransaction(id);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onload = async () => {
      const base64 = (reader.result as string).split(',')[1];
      try {
        const items = await analyzeReceipt(base64);
        const reversedItems = [...items].reverse();
        setScannedQueue(reversedItems);
        setTotalScannedCount(reversedItems.length);
        if (reversedItems.length > 0) {
          loadScannedItem(reversedItems[0]);
          setIsAdding(true);
        }
      } catch (err) {
        console.error(err);
      } finally {
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const loadScannedItem = (item: ScannedTransaction) => {
    setDesc(item.description);
    setAmount(item.amount);
    setDate(item.date);
    setType(item.isSaving ? 'saving' : item.type);
    setIsTransfer(item.isTransfer);
    setIsRefundLink(item.isRefund);
    setCategory(item.category);

    if (item.suggestedAccount) {
      const matched = accounts.find(a => a.name.toLowerCase().includes(item.suggestedAccount!.toLowerCase()));
      if (matched) setAccountId(matched.id);
    }
  };

  const handleDiscardCurrentScanned = () => {
    const nextQueue = scannedQueue.slice(1);
    setScannedQueue(nextQueue);
    if (nextQueue.length > 0) {
      loadScannedItem(nextQueue[0]);
    } else {
      setIsAdding(false);
      resetForm();
    }
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (isTransfer) {
      addTransaction({
        date,
        amount: Number(amount),
        description: `Transferencia a ${accounts.find(a => a.id === transferTargetId)?.name || 'Cuenta'}`,
        category: 'Traspaso',
        type: 'expense',
        accountId,
        isRefund: false
      });
      addTransaction({
        date,
        amount: Number(amount),
        description: `Transferencia desde ${accounts.find(a => a.id === accountId)?.name || 'Cuenta'}`,
        category: 'Traspaso',
        type: 'income',
        accountId: transferTargetId,
        isRefund: false
      });
    } else {
      const finalType = type === 'saving' ? 'expense' : type;
      const finalCategory = type === 'saving' ? 'Ahorro' : category; // La categoría para un refund income se gestiona en el useEffect

      if (editingTx) {
        updateTransaction({
          ...editingTx,
          date,
          amount: Number(amount),
          description: desc,
          category: finalCategory,
          type: finalType as any,
          accountId,
          refundId: finalType === 'income' && isRefundLink ? selectedRefundId : undefined, // refundId solo si es income y es reembolso
          savingId: type === 'saving' ? selectedSavingId : undefined
        });
      } else {
        addTransaction({
          date,
          amount: Number(amount),
          description: desc,
          category: finalCategory,
          type: finalType as any,
          accountId,
          isRefund: isRefundLink,
          refundId: finalType === 'income' && isRefundLink ? selectedRefundId : undefined, // refundId solo si es income y es reembolso
          savingId: type === 'saving' ? selectedSavingId : undefined
        }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
      }
    }

    const nextQueue = scannedQueue.slice(1);
    setScannedQueue(nextQueue);
    if (nextQueue.length > 0) {
      loadScannedItem(nextQueue[0]);
    } else {
      setIsAdding(false);
      resetForm();
    }
  };

  const filteredTx = useMemo(() => {
    return transactions
      .filter(t => {
        // Filtro por Periodo (Mes o Año)
        const matchesPeriod = t.date.startsWith(currentDate);
        if (!matchesPeriod) return false;

        // Filtro por Tipo de Vista
        let matchesType = true;
        const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
        const isRefundIncome = t.type === 'income' && !!t.refundId; // Ingresos que son reembolsos
        const isSharedExpense = t.type === 'expense' && !!t.refundId && !isSaving; // Gastos que son deudas compartidas (no ahorros)

        if (filter === 'income') matchesType = t.type === 'income' && !isRefundIncome; // Ingresos puros
        else if (filter === 'expense') matchesType = t.type === 'expense' && !isSaving && !isSharedExpense; // Gastos puros
        else if (filter === 'savings') matchesType = isSaving;
        else if (filter === 'refunds') matchesType = isRefundIncome || isSharedExpense; // Ambos lados de un reembolso

        // Filtro por Búsqueda
        const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                              t.category.toLowerCase().includes(searchTerm.toLowerCase());

        return matchesType && matchesSearch;
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, filter, searchTerm, currentDate]);

  const getTxStyle = (t: Transaction) => {
    const isSaving = t.type === 'expense' && (t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId);
    const isRefundIncome = t.type === 'income' && !!t.refundId;
    const isSharedExpense = t.type === 'expense' && !!t.refundId && !isSaving;

    if (isSaving) return { color: 'text-amber-500', bg: 'bg-amber-50 dark:bg-amber-900/40', icon: <PiggyBank size={18} /> }; 
    if (isRefundIncome) return { color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-900/40', icon: <ArrowRightLeft size={18} /> }; 
    if (isSharedExpense) return { color: 'text-purple-600 dark:text-purple-400', bg: 'bg-purple-50 dark:bg-purple-900/40', icon: <Split size={18} /> };
    if (t.type === 'income') return { color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-900/40', icon: <ArrowUpRight size={18} /> }; 
    return { color: 'text-rose-600 dark:text-rose-400', bg: 'bg-rose-50 dark:bg-rose-900/40', icon: <ArrowDownRight size={18} /> }; 
  };

  const isCategoryFieldDisabled = useMemo(() => {
    return type === 'income' && isRefundLink && selectedRefundId !== '';
  }, [type, isRefundLink, selectedRefundId]);


  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4 transition-colors">

      {/* Overlay de Carga para Aura Vision */}
      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/90 z-[100] flex flex-col items-center justify-center p-6 text-center">
          <div className="relative mb-8">
            <div className="w-32 h-32 border-4 border-blue-500/20 rounded-full border-t-blue-500 animate-spin"></div>
            <Sparkles className="absolute inset-0 m-auto text-blue-500 animate-pulse" size={48} />
          </div>
          <h3 className="text-2xl font-black text-white mb-2">Aura Vision Procesando</h3>
          <p className="text-slate-400 max-w-xs">He recibido tu imagen. Estoy extrayendo y categorizando cada movimiento para ti...</p>
