                              className={`w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none appearance-none text-slate-900 dark:text-white ${isCategoryFieldDisabled ? 'opacity-60 grayscale cursor-not-allowed' : ''}`} 
                              required
                            >
