import React, { useState } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  CheckCircle2, 
  Users, 
  Trash2, 
  Merge, 
  X, 
  Edit3, 
  Save, 
  MessageSquare,
  Check,
  TrendingUp,
  AlertCircle,
  AlignLeft,
  ChevronDown
} from 'lucide-react';
import { Refund } from '../types';
import { CATEGORIES } from '../constants';

const Refunds: React.FC = () => {
  const { refunds, addRefund, updateRefund, deleteRefund, mergeRefunds } = useFinance();

  // UI States
  const [isAdding, setIsAdding] = useState(false);
  const [isMerging, setIsMerging] = useState(false);
  const [mergeSelection, setMergeSelection] = useState<string[]>([]);
  const [filter, setFilter] = useState<'all' | 'open' | 'closed'>('open');
  const [selectedRefundId, setSelectedRefundId] = useState<string | null>(null);

  // Form state
  const [name, setName] = useState('');
  const [total, setTotal] = useState<number | ''>('');
  const [myPart, setMyPart] = useState<number | ''>('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0].name);

  // Notes editing in Modal
  const [modalNotes, setModalNotes] = useState('');

  // Encuentra el reembolso actualmente seleccionado desde el estado global
  const selectedRefund = refunds.find(r => r.id === selectedRefundId);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (total === '' || myPart === '') return;
    const pending = total - myPart;
    addRefund({
      name,
      totalAmount: total,
      paidByMe: myPart,
      pendingAmount: pending,
      status: pending <= 0 ? 'closed' : 'open',
      notes,
      date: new Date().toISOString(),
      category: category
    });
    setIsAdding(false);
    resetForm();
  };

  const resetForm = () => { setName(''); setTotal(''); setMyPart(''); setNotes(''); setCategory(CATEGORIES[0].name); };

  const handleCardClick = (r: Refund) => {
    if (isMerging) {
      setMergeSelection(prev => {
        if (prev.includes(r.id)) return prev.filter(x => x !== r.id);
        if (prev.length >= 2) return prev; 
        return [...prev, r.id];
      });
    } else {
      setSelectedRefundId(r.id);
      setModalNotes(r.notes || '');
    }
  };

  const executeMerge = () => {
    if (mergeSelection.length === 2) {
      mergeRefunds(mergeSelection[0], mergeSelection[1]);
      setMergeSelection([]);
      setIsMerging(false);
    }
  };

  const handleActionClick = (e: React.MouseEvent, action: () => void) => {
    e.stopPropagation();
    e.preventDefault();
    action();
  };

  const handleSaveNotes = () => {
    if (selectedRefund) {
        updateRefund({ ...selectedRefund, notes: modalNotes });
        setSelectedRefundId(null);
    }
  };

  const filteredRefunds = refunds.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Reembolsos</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight">Gestiona deudas pendientes. Los cobros reducen el gasto neto del mes.</p>
        </div>
        <div className="flex gap-2">
          {isMerging && mergeSelection.length === 2 && (
             <button 
                type="button"
                onClick={executeMerge}
                className="flex items-center gap-2 px-6 py-3 bg-amber-600 text-white font-bold rounded-2xl shadow-lg hover:bg-amber-700 transition-all animate-in zoom-in"
             >
                <Check size={18} /> CONFIRMAR FUSIÓN
             </button>
          )}

          {refunds.length >= 2 && (
            <button 
              type="button"
              onClick={() => {
                setIsMerging(!isMerging);
                setMergeSelection([]);
              }}
              className={`flex items-center gap-2 px-6 py-3 font-bold rounded-2xl transition-all shadow-sm ${isMerging ? 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300' : 'bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
            >
              <Merge size={18} />
              {isMerging ? 'Cancelar' : 'Unificar Deudas'}
            </button>
          )}
          <button 
            type="button"
            onClick={() => setIsAdding(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
          >
            <Plus size={18} />
            Nuevo Reembolso
          </button>
        </div>
      </div>

      <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl w-fit border border-slate-200 dark:border-slate-700 shadow-inner">
        <button type="button" onClick={() => setFilter('open')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'open' ? 'bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>PENDIENTES</button>
        <button type="button" onClick={() => setFilter('closed')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'closed' ? 'bg-white dark:bg-slate-700 text-emerald-600 dark:text-emerald-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>COMPLETADOS</button>
        <button type="button" onClick={() => setFilter('all')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'all' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-slate-100 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>TODOS</button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredRefunds.map(r => (
          <div 
            key={r.id} 
            onClick={() => handleCardClick(r)}
            className={`bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border transition-all relative overflow-hidden group flex flex-col duration-300 cursor-pointer ${
              isMerging && mergeSelection.includes(r.id) ? 'border-amber-500 ring-4 ring-amber-100 dark:ring-amber-900/30 scale-[1.02] shadow-xl' : 
              r.status === 'closed' ? 'border-slate-100 dark:border-slate-800 opacity-80 shadow-sm' : 'border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md'
            }`}
          >
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${r.status === 'closed' ? 'bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-600' : 'bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400'}`}>
                  <Users size={22} />
                </div>
                <div>
                  <h4 className="font-bold text-slate-800 dark:text-slate-100 line-clamp-1">{r.name}</h4>
                  <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{r.category} • {new Date(r.date).toLocaleDateString()}</p>
                </div>
              </div>
              <button 
                type="button"
                onClick={(e) => handleActionClick(e, () => deleteRefund(r.id))}
                className="p-2.5 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 transition-all"
              >
                <Trash2 size={18} />
              </button>
            </div>

            <div className={`rounded-3xl p-6 border transition-all space-y-4 ${r.status === 'closed' ? 'bg-slate-50 dark:bg-slate-800/50 border-slate-200 dark:border-slate-800' : 'bg-blue-50/50 dark:bg-blue-900/20 border-blue-100 dark:border-blue-900/50 shadow-sm'}`}>
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-[10px] text-slate-400 dark:text-slate-500 uppercase font-bold mb-1">Pendiente</p>
                  <p className={`text-3xl font-black ${r.status === 'closed' ? 'text-slate-400 dark:text-slate-600 line-through' : 'text-blue-600 dark:text-blue-400'}`}>{r.pendingAmount.toLocaleString()}€</p>
                </div>
                {!isMerging && (
                    <div className="bg-white dark:bg-slate-800 p-2 rounded-full shadow-sm text-slate-400">
                        <ChevronDown size={16} />
                    </div>
                )}
              </div>
            </div>

            {r.status === 'open' && !isMerging && (
              <div className="mt-4">
                <button 
                  type="button"
                  onClick={(e) => handleActionClick(e, () => updateRefund({ ...r, status: 'closed', pendingAmount: 0 }))}
                  className="w-full flex items-center justify-center gap-2 p-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 rounded-2xl text-xs font-bold hover:bg-emerald-50 dark:hover:bg-emerald-900/40 hover:text-emerald-600 dark:hover:text-emerald-400 hover:border-emerald-200 dark:hover:border-emerald-800 transition-all active:scale-95"
                >
                  <CheckCircle2 size={16} className="text-slate-300 dark:text-slate-600" />
                  Marcar como cobrado
                </button>
              </div>
            )}
          </div>
        ))}
      </div>

      {selectedRefund && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4" onClick={() => setSelectedRefundId(null)}>
            <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100 dark:border-slate-800" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-8">
                    <div>
                        <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tight">{selectedRefund.name}</h3>
                        <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{selectedRefund.category} • Detalles</p>
                    </div>
                    <button onClick={() => setSelectedRefundId(null)} className="p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={24} /></button>
                </div>

                <div className="space-y-4 mb-8">
                    <div className="bg-slate-50 dark:bg-slate-800/50 p-5 rounded-2xl border border-slate-100 dark:border-slate-800 flex justify-between items-center">
                        <span className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">Mi Parte</span>
                        <span className="text-lg font-black text-slate-800 dark:text-white">{selectedRefund.paidByMe.toLocaleString()}€</span>
                    </div>

                    <div className="bg-emerald-50 dark:bg-emerald-900/20 p-5 rounded-2xl border border-emerald-100 dark:border-emerald-800/50 flex justify-between items-center">
                        <span className="text-xs font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest">Cobrado (Recibido)</span>
                        <span className="text-lg font-black text-emerald-700 dark:text-emerald-300">
                            {Math.max(0, (selectedRefund.totalAmount - selectedRefund.paidByMe) - selectedRefund.pendingAmount).toLocaleString()}€
                        </span>
                    </div>

                    <div className="bg-blue-50 dark:bg-blue-900/20 p-5 rounded-2xl border border-blue-100 dark:border-blue-800/50 flex justify-between items-center">
                        <span className="text-xs font-black text-blue-600 dark:text-blue-400 uppercase tracking-widest">Total Operación</span>
                        <span className="text-lg font-black text-blue-700 dark:text-blue-300">{selectedRefund.totalAmount.toLocaleString()}€</span>
                    </div>
                </div>

                <div className="space-y-3">
                    <label className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                        <AlignLeft size={14} /> Notas y Detalles
                    </label>
                    <textarea 
                        className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-4 text-sm font-medium text-slate-700 dark:text-slate-300 focus:border-blue-500 outline-none resize-none h-32 transition-colors"
                        placeholder="Escribe aquí quién te ha pagado, fechas o recordatorios..."
                        value={modalNotes}
                        onChange={(e) => setModalNotes(e.target.value)}
                    />
                </div>

                <button 
                    onClick={handleSaveNotes}
                    className="w-full mt-6 py-4 bg-slate-900 dark:bg-blue-600 text-white font-black rounded-2xl hover:bg-slate-800 dark:hover:bg-blue-700 transition-all active:scale-95 shadow-xl shadow-slate-200 dark:shadow-none"
                >
                    GUARDAR CAMBIOS
                </button>
            </div>
        </div>
      )}

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8">
               <h3 className="text-2xl font-black text-slate-800 dark:text-white tracking-tight">Nuevo Reembolso</h3>
               <button type="button" onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Concepto</label>
                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 outline-none font-medium text-slate-900 dark:text-white" placeholder="Cena..." required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Importe Total</label>
                  <input type="number" value={total} onChange={e => setTotal(Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Tu parte</label>
                  <input type="number" value={myPart} onChange={e => setMyPart(Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white" required />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Categoría a la que pertenece</label>
                <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white">
                  {CATEGORIES.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                </select>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl active:scale-95 shadow-xl shadow-blue-100 dark:shadow-none">Crear</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Refunds;

import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2,
  ChevronRight,
  Sparkles,
  Loader2,
  ShoppingBag,
  AlertCircle,
  History,
  X
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { generateAIChallenges } from '../services/geminiService';
import { Budget, Transaction } from '../types';
import { ICON_MAP } from '../constants'; // Importar ICON_MAP

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    budgets,
    currentDate,
    dashboardLayout,
    updateLayout,
    setChallenges,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    getNetWorthHistorical, // Now using the new function
    viewMode,
    theme
  } = useFinance();

  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');
  const [showBreakdown, setShowBreakdown] = useState(false);
  const [isGeneratingChallenges, setIsGeneratingChallenges] = useState(false);
  const [selectedBudgetForDetails, setSelectedBudgetForDetails] = useState<Budget | null>(null); // New state for modal
  const [isBudgetsExpanded, setIsBudgetsExpanded] = useState(false); // Estado para expandir/colapsar presupuestos

  // Helper para identificar transacciones de ahorro
  const isSavingTx = (t: any) => t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;

  // Lógica Financiera Corregida
  const metrics = useMemo(() => {
    let prevDateStr: string;
    if (viewMode === 'year') {
      prevDateStr = (parseInt(currentDate) - 1).toString();
    } else {
      const parts = currentDate.split('-').map(Number);
      const date = new Date(parts[0], parts[1] - 2, 1);
      const y = date.getFullYear();
      const m = String(date.getMonth() + 1).padStart(2, '0');
      prevDateStr = `${y}-${m}`;
    }

    const pastLiquidBalance = accounts.reduce((sum, acc) => sum + getAccountHistoricalBalance(acc.id, prevDateStr), 0);
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));

    const income = monthTx
      .filter(t => t.type === 'income' && !t.refundId && !isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    const refundRecoveries = monthTx
      .filter(t => t.type === 'income' && t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    const spendingExits = monthTx
      .filter(t => t.type === 'expense' && !isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    const netSpending = Math.max(0, spendingExits - refundRecoveries);

    const monthSavings = monthTx
      .filter(t => t.type === 'expense' && isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    const monthResult = income - netSpending - monthSavings;
    const liquidity = pastLiquidBalance + monthResult;
    const totalSavingsAccumulated = savings.reduce((sum, s) => sum + getSavingHistoricalBalance(s.id, currentDate), 0);
    const netWorth = liquidity + totalSavingsAccumulated;

    return {
      income,
      expense: netSpending,
      monthSavings,
      monthResult,
      pastLiquidBalance,
      liquidity,
      totalSavingsAccumulated,
      netWorth,
      refundRecoveries
    };
  }, [transactions, currentDate, accounts, savings, getAccountHistoricalBalance, getSavingHistoricalBalance, viewMode]);

  // AI Challenges Auto-Evaluator
  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;

      if (ch.type === 'spending_limit') {
        const spent = monthTx
          .filter(t => t.type === 'expense' && t.category === ch.category)
          .reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavingsAccumulated >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.income >= ch.target;
      }

      return { ...ch, completed: isCompleted || ch.completed };
    });
  }, [challenges, transactions, currentDate, metrics]);

  // Chart Data
  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;

    // Parse current date
    const currentYear = parseInt(currentDate.substring(0, 4));
    const currentMonthIndex = viewMode === 'month' ? parseInt(currentDate.substring(5, 7)) - 1 : 11; // 0-indexed month, for year view use Dec (11)

    const data = Array.from({ length: limit }).map((_, i) => {
        const date = new Date(currentYear, currentMonthIndex, 1);
        date.setMonth(date.getMonth() - (limit - 1 - i)); // Go back (limit - 1 - i) months from current period

        const displayMonthIndex = date.getMonth();
        const displayYear = date.getFullYear();

        // Construct the date string for calculation based on viewMode
        const dateStrForCalculation = viewMode === 'year' 
            ? displayYear.toString() 
            : `${displayYear}-${String(displayMonthIndex + 1).padStart(2, '0')}`;

        const patrimonio = getNetWorthHistorical(dateStrForCalculation); // Use the actual historical net worth

        return {
            name: monthNames[displayMonthIndex], // E.g., "Jul" for current, "Jun" for previous, etc.
            fullLabel: `${monthNames[displayMonthIndex]} ${displayYear}`, // For tooltip
            patrimonio: patrimonio // Actual historical net worth
        };
    });
    return data;
  }, [getNetWorthHistorical, chartFilter, currentDate, viewMode]); // Added getNetWorthHistorical and viewMode as dependencies

  const handleGenerateChallenges = async () => {
    setIsGeneratingChallenges(true);
    try {
      // Usar valores calculados dinámicamente para el contexto de la IA
      const budgetsInfo = budgets.map(b => {
        const calculatedSpent = transactions
          .filter(t => t.date.startsWith(currentDate) && t.category === b.category)
          .reduce((sum, t) => {
            if (b.type === 'expense') {
              if (t.type === 'expense') return sum + t.amount;
              if (t.type === 'income' && t.refundId) return sum - t.amount;
            }
            if (b.type === 'income' && t.type === 'income') return sum + t.amount;
            return sum;
          }, 0);
        return `${b.category}: ${calculatedSpent}/${b.limit}€`;
      }).join(", ");

      const context = `Presupuestos: ${budgetsInfo}. Patrimonio: ${metrics.netWorth}€. Ahorros: ${metrics.totalSavingsAccumulated}€.`;
      const newChallenges = await generateAIChallenges(context);
      setChallenges(newChallenges);
    } catch (error) {
      console.error("Error generating challenges:", error);
    } finally {
      setIsGeneratingChallenges(false);
    }
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newLayout = [...dashboardLayout];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLayout.length) return;
    [newLayout[index], newLayout[targetIndex]] = [newLayout[targetIndex], newLayout[index]];
    updateLayout(newLayout);
  };

  // Cálculo dinámico de presupuestos con su gasto real (para Dashboard)
  const budgetsWithCalculatedSpent = useMemo(() => {
    return budgets.map(b => {
      const calculatedSpent = transactions
        .filter(t => t.date.startsWith(currentDate) && t.category === b.category)
        .reduce((sum, t) => {
          // Para presupuestos de gasto:
          if (b.type === 'expense') {
            if (t.type === 'expense') {
              return sum + t.amount; // Gastos regulares aumentan el 'spent'
            }
            if (t.type === 'income' && t.refundId) {
              return sum - t.amount; // Ingresos por reembolso disminuyen el 'spent'
            }
          }
          // Para presupuestos de ingreso:
          if (b.type === 'income') {
            // Solo cuenta ingresos que NO son reembolsos
            if (t.type === 'income' && !t.refundId) {
              return sum + t.amount; // Ingresos regulares (ej: nómina) aumentan el 'spent'
            }
          }
          return sum; // No cuenta otros tipos de transacciones
        }, 0);

      const totalRefundedForCategory = transactions
        .filter(t => t.date.startsWith(currentDate) && t.category === b.category && t.type === 'income' && !!t.refundId)
        .reduce((sum, t) => sum + t.amount, 0);

      return { ...b, spent: calculatedSpent, totalRefunded: totalRefundedForCategory };
    });
  }, [budgets, transactions, currentDate]);

  const renderBlock = (key: string, index: number) => {
    const moveControls = isEditMode && (
      <div className="absolute top-4 right-4 flex gap-1 z-20">
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'up'); }} className="p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-95" disabled={index === 0}>
          <ChevronUp size={16} className="text-slate-600 dark:text-slate-400" />
        </button>
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'down'); }} className="p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-95" disabled={index === dashboardLayout.length - 1}>
          <ChevronDown size={16} className="text-slate-600 dark:text-slate-400" />
        </button>
      </div>
    );

    switch (key) {
      case 'balance':
        return (
          <div key={key} className="relative bg-[#2563eb] dark:bg-blue-600 rounded-[2.5rem] p-8 md:p-10 text-white shadow-2xl shadow-blue-200/50 dark:shadow-blue-900/20 overflow-hidden transition-colors duration-300">
            {moveControls}
            <div className="relative z-10 flex flex-col">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <p className="text-blue-100 text-[9px] font-black uppercase tracking-[0.2em] mb-2 opacity-80">Patrimonio Neto en {currentDate}</p>
                  <h2 className="text-4xl md:text-5xl font-black tracking-tight">{metrics.netWorth.toLocaleString()}€</h2>
                </div>
                <button 
                  onClick={() => setShowBreakdown(!showBreakdown)}
                  className={`px-5 py-3 rounded-2xl flex items-center gap-2 text-xs font-black transition-all shadow-lg bg-white/20 backdrop-blur-md hover:bg-white/30 active:scale-95`}
                >
                  {metrics.monthResult >= 0 ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
                  {metrics.monthResult >= 0 ? '+' : ''}{metrics.monthResult.toLocaleString()}€ en este mes
                  <ChevronDown size={14} className={`transition-transform duration-300 ${showBreakdown ? 'rotate-180' : ''}`} />
                </button>
              </div>

              {showBreakdown && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8 animate-in slide-in-from-top-4 duration-300">
                  <div className="p-5 bg-blue-400/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-blue-100">Ingresos del Mes</p>
                    <p className="text-2xl font-black">{metrics.income.toLocaleString()}€</p>
                  </div>
                  <div className="p-5 bg-[#4c51bf]/40 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-indigo-100">Gastos Netos Mes</p>
                    <p className="text-2xl font-black">{metrics.expense.toLocaleString()}€</p>
                    {metrics.refundRecoveries > 0 && (
                      <p className="text-[9px] font-bold text-indigo-200 opacity-80 mt-1">(-{metrics.refundRecoveries.toLocaleString()}€ de reembolsos)</p>
                    )}
                  </div>
                  <div className="p-5 bg-slate-500/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-slate-100">Ahorrado Mes</p>
                    <p className="text-2xl font-black">{metrics.monthSavings.toLocaleString()}€</p>
                  </div>
                </div>
              )}

              <div className="h-px bg-white/15 w-full mb-8"></div>

              <div className="grid grid-cols-3 gap-8">
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Saldo Anterior</p>
                  <p className="text-xl md:text-2xl font-black">{metrics.pastLiquidBalance.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Resultado Mes</p>
                  <p className="text-xl md:text-2xl font-black">{metrics.monthResult.toLocaleString()}€</p>
                </div>
                <div>
                  <p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Liquidez</p>
                  <p className="text-xl md:text-2xl font-black">{metrics.liquidity.toLocaleString()}€</p>
                </div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <div className="w-10 h-10 bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 rounded-xl flex items-center justify-center transition-colors">
                  <Target size={20} />
                </div>
                <h3 className="font-bold text-slate-800 dark:text-slate-100">Retos AI Aura</h3>
              </div>
              <button 
                onClick={handleGenerateChallenges}
                disabled={isGeneratingChallenges}
                className="p-2.5 bg-blue-600 text-white rounded-xl transition-all disabled:opacity-50 hover:bg-blue-700 shadow-md shadow-blue-100 dark:shadow-none"
              >
                {isGeneratingChallenges ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
              </button>
            </div>
            <div className="space-y-3">
              {evaluatedChallenges.map(ch => (
                <div key={ch.id} className={`p-4 rounded-2xl border flex items-center gap-3 transition-all ${ch.completed ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-100 dark:border-emerald-800/50' : 'bg-slate-50 dark:bg-slate-800/50 border-slate-100 dark:border-slate-800'}`}>
                  {ch.completed ? <CheckCircle2 className="text-emerald-500" size={20}/> : <Circle className="text-slate-300 dark:text-slate-600" size={20}/>}
                  <div className="flex-1">
                    <p className={`text-sm font-bold ${ch.completed ? 'text-emerald-700 dark:text-emerald-300' : 'text-slate-700 dark:text-slate-300'}`}>{ch.title}</p>
                    <p className="text-[10px] text-slate-500 dark:text-slate-400 font-medium">Objetivo: {ch.target}€</p>
                  </div>
                </div>
              ))}
              {evaluatedChallenges.length === 0 && (
                <p className="text-slate-400 dark:text-slate-500 text-xs text-center py-4 italic">Pulsa en el destello para que Aura te proponga retos.</p>
              )}
            </div>
          </div>
        );
      case 'savings':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-amber-50 dark:bg-amber-900/40 text-amber-600 dark:text-amber-400 rounded-xl flex items-center justify-center transition-colors">
                <PiggyBank size={20} />
              </div>
              <h3 className="font-bold text-slate-800 dark:text-slate-100">Ahorro en {currentDate}</h3>
            </div>
            <div className="text-center py-6">
              <p className="text-4xl font-black text-slate-900 dark:text-white">{metrics.totalSavingsAccumulated.toLocaleString()}€</p>
              <p className="text-xs text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest mt-2">Capital acumulado histórico</p>
            </div>
            <div className="grid grid-cols-2 gap-2 mt-4">
               {savings.slice(0, 4).map(s => (
                 <div key={s.id} className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800 transition-colors">
                   <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold truncate uppercase tracking-tighter">{s.name}</p>
                   <p className="text-xs font-black text-slate-700 dark:text-slate-200">{getSavingHistoricalBalance(s.id, currentDate)}€</p>
                 </div>
               ))}
            </div>
          </div>
        );
      case 'chart':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm transition-all duration-300">
            {moveControls}
            <div className="flex items-center justify-between mb-8">
              <h3 className="font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                <TrendingUp size={20} className="text-emerald-500" /> Evolución del Patrimonio
              </h3>
              <div className="flex gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                <button onClick={() => setChartFilter('6m')} className={`px-4 py-1.5 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '6m' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400 dark:text-slate-500'}`}>6 M</button>
                <button onClick={() => setChartFilter('12m')} className={`px-4 py-1.5 text-[10px] font-bold rounded-lg transition-all ${chartFilter === '12m' ? 'bg-white dark:bg-slate-700 shadow-sm text-blue-600 dark:text-blue-400' : 'text-slate-400 dark:text-slate-500'}`}>12 M</button>
              </div>
            </div>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorPat" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={theme === 'dark' ? '#1e293b' : '#f1f5f9'} />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: theme === 'dark' ? '#64748b' : '#94a3b8'}} />
                  <YAxis hide />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', backgroundColor: theme === 'dark' ? '#0f172a' : '#fff', color: theme === 'dark' ? '#f1f5f9' : '#000' }}
                    itemStyle={{ color: theme === 'dark' ? '#3b82f6' : '#2563eb' }}
                    formatter={(value: any, name: string, props: any) => [`${value.toLocaleString()}€`, props.payload.fullLabel || 'Patrimonio']}
                  />
                  <Area type="monotone" dataKey="patrimonio" stroke="#3b82f6" strokeWidth={3} fill="url(#colorPat)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        );
      case 'accounts':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center gap-2 mb-6">
              <div className="w-10 h-10 bg-emerald-50 dark:bg-emerald-900/40 text-emerald-600 dark:text-emerald-400 rounded-xl flex items-center justify-center transition-colors">
                <Wallet size={20} />
              </div>
              <h3 className="font-bold text-slate-800 dark:text-slate-100">Cuentas en {currentDate}</h3>
            </div>
            <div className="space-y-4">
              {accounts.map(acc => (
                <div key={acc.id} className="flex justify-between items-center p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-800 transition-colors">
                  <div className="flex items-center gap-3">
                    <span className="text-xl">{acc.emoji || '🏦'}</span>
                    <span className="font-bold text-slate-700 dark:text-slate-300 text-sm">{acc.name}</span>
                  </div>
                  <span className="font-black text-slate-900 dark:text-white">{getAccountHistoricalBalance(acc.id, currentDate).toLocaleString()}€</span>
                </div>
              ))}
            </div>
          </div>
        );
      case 'budget':
        const displayedBudgets = isBudgetsExpanded ? budgetsWithCalculatedSpent : budgetsWithCalculatedSpent.slice(0, 4);
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <div className="w-10 h-10 bg-purple-50 dark:bg-purple-900/40 text-purple-600 dark:text-purple-400 rounded-xl flex items-center justify-center transition-colors">
                  <ShoppingBag size={20} />
                </div>
                <h3 className="font-bold text-slate-800 dark:text-slate-100">Presupuestos Mes</h3>
              </div>
              {budgets.length > 4 && (
                <button 
                  onClick={() => setIsBudgetsExpanded(!isBudgetsExpanded)}
                  className="p-2.5 bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 rounded-xl hover:bg-slate-200 dark:hover:bg-slate-700 transition-all shadow-sm"
                >
                  <ChevronDown className={`transition-transform duration-300 ${isBudgetsExpanded ? 'rotate-180' : ''}`} size={18} />
                </button>
              )}
            </div>
            <div className="space-y-6">
              {displayedBudgets.map(b => {
                const progress = b.limit > 0 ? Math.min((b.spent / b.limit) * 100, 100) : 0;
                const isOverBudget = b.type === 'expense' && b.spent > b.limit;

                return (
                  <div key={b.id} onClick={() => setSelectedBudgetForDetails(b)} className="cursor-pointer group space-y-1.5">
                    <div className="flex justify-between text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
                      <span>{b.category}</span>
                      <span style={{ color: isOverBudget ? '#f43f5e' : b.color }}>
                        {b.spent.toLocaleString('es-ES')}€ / {b.limit.toLocaleString('es-ES')}€ ({Math.round(progress)}%)
                      </span>
                    </div>
                    <div className="w-full h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                      <div 
                        className={`h-full transition-all duration-700`} 
                        style={{ 
                          width: `${progress}%`,
                          backgroundColor: isOverBudget ? '#f43f5e' : b.color || '#3b82f6'
                        }}
                      ></div>
                    </div>
                    {b.totalRefunded > 0 && (
                      <p className="text-[9px] font-black text-blue-500 dark:text-blue-400 flex items-center gap-1 mt-1 transition-all">
                         <ChevronRight size={10} className="shrink-0" /> 
                         Reembolsado: +{b.totalRefunded.toLocaleString()}€ (Ahorro en gasto neto)
                      </p>
                    )}
                  </div>
                );
              })}
              {budgets.length === 0 && <p className="text-xs text-slate-400 dark:text-slate-500 italic text-center py-4">Sin límites definidos.</p>}
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  const budgetTransactions = useMemo(() => {
    if (!selectedBudgetForDetails) return [];
    return transactions.filter(t => 
      t.category === selectedBudgetForDetails.category && 
      t.date.startsWith(currentDate)
    ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedBudgetForDetails, transactions, currentDate]);


  return (
    <div className="space-y-6 pb-20 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
