          return (
            <div key={key} className={`${isFullWidth ? 'lg:col-span-2' : 'lg:col-span-1'} transition-all duration-300`}>
              {renderBlock(key, idx)}
            </div>
          );
        })}
      </div>

      {/* Modal Ver Detalles de Presupuesto (adaptado de BudgetManager) */}
      {selectedBudgetForDetails && (
        <div className="fixed inset-0 bg-slate-900/90 z-[60] flex items-center justify-center p-4" onClick={() => setSelectedBudgetForDetails(null)}>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-8 md:p-10 shadow-2xl animate-in fade-in zoom-in duration-300 border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-start mb-8 flex-shrink-0">
               <div className="flex items-center gap-5">
                  <div 
                    className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-lg dark:shadow-none transition-colors`}
                    style={{ backgroundColor: `${selectedBudgetForDetails.color}${theme === 'dark' ? '30' : '15'}`, color: selectedBudgetForDetails.color }}
                  >
                    {ICON_MAP[selectedBudgetForDetails.icon] ? (
                      React.cloneElement(ICON_MAP[selectedBudgetForDetails.icon] as React.ReactElement, { size: 28 })
                    ) : (
                      <span className="text-3xl">{selectedBudgetForDetails.icon || <ShoppingBag size={28} />}</span>
                    )}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{selectedBudgetForDetails.category}</h3>
                    <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Movimientos de {currentDate}</p>
                  </div>
               </div>
               <button onClick={() => setSelectedBudgetForDetails(null)} className="p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={24} /></button>
            </div>

            <div className="bg-slate-50 dark:bg-slate-800/50 rounded-3xl p-6 mb-8 border border-slate-100 dark:border-slate-800 flex-shrink-0 transition-colors">
               <div className="flex justify-between items-end mb-4">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-1">Total acumulado</p>
                    <p className="text-3xl font-black text-slate-900 dark:text-white transition-colors">{selectedBudgetForDetails.spent.toLocaleString()}€</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-1">Límite</p>
                    <p className="text-lg font-bold text-slate-600 dark:text-slate-400 transition-colors">{selectedBudgetForDetails.limit.toLocaleString()}€</p>
                  </div>
               </div>
               <div className="w-full h-3 bg-white dark:bg-slate-800 rounded-full overflow-hidden border border-slate-200 dark:border-slate-700">
                  <div 
                    className={`h-full rounded-full transition-all duration-1000`} 
                    style={{ 
                      width: `${Math.min((selectedBudgetForDetails.spent / selectedBudgetForDetails.limit) * 100, 100)}%`,
                      backgroundColor: (selectedBudgetForDetails.type === 'expense' && selectedBudgetForDetails.spent > selectedBudgetForDetails.limit) ? '#f43f5e' : selectedBudgetForDetails.color 
                    }}
                  ></div>
               </div>
            </div>

            <div className="flex items-center gap-2 mb-4 flex-shrink-0">
              <History size={16} className="text-slate-400 dark:text-slate-600" />
