          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-8 md:p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-start mb-8 flex-shrink-0"><div className="flex items-center gap-5"><div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-lg dark:shadow-none transition-colors`} style={{ backgroundColor: `${selectedBudgetForDetails.color}${theme === 'dark' ? '30' : '15'}`, color: selectedBudgetForDetails.color }}>{ICON_MAP[selectedBudgetForDetails.icon] ? (React.cloneElement(ICON_MAP[selectedBudgetForDetails.icon] as React.ReactElement, { size: 28 })) : (<span className="text-3xl">{selectedBudgetForDetails.icon || <ShoppingBag size={28} />}</span>)}</div><div><h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{selectedBudgetForDetails.category}</h3><p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Movimientos de {currentDate}</p></div></div><button onClick={() => setSelectedBudgetForDetails(null)} className="p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={24} /></button></div>
            <div className="bg-slate-50 dark:bg-slate-800/50 rounded-3xl p-6 mb-8 border border-slate-100 dark:border-slate-800 flex-shrink-0 transition-colors"><div className="flex justify-between items-end mb-4"><div><p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-1">Total acumulado</p><p className="text-3xl font-black text-slate-900 dark:text-white transition-colors">{selectedBudgetForDetails.spent.toLocaleString()}€</p></div><div className="text-right"><p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-1">Límite</p><p className="text-lg font-bold text-slate-600 dark:text-slate-400 transition-colors">{selectedBudgetForDetails.limit.toLocaleString()}€</p></div></div><div className="w-full h-3 bg-white dark:bg-slate-800 rounded-full overflow-hidden border border-slate-200 dark:border-slate-700"><div className={`h-full rounded-full transition-all duration-1000`} style={{ width: `${Math.min((selectedBudgetForDetails.spent / selectedBudgetForDetails.limit) * 100, 100)}%`, backgroundColor: (selectedBudgetForDetails.type === 'expense' && selectedBudgetForDetails.spent > selectedBudgetForDetails.limit) ? '#f43f5e' : selectedBudgetForDetails.color }}></div></div></div>
            <div className="flex items-center gap-2 mb-4 flex-shrink-0"><History size={16} className="text-slate-400 dark:text-slate-600" /><h4 className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Historial Reciente</h4></div>
            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 pr-2">{budgetTransactions.length > 0 ? budgetTransactions.map(tx => (<div key={tx.id} className="flex justify-between items-center p-4 bg-white dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 rounded-2xl hover:border-blue-200 dark:hover:border-blue-800 transition-colors duration-300"><div className="flex items-center gap-4"><div className="text-center bg-slate-50 dark:bg-slate-900 w-10 py-1.5 rounded-xl border border-slate-100 dark:border-slate-700 transition-colors"><p className="text-[8px] font-black text-slate-400 dark:text-slate-600 uppercase">{new Date(tx.date).toLocaleDateString('es-ES', { month: 'short' })}</p><p className="text-xs font-black text-slate-700 dark:text-slate-300 transition-colors">{new Date(tx.date).getDate()}</p></div><div><p className="text-sm font-bold text-slate-800 dark:text-slate-200 line-clamp-1 transition-colors">{tx.description}</p><p className="text-[10px] font-medium text-slate-400 dark:text-slate-500">{accounts.find(a => a.id === tx.accountId)?.name || 'Cuenta'}</p></div></div><div className="text-right"><p className={`font-black ${tx.type === 'income' ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-900 dark:text-white'} transition-colors`}>{tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€</p></div></div>)) : (<div className="text-center py-12 bg-slate-50 dark:bg-slate-800/30 rounded-[2rem] border-2 border-dashed border-slate-200 dark:border-slate-700 transition-colors"><AlertCircle size={32} className="mx-auto text-slate-300 dark:text-slate-700 mb-3" /><p className="text-xs font-bold text-slate-400 dark:text-slate-600 uppercase tracking-widest">No hay transacciones aún</p></div>)}</div>
            <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex-shrink-0"><button onClick={() => setSelectedBudgetForDetails(null)} className="w-full py-4 bg-slate-900 dark:bg-blue-600 text-white font-black rounded-2xl hover:bg-slate-800 dark:hover:bg-blue-700 transition-all active:scale-[0.98]">ENTENDIDO</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  X, 
  UserCheck, 
  AlertCircle, 
  Check, 
  PiggyBank, 
  ChevronDown, 
  Split,
  Camera,
  Loader2,
  Sparkles,
  ArrowRightLeft,
  ArrowRight,
  Ban,
  Filter
} from 'lucide-react';
import { Transaction } from '../types';
import { analyzeReceipt, ScannedTransaction } from '../services/geminiService';

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, theme, currentDate, viewMode } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const [isScanning, setIsScanning] = useState(false);
  const [scannedQueue, setScannedQueue] = useState<ScannedTransaction[]>([]);
  const [totalScannedCount, setTotalScannedCount] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const location = useLocation();

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  const [isTransfer, setIsTransfer] = useState(false);
  const [transferTargetId, setTransferTargetId] = useState('');

  const isSavingTx = (t: any) => t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;
  const isTransferTx = (t: any) => t.category === 'Traspaso' || t.category === 'Transferencia';

  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];
    if (type === 'income' && isRefundLink && selectedRefundId) {
      const selectedRefund = refunds.find(r => r.id === selectedRefundId);
      if (selectedRefund) return [selectedRefund.category];
    }
    if (type === 'income' && isRefundLink) {
      const expenseCats = budgets.filter(b => b.type === 'expense').map(b => b.category);
      return expenseCats.length > 0 ? Array.from(new Set(expenseCats)) : ["Sin Presupuesto"];
    }
    const budgetList = budgets.filter(b => b.type === (type as any === 'saving' ? 'expense' : type as any)).map(b => b.category);
    return budgetList.length > 0 ? Array.from(new Set(budgetList)) : ["Sin Presupuesto"];
  }, [type, isRefundLink, selectedRefundId, budgets, refunds]);

  useEffect(() => {
    if (type === 'income' && isRefundLink && selectedRefundId) {
      const refundObj = refunds.find(r => r.id === selectedRefundId);
      if (refundObj) setCategory(refundObj.category);
    } else if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories, type, isRefundLink, selectedRefundId, refunds]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc(''); setAmount(''); setDate(new Date().toISOString().split('T')[0]);
    setType('expense'); setCategory(''); setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false); setSelectedRefundId(''); setSelectedSavingId('');
    setMyPartManual(''); setIsTransfer(false); setTransferTargetId(''); setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    const isSavingType = tx.type === 'expense' && !!tx.savingId;
    setType(isSavingType ? 'saving' : tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setSelectedSavingId(tx.savingId || '');
    setIsAdding(true);
    setViewingTx(null);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (isTransfer) {
      addTransaction({ date, amount: Number(amount), description: `Traspaso a ${accounts.find(a => a.id === transferTargetId)?.name}`, category: 'Traspaso', type: 'expense', accountId, isRefund: false });
      addTransaction({ date, amount: Number(amount), description: `Traspaso desde ${accounts.find(a => a.id === accountId)?.name}`, category: 'Traspaso', type: 'income', accountId: transferTargetId, isRefund: false });
    } else {
      const finalType = type === 'saving' ? 'expense' : type;
      const finalCategory = type === 'saving' ? 'Ahorro' : category;
      if (editingTx) {
        updateTransaction({ ...editingTx, date, amount: Number(amount), description: desc, category: finalCategory, type: finalType as any, accountId, refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined, savingId: type === 'saving' ? selectedSavingId : undefined });
      } else {
        addTransaction({ date, amount: Number(amount), description: desc, category: finalCategory, type: finalType as any, accountId, isRefund: isRefundLink, refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined, savingId: type === 'saving' ? selectedSavingId : undefined }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
      }
    }
    const nextQueue = scannedQueue.slice(1);
    setScannedQueue(nextQueue);
    if (nextQueue.length > 0) loadScannedItem(nextQueue[0]);
    else { setIsAdding(false); resetForm(); }
  };

  const loadScannedItem = (item: ScannedTransaction) => {
    setDesc(item.description); setAmount(item.amount); setDate(item.date);
    setType(item.isSaving ? 'saving' : item.type); setIsTransfer(item.isTransfer);
    setIsRefundLink(item.isRefund); setCategory(item.category);
    if (item.suggestedAccount) {
      const matched = accounts.find(a => a.name.toLowerCase().includes(item.suggestedAccount!.toLowerCase()));
      if (matched) setAccountId(matched.id);
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    const reader = new FileReader();
    reader.onload = async () => {
      const base64 = (reader.result as string).split(',')[1];
      try {
        const items = await analyzeReceipt(base64);
        setScannedQueue(items);
        setTotalScannedCount(items.length);
        if (items.length > 0) { loadScannedItem(items[0]); setIsAdding(true); }
      } catch (err) { console.error(err); } finally { setIsScanning(false); }
    };
    reader.readAsDataURL(file);
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesPeriod = t.date.startsWith(currentDate);
      if (!matchesPeriod) return false;
      let matchesType = true;
      if (filter === 'income') matchesType = t.type === 'income' && !t.refundId && !isTransferTx(t);
      else if (filter === 'expense') matchesType = t.type === 'expense' && !isSavingTx(t) && !isTransferTx(t);
      else if (filter === 'savings') matchesType = isSavingTx(t);
      else if (filter === 'refunds') matchesType = t.type === 'income' && !!t.refundId;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, filter, searchTerm, currentDate]);

  const getTxStyle = (t: Transaction) => {
    if (isTransferTx(t)) return { color: 'text-slate-500', bg: 'bg-slate-100 dark:bg-slate-800', icon: <ArrowRightLeft size={18} /> };
    if (isSavingTx(t)) return { color: 'text-amber-500', bg: 'bg-amber-50 dark:bg-amber-900/40', icon: <PiggyBank size={18} /> };
    if (t.type === 'income' && !!t.refundId) return { color: 'text-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/40', icon: <ArrowUpRight size={18} /> };
    if (t.type === 'income') return { color: 'text-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/40', icon: <ArrowUpRight size={18} /> };
    return { color: 'text-rose-500', bg: 'bg-rose-50 dark:bg-rose-900/40', icon: <ArrowDownRight size={18} /> };
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4 transition-colors">
      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/90 z-[100] flex flex-col items-center justify-center p-6 text-center">
          <div className="relative mb-8"><div className="w-32 h-32 border-4 border-blue-500/20 rounded-full border-t-blue-500 animate-spin"></div><Sparkles className="absolute inset-0 m-auto text-blue-500 animate-pulse" size={48} /></div>
          <h3 className="text-2xl font-black text-white mb-2">Aura Vision Procesando</h3>
          <p className="text-slate-400 max-w-xs">Extrayendo y categorizando tus movimientos bancarios...</p>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Transacciones</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium">Historial sincronizado del periodo {currentDate}.</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-6 py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 font-black rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-700 transition-all shadow-sm"><Camera size={20} className="text-blue-500" /> Aura Vision</button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl active:scale-95"><Plus size={20} /> Nueva</button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-300">
        <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 flex flex-col gap-4 bg-slate-50/30 dark:bg-slate-800/20">
          <div className="flex items-center gap-1 bg-white dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-x-auto no-scrollbar">
            <button onClick={() => setFilter('all')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 dark:bg-slate-700 text-white' : 'text-slate-400'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white' : 'text-slate-400'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white' : 'text-slate-400'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 text-white' : 'text-slate-400'}`}>AHORRO</button>
            <button onClick={() => setFilter('refunds')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 text-white' : 'text-slate-400'}`}>COBROS</button>
          </div>
          <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Buscar por concepto o categoría..." className="w-full pl-12 pr-4 py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium text-sm text-slate-700 dark:text-slate-200" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left">
            <thead><tr className="bg-slate-50/50 dark:bg-slate-800/40 text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em]"><th className="px-8 py-5">Fecha</th><th className="px-8 py-5">Concepto</th><th className="px-8 py-5">Categoría</th><th className="px-8 py-5">Cuenta</th><th className="px-8 py-5 text-right">Importe</th></tr></thead>
            <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
              {filteredTx.map(t => {
                const style = getTxStyle(t);
                return (
                  <tr key={t.id} onClick={() => setViewingTx(t)} className="group hover:bg-slate-50/50 dark:hover:bg-slate-800/30 cursor-pointer transition-colors">
                    <td className="px-8 py-6 whitespace-nowrap text-xs font-bold text-slate-400 dark:text-slate-500">{new Date(t.date).toLocaleDateString()}</td>
                    <td className="px-8 py-6"><div className="flex items-center gap-4"><div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-colors ${style.bg} ${style.color}`}>{style.icon}</div><div className="font-bold text-slate-700 dark:text-slate-200">{t.description}</div></div></td>
                    <td className="px-8 py-6"><span className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-full text-[10px] font-black uppercase text-slate-500 dark:text-slate-400 tracking-wider">{t.category}</span></td>
                    <td className="px-8 py-6 text-xs font-bold text-slate-500 dark:text-slate-400">{accounts.find(a => a.id === t.accountId)?.name}</td>
                    <td className="px-8 py-6 text-right"><div className={`font-black text-lg ${style.color}`}>{t.type === 'income' ? '+' : '-'}{t.amount.toLocaleString()}€</div></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTx.length === 0 && <div className="p-20 text-center flex flex-col items-center gap-4 text-slate-400"><AlertCircle size={48} className="opacity-20" /><p className="font-black uppercase text-xs tracking-widest">Sin movimientos registrados</p></div>}
        </div>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-10 shadow-2xl overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800 dark:text-white">{editingTx ? 'Editar Movimiento' : (scannedQueue.length > 0 ? `Aura Vision (${totalScannedCount - scannedQueue.length + 1}/${totalScannedCount})` : 'Nuevo Movimiento')}</h3>
              <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-2 hover:bg-slate-100 rounded-full text-slate-400"><X size={24} /></button>
            </div>
            <form onSubmit={handleManualSubmit} className="space-y-6">
              <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl">
                <button type="button" onClick={() => { setType('expense'); setIsTransfer(false); }} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${type === 'expense' && !isTransfer ? 'bg-white dark:bg-slate-700 text-rose-600 shadow-md' : 'text-slate-400'}`}>GASTO</button>
                <button type="button" onClick={() => { setType('income'); setIsTransfer(false); }} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${type === 'income' && !isTransfer ? 'bg-white dark:bg-slate-700 text-emerald-600 shadow-md' : 'text-slate-400'}`}>INGRESO</button>
                <button type="button" onClick={() => { setType('saving'); setIsTransfer(false); }} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${type === 'saving' ? 'bg-white dark:bg-slate-700 text-amber-600 shadow-md' : 'text-slate-400'}`}>AHORRO</button>
                <button type="button" onClick={() => setIsTransfer(true)} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${isTransfer ? 'bg-white dark:bg-slate-700 text-slate-600 shadow-md' : 'text-slate-400'}`}>TRASPASO</button>
              </div>
              <input type="text" placeholder="Concepto..." className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl border border-slate-100 dark:border-slate-700 text-slate-900 dark:text-white font-bold outline-none" value={desc} onChange={e => setDesc(e.target.value)} required />
              <input type="number" placeholder="0.00€" className="w-full bg-slate-50 dark:bg-slate-800 p-8 rounded-[2rem] border border-slate-100 dark:border-slate-700 text-5xl font-black text-center text-slate-900 dark:text-white outline-none" value={amount} onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} required />
              <div className="grid grid-cols-2 gap-4">
                <input type="date" className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl text-slate-900 dark:text-white font-bold" value={date} onChange={e => setDate(e.target.value)} required />
                {!isTransfer ? (
                  <select className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl text-slate-900 dark:text-white font-bold" value={category} onChange={e => setCategory(e.target.value)} disabled={isCategoryDisabled} required>
                    {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                ) : (
                  <select className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl text-slate-900 dark:text-white font-bold" value={transferTargetId} onChange={e => setTransferTargetId(e.target.value)} required>
                    <option value="">Destino...</option>
                    {accounts.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                  </select>
                )}
              </div>
              <select className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl text-slate-900 dark:text-white font-bold" value={accountId} onChange={e => setAccountId(e.target.value)} required>
                {accounts.map(a => <option key={a.id} value={a.id}>{isTransfer ? 'Origen: ' : ''}{a.name}</option>)}
              </select>
              {type === 'saving' && (
                <select className="w-full bg-amber-50 dark:bg-amber-900/20 p-5 rounded-2xl text-amber-900 dark:text-amber-300 font-bold border-2 border-amber-100 dark:border-amber-800" value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} required>
                  <option value="">Selecciona Hucha...</option>
                  {savings.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              )}
              {type === 'income' && !isTransfer && (
                <div className="flex items-center gap-3 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-2xl border-2 border-blue-100 dark:border-blue-900/40">
                  <div onClick={() => setIsRefundLink(!isRefundLink)} className={`w-10 h-10 rounded-xl flex items-center justify-center cursor-pointer transition-all ${isRefundLink ? 'bg-blue-600 text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-slate-300'}`}><UserCheck size={20} /></div>
                  <div className="flex-1"><p className="text-xs font-black text-blue-700 dark:text-blue-400 uppercase tracking-widest">¿Es un Reembolso?</p><p className="text-[10px] text-blue-600/60 dark:text-blue-400/60 font-bold">Vincúlalo a una deuda pendiente.</p></div>
                  {isRefundLink && (
                    <select className="bg-transparent border-none outline-none text-xs font-black text-blue-800 dark:text-blue-200" value={selectedRefundId} onChange={e => setSelectedRefundId(e.target.value)}>
                      <option value="">-- Seleccionar deuda --</option>
                      {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                    </select>
                  )}
                </div>
              )}
              <div className="flex gap-4 pt-4">
                {scannedQueue.length > 0 && <button type="button" onClick={() => scannedQueue.length > 1 ? loadScannedItem(scannedQueue[1]) : setIsAdding(false)} className="flex-1 py-5 bg-slate-100 text-slate-400 font-black rounded-2xl uppercase tracking-widest text-[10px]">Descartar</button>}
                <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-200 active:scale-95 uppercase tracking-widest text-[10px]">{editingTx ? 'Guardar' : (scannedQueue.length > 1 ? 'Registrar y Siguiente' : 'Registrar')}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4" onClick={() => { setViewingTx(null); setConfirmDeleteInModal(false); }}>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-sm p-10 shadow-2xl border border-slate-100 dark:border-slate-800 flex flex-col items-center text-center animate-in zoom-in duration-300" onClick={e => e.stopPropagation()}>
            <div className={`w-20 h-20 rounded-3xl mb-6 flex items-center justify-center text-3xl ${getTxStyle(viewingTx).bg} ${getTxStyle(viewingTx).color}`}>{getTxStyle(viewingTx).icon}</div>
            <h3 className="text-2xl font-black text-slate-800 dark:text-white mb-2">{viewingTx.description}</h3>
            <p className="px-4 py-1.5 bg-slate-100 dark:bg-slate-800 rounded-full text-[10px] font-black uppercase text-slate-400 tracking-widest mb-8">{viewingTx.category}</p>
            <div className={`text-4xl font-black mb-10 ${getTxStyle(viewingTx).color}`}>{viewingTx.type === 'income' ? '+' : '-'}{viewingTx.amount.toLocaleString()}€</div>
            <div className="w-full space-y-3">
              <button onClick={() => startEdit(viewingTx)} className="w-full py-4 bg-slate-900 dark:bg-blue-600 text-white font-black rounded-2xl flex items-center justify-center gap-3 hover:bg-slate-800 transition-all"><Edit2 size={18} /> EDITAR MOVIMIENTO</button>
              {!confirmDeleteInModal ? (
                <button onClick={() => setConfirmDeleteInModal(true)} className="w-full py-4 bg-slate-50 dark:bg-slate-800 text-rose-500 font-black rounded-2xl flex items-center justify-center gap-3 hover:bg-rose-50 transition-all"><Trash2 size={18} /> ELIMINAR</button>
              ) : (
                <div className="flex gap-2 animate-in slide-in-from-bottom-2">
                  <button onClick={() => handleDeleteFromModal(viewingTx.id)} className="flex-1 py-4 bg-rose-600 text-white font-black rounded-2xl shadow-lg shadow-rose-200 uppercase text-[10px] tracking-widest">¿BORRAR?</button>
                  <button onClick={() => setConfirmDeleteInModal(false)} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-400 font-black rounded-2xl uppercase text-[10px] tracking-widest">NO</button>
                </div>
              )}
            </div>
            <button onClick={() => { setViewingTx(null); setConfirmDeleteInModal(false); }} className="mt-8 text-xs font-bold text-slate-300 dark:text-slate-600 uppercase tracking-widest hover:text-slate-400">Cerrar Detalle</button>
          </div>
        </div>
      )}
    </div>
  );
};

const isCategoryDisabled = false; // logic simplified

export default Transactions;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  X, 
  UserCheck, 
  AlertCircle, 
  Check, 
  PiggyBank, 
  ChevronDown, 
  Split,
  Camera,
  Loader2,
  Sparkles,
  ArrowRightLeft,
  ArrowRight,
  Ban,
  Filter
} from 'lucide-react';
import { Transaction } from '../types';
import { analyzeReceipt, ScannedTransaction } from '../services/geminiService';

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, theme, currentDate, viewMode } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const [isScanning, setIsScanning] = useState(false);
  const [scannedQueue, setScannedQueue] = useState<ScannedTransaction[]>([]);
  const [totalScannedCount, setTotalScannedCount] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const location = useLocation();

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  const [isTransfer, setIsTransfer] = useState(false);
  const [transferTargetId, setTransferTargetId] = useState('');

  const isSavingTx = (t: any) => t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;
  const isTransferTx = (t: any) => t.category === 'Traspaso' || t.category === 'Transferencia';

  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];
    if (type === 'income' && isRefundLink && selectedRefundId) {
      const selectedRefund = refunds.find(r => r.id === selectedRefundId);
      if (selectedRefund) return [selectedRefund.category];
    }
    if (type === 'income' && isRefundLink) {
      const expenseCats = budgets.filter(b => b.type === 'expense').map(b => b.category);
      return expenseCats.length > 0 ? Array.from(new Set(expenseCats)) : ["Sin Presupuesto"];
    }
    const budgetList = budgets.filter(b => b.type === (type as any === 'saving' ? 'expense' : type as any)).map(b => b.category);
    return budgetList.length > 0 ? Array.from(new Set(budgetList)) : ["Sin Presupuesto"];
  }, [type, isRefundLink, selectedRefundId, budgets, refunds]);

  useEffect(() => {
    if (type === 'income' && isRefundLink && selectedRefundId) {
      const refundObj = refunds.find(r => r.id === selectedRefundId);
      if (refundObj) setCategory(refundObj.category);
    } else if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories, type, isRefundLink, selectedRefundId, refunds]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc(''); setAmount(''); setDate(new Date().toISOString().split('T')[0]);
    setType('expense'); setCategory(''); setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false); setSelectedRefundId(''); setSelectedSavingId('');
    setMyPartManual(''); setIsTransfer(false); setTransferTargetId(''); setEditingTx(null);
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    const isSavingType = tx.type === 'expense' && !!tx.savingId;
    setType(isSavingType ? 'saving' : tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setSelectedSavingId(tx.savingId || '');
    setIsAdding(true);
    setViewingTx(null);
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (isTransfer) {
      addTransaction({ date, amount: Number(amount), description: `Traspaso a ${accounts.find(a => a.id === transferTargetId)?.name}`, category: 'Traspaso', type: 'expense', accountId, isRefund: false });
      addTransaction({ date, amount: Number(amount), description: `Traspaso desde ${accounts.find(a => a.id === accountId)?.name}`, category: 'Traspaso', type: 'income', accountId: transferTargetId, isRefund: false });
    } else {
      const finalType = type === 'saving' ? 'expense' : type;
      const finalCategory = type === 'saving' ? 'Ahorro' : category;
      if (editingTx) {
        updateTransaction({ ...editingTx, date, amount: Number(amount), description: desc, category: finalCategory, type: finalType as any, accountId, refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined, savingId: type === 'saving' ? selectedSavingId : undefined });
      } else {
        addTransaction({ date, amount: Number(amount), description: desc, category: finalCategory, type: finalType as any, accountId, isRefund: isRefundLink, refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined, savingId: type === 'saving' ? selectedSavingId : undefined }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
      }
    }
    const nextQueue = scannedQueue.slice(1);
    setScannedQueue(nextQueue);
    if (nextQueue.length > 0) loadScannedItem(nextQueue[0]);
    else { setIsAdding(false); resetForm(); }
  };

  // Fix: Added missing handleDeleteFromModal function to resolve the reference error in the modal
  const handleDeleteFromModal = (id: string) => {
    deleteTransaction(id);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const loadScannedItem = (item: ScannedTransaction) => {
    setDesc(item.description); setAmount(item.amount); setDate(item.date);
    setType(item.isSaving ? 'saving' : item.type); setIsTransfer(item.isTransfer);
    setIsRefundLink(item.isRefund); setCategory(item.category);
    if (item.suggestedAccount) {
      const matched = accounts.find(a => a.name.toLowerCase().includes(item.suggestedAccount!.toLowerCase()));
      if (matched) setAccountId(matched.id);
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    const reader = new FileReader();
    reader.onload = async () => {
      const base64 = (reader.result as string).split(',')[1];
      try {
        const items = await analyzeReceipt(base64);
        setScannedQueue(items);
        setTotalScannedCount(items.length);
        if (items.length > 0) { loadScannedItem(items[0]); setIsAdding(true); }
      } catch (err) { console.error(err); } finally { setIsScanning(false); }
    };
    reader.readAsDataURL(file);
  };

  const filteredTx = useMemo(() => {
    return transactions.filter(t => {
      const matchesPeriod = t.date.startsWith(currentDate);
      if (!matchesPeriod) return false;
      let matchesType = true;
      if (filter === 'income') matchesType = t.type === 'income' && !t.refundId && !isTransferTx(t);
      else if (filter === 'expense') matchesType = t.type === 'expense' && !isSavingTx(t) && !isTransferTx(t);
      else if (filter === 'savings') matchesType = isSavingTx(t);
      else if (filter === 'refunds') matchesType = t.type === 'income' && !!t.refundId;
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || t.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesType && matchesSearch;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, filter, searchTerm, currentDate]);

  const getTxStyle = (t: Transaction) => {
    if (isTransferTx(t)) return { color: 'text-slate-500', bg: 'bg-slate-100 dark:bg-slate-800', icon: <ArrowRightLeft size={18} /> };
    if (isSavingTx(t)) return { color: 'text-amber-500', bg: 'bg-amber-50 dark:bg-amber-900/40', icon: <PiggyBank size={18} /> };
    if (t.type === 'income' && !!t.refundId) return { color: 'text-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/40', icon: <ArrowUpRight size={18} /> };
    if (t.type === 'income') return { color: 'text-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/40', icon: <ArrowUpRight size={18} /> };
    return { color: 'text-rose-500', bg: 'bg-rose-50 dark:bg-rose-900/40', icon: <ArrowDownRight size={18} /> };
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4 transition-colors">
      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/90 z-[100] flex flex-col items-center justify-center p-6 text-center">
          <div className="relative mb-8"><div className="w-32 h-32 border-4 border-blue-500/20 rounded-full border-t-blue-500 animate-spin"></div><Sparkles className="absolute inset-0 m-auto text-blue-500 animate-pulse" size={48} /></div>
          <h3 className="text-2xl font-black text-white mb-2">Aura Vision Procesando</h3>
          <p className="text-slate-400 max-w-xs">Extrayendo y categorizando tus movimientos bancarios...</p>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Transacciones</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium">Historial sincronizado del periodo {currentDate}.</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-6 py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 font-black rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-700 transition-all shadow-sm"><Camera size={20} className="text-blue-500" /> Aura Vision</button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl active:scale-95"><Plus size={20} /> Nueva</button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-300">
        <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 flex flex-col gap-4 bg-slate-50/30 dark:bg-slate-800/20">
          <div className="flex items-center gap-1 bg-white dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-x-auto no-scrollbar">
            <button onClick={() => setFilter('all')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 dark:bg-slate-700 text-white' : 'text-slate-400'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 text-white' : 'text-slate-400'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 text-white' : 'text-slate-400'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 text-white' : 'text-slate-400'}`}>AHORRO</button>
            <button onClick={() => setFilter('refunds')} className={`px-4 py-2 text-[10px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 text-white' : 'text-slate-400'}`}>COBROS</button>
          </div>
          <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Buscar por concepto o categoría..." className="w-full pl-12 pr-4 py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium text-sm text-slate-700 dark:text-slate-200" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left">
            <thead><tr className="bg-slate-50/50 dark:bg-slate-800/40 text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em]"><th className="px-8 py-5">Fecha</th><th className="px-8 py-5">Concepto</th><th className="px-8 py-5">Categoría</th><th className="px-8 py-5">Cuenta</th><th className="px-8 py-5 text-right">Importe</th></tr></thead>
            <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
              {filteredTx.map(t => {
                const style = getTxStyle(t);
                return (
                  <tr key={t.id} onClick={() => setViewingTx(t)} className="group hover:bg-slate-50/50 dark:hover:bg-slate-800/30 cursor-pointer transition-colors">
                    <td className="px-8 py-6 whitespace-nowrap text-xs font-bold text-slate-400 dark:text-slate-500">{new Date(t.date).toLocaleDateString()}</td>
                    <td className="px-8 py-6"><div className="flex items-center gap-4"><div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-colors ${style.bg} ${style.color}`}>{style.icon}</div><div className="font-bold text-slate-700 dark:text-slate-200">{t.description}</div></div></td>
                    <td className="px-8 py-6"><span className="px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-full text-[10px] font-black uppercase text-slate-500 dark:text-slate-400 tracking-wider">{t.category}</span></td>
                    <td className="px-8 py-6 text-xs font-bold text-slate-500 dark:text-slate-400">{accounts.find(a => a.id === t.accountId)?.name}</td>
                    <td className="px-8 py-6 text-right"><div className={`font-black text-lg ${style.color}`}>{t.type === 'income' ? '+' : '-'}{t.amount.toLocaleString()}€</div></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTx.length === 0 && <div className="p-20 text-center flex flex-col items-center gap-4 text-slate-400"><AlertCircle size={48} className="opacity-20" /><p className="font-black uppercase text-xs tracking-widest">Sin movimientos registrados</p></div>}
        </div>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-10 shadow-2xl overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800 dark:text-white">{editingTx ? 'Editar Movimiento' : (scannedQueue.length > 0 ? `Aura Vision (${totalScannedCount - scannedQueue.length + 1}/${totalScannedCount})` : 'Nuevo Movimiento')}</h3>
              <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-2 hover:bg-slate-100 rounded-full text-slate-400"><X size={24} /></button>
            </div>
            <form onSubmit={handleManualSubmit} className="space-y-6">
              <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl">
                <button type="button" onClick={() => { setType('expense'); setIsTransfer(false); }} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${type === 'expense' && !isTransfer ? 'bg-white dark:bg-slate-700 text-rose-600 shadow-md' : 'text-slate-400'}`}>GASTO</button>
                <button type="button" onClick={() => { setType('income'); setIsTransfer(false); }} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${type === 'income' && !isTransfer ? 'bg-white dark:bg-slate-700 text-emerald-600 shadow-md' : 'text-slate-400'}`}>INGRESO</button>
                <button type="button" onClick={() => { setType('saving'); setIsTransfer(false); }} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${type === 'saving' ? 'bg-white dark:bg-slate-700 text-amber-600 shadow-md' : 'text-slate-400'}`}>AHORRO</button>
                <button type="button" onClick={() => setIsTransfer(true)} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${isTransfer ? 'bg-white dark:bg-slate-700 text-slate-600 shadow-md' : 'text-slate-400'}`}>TRASPASO</button>
              </div>
              <input type="text" placeholder="Concepto..." className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl border border-slate-100 dark:border-slate-700 text-slate-900 dark:text-white font-bold outline-none" value={desc} onChange={e => setDesc(e.target.value)} required />
              <input type="number" placeholder="0.00€" className="w-full bg-slate-50 dark:bg-slate-800 p-8 rounded-[2rem] border border-slate-100 dark:border-slate-700 text-5xl font-black text-center text-slate-900 dark:text-white outline-none" value={amount} onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} required />
              <div className="grid grid-cols-2 gap-4">
                <input type="date" className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl text-slate-900 dark:text-white font-bold" value={date} onChange={e => setDate(e.target.value)} required />
                {!isTransfer ? (
                  <select className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl text-slate-900 dark:text-white font-bold" value={category} onChange={e => setCategory(e.target.value)} disabled={isCategoryDisabled} required>
                    {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                ) : (
                  <select className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl text-slate-900 dark:text-white font-bold" value={transferTargetId} onChange={e => setTransferTargetId(e.target.value)} required>
                    <option value="">Destino...</option>
                    {accounts.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                  </select>
                )}
              </div>
              <select className="w-full bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl text-slate-900 dark:text-white font-bold" value={accountId} onChange={e => setAccountId(e.target.value)} required>
                {accounts.map(a => <option key={a.id} value={a.id}>{isTransfer ? 'Origen: ' : ''}{a.name}</option>)}
              </select>
              {type === 'saving' && (
                <select className="w-full bg-amber-50 dark:bg-amber-900/20 p-5 rounded-2xl text-amber-900 dark:text-amber-300 font-bold border-2 border-amber-100 dark:border-amber-800" value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} required>
                  <option value="">Selecciona Hucha...</option>
                  {savings.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              )}
              {type === 'income' && !isTransfer && (
                <div className="flex items-center gap-3 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-2xl border-2 border-blue-100 dark:border-blue-900/40">
                  <div onClick={() => setIsRefundLink(!isRefundLink)} className={`w-10 h-10 rounded-xl flex items-center justify-center cursor-pointer transition-all ${isRefundLink ? 'bg-blue-600 text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-slate-300'}`}><UserCheck size={20} /></div>
                  <div className="flex-1"><p className="text-xs font-black text-blue-700 dark:text-blue-400 uppercase tracking-widest">¿Es un Reembolso?</p><p className="text-[10px] text-blue-600/60 dark:text-blue-400/60 font-bold">Vincúlalo a una deuda pendiente.</p></div>
                  {isRefundLink && (
                    <select className="bg-transparent border-none outline-none text-xs font-black text-blue-800 dark:text-blue-200" value={selectedRefundId} onChange={e => setSelectedRefundId(e.target.value)}>
                      <option value="">-- Seleccionar deuda --</option>
                      {refunds.filter(r => r.status === 'open').map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                    </select>
                  )}
                </div>
              )}
              <div className="flex gap-4 pt-4">
                {scannedQueue.length > 0 && <button type="button" onClick={() => scannedQueue.length > 1 ? loadScannedItem(scannedQueue[1]) : setIsAdding(false)} className="flex-1 py-5 bg-slate-100 text-slate-400 font-black rounded-2xl uppercase tracking-widest text-[10px]">Descartar</button>}
                <button type="submit" className="flex-1 py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-200 active:scale-95 uppercase tracking-widest text-[10px]">{editingTx ? 'Guardar' : (scannedQueue.length > 1 ? 'Registrar y Siguiente' : 'Registrar')}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4" onClick={() => { setViewingTx(null); setConfirmDeleteInModal(false); }}>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-sm p-10 shadow-2xl border border-slate-100 dark:border-slate-800 flex flex-col items-center text-center animate-in zoom-in duration-300" onClick={e => e.stopPropagation()}>
            <div className={`w-20 h-20 rounded-3xl mb-6 flex items-center justify-center text-3xl ${getTxStyle(viewingTx).bg} ${getTxStyle(viewingTx).color}`}>{getTxStyle(viewingTx).icon}</div>
            <h3 className="text-2xl font-black text-slate-800 dark:text-white mb-2">{viewingTx.description}</h3>
            <p className="px-4 py-1.5 bg-slate-100 dark:bg-slate-800 rounded-full text-[10px] font-black uppercase text-slate-400 tracking-widest mb-8">{viewingTx.category}</p>
            <div className={`text-4xl font-black mb-10 ${getTxStyle(viewingTx).color}`}>{viewingTx.type === 'income' ? '+' : '-'}{viewingTx.amount.toLocaleString()}€</div>
            <div className="w-full space-y-3">
              <button onClick={() => startEdit(viewingTx)} className="w-full py-4 bg-slate-900 dark:bg-blue-600 text-white font-black rounded-2xl flex items-center justify-center gap-3 hover:bg-slate-800 transition-all"><Edit2 size={18} /> EDITAR MOVIMIENTO</button>
              {!confirmDeleteInModal ? (
                <button onClick={() => setConfirmDeleteInModal(true)} className="w-full py-4 bg-slate-50 dark:bg-slate-800 text-rose-500 font-black rounded-2xl flex items-center justify-center gap-3 hover:bg-rose-50 transition-all"><Trash2 size={18} /> ELIMINAR</button>
              ) : (
                <div className="flex gap-2 animate-in slide-in-from-bottom-2">
                  <button onClick={() => handleDeleteFromModal(viewingTx.id)} className="flex-1 py-4 bg-rose-600 text-white font-black rounded-2xl shadow-lg shadow-rose-200 uppercase text-[10px] tracking-widest">¿BORRAR?</button>
                  <button onClick={() => setConfirmDeleteInModal(false)} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-400 font-black rounded-2xl uppercase text-[10px] tracking-widest">NO</button>
                </div>
              )}
            </div>
            <button onClick={() => { setViewingTx(null); setConfirmDeleteInModal(false); }} className="mt-8 text-xs font-bold text-slate-300 dark:text-slate-600 uppercase tracking-widest hover:text-slate-400">Cerrar Detalle</button>
          </div>
        </div>
      )}
    </div>
  );
};

const isCategoryDisabled = false; // logic simplified

export default Transactions;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  CheckCircle2, 
  Users, 
  Trash2, 
  Merge, 
  X, 
  Edit3, 
  Save, 
  MessageSquare,
  Check,
  TrendingUp,
  AlertCircle,
  AlignLeft,
  ChevronDown
} from 'lucide-react';
import { Refund } from '../types';

const Refunds: React.FC = () => {
  const { budgets, refunds, addRefund, updateRefund, deleteRefund, mergeRefunds } = useFinance();

  // UI States
  const [isAdding, setIsAdding] = useState(false);
  const [isMerging, setIsMerging] = useState(false);
  const [mergeSelection, setMergeSelection] = useState<string[]>([]);
  const [filter, setFilter] = useState<'all' | 'open' | 'closed'>('open');
  const [selectedRefundId, setSelectedRefundId] = useState<string | null>(null);

  // Extraemos las categorías únicas de los presupuestos de gastos
  const budgetExpenseCategories = useMemo(() => {
    const cats = budgets
      .filter(b => b.type === 'expense')
      .map(b => b.category);
    return Array.from(new Set(cats));
  }, [budgets]);

  // Form state
  const [name, setName] = useState('');
  const [total, setTotal] = useState<number | ''>('');
  const [myPart, setMyPart] = useState<number | ''>('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState('');

  // Sincronizar la categoría seleccionada por defecto al abrir el modal
  useEffect(() => {
    if (isAdding && budgetExpenseCategories.length > 0 && !category) {
      setCategory(budgetExpenseCategories[0]);
    }
  }, [isAdding, budgetExpenseCategories, category]);

  // Notes editing in Modal
  const [modalNotes, setModalNotes] = useState('');

  // Encuentra el reembolso actualmente seleccionado desde el estado global
  const selectedRefund = refunds.find(r => r.id === selectedRefundId);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (total === '' || myPart === '' || !category) return;
    const pending = total - myPart;
    addRefund({
      name,
      totalAmount: total,
      paidByMe: myPart,
      pendingAmount: pending,
      status: pending <= 0 ? 'closed' : 'open',
      notes,
      date: new Date().toISOString(),
      category: category
    });
    setIsAdding(false);
    resetForm();
  };

  const resetForm = () => { 
    setName(''); 
    setTotal(''); 
    setMyPart(''); 
    setNotes(''); 
    setCategory(budgetExpenseCategories[0] || ''); 
  };

  const handleCardClick = (r: Refund) => {
    if (isMerging) {
      setMergeSelection(prev => {
        if (prev.includes(r.id)) return prev.filter(x => x !== r.id);
        if (prev.length >= 2) return prev; 
        return [...prev, r.id];
      });
    } else {
      setSelectedRefundId(r.id);
      setModalNotes(r.notes || '');
    }
  };

  const executeMerge = () => {
    if (mergeSelection.length === 2) {
      mergeRefunds(mergeSelection[0], mergeSelection[1]);
      setMergeSelection([]);
      setIsMerging(false);
    }
  };

  const handleActionClick = (e: React.MouseEvent, action: () => void) => {
    e.stopPropagation();
    e.preventDefault();
    action();
  };

  const handleSaveNotes = () => {
    if (selectedRefund) {
        updateRefund({ ...selectedRefund, notes: modalNotes });
        setSelectedRefundId(null);
    }
  };

  const filteredRefunds = refunds.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Reembolsos</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight">Gestiona deudas pendientes. Los cobros reducen el gasto neto del mes.</p>
        </div>
        <div className="flex gap-2">
          {isMerging && mergeSelection.length === 2 && (
             <button 
                type="button"
                onClick={executeMerge}
                className="flex items-center gap-2 px-6 py-3 bg-amber-600 text-white font-bold rounded-2xl shadow-lg hover:bg-amber-700 transition-all animate-in zoom-in"
             >
                <Check size={18} /> CONFIRMAR FUSIÓN
             </button>
          )}

          {refunds.length >= 2 && (
            <button 
              type="button"
              onClick={() => {
                setIsMerging(!isMerging);
                setMergeSelection([]);
              }}
              className={`flex items-center gap-2 px-6 py-3 font-bold rounded-2xl transition-all shadow-sm ${isMerging ? 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300' : 'bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
            >
              <Merge size={18} />
              {isMerging ? 'Cancelar' : 'Unificar Deudas'}
            </button>
          )}
          <button 
            type="button"
            onClick={() => setIsAdding(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
          >
            <Plus size={18} />
            Nuevo Reembolso
          </button>
        </div>
      </div>

      <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl w-fit border border-slate-200 dark:border-slate-700 shadow-inner">
        <button type="button" onClick={() => setFilter('open')} className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all ${filter === 'open' ? 'bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>PENDIENTES</button>
