import { GoogleGenAI, Type, FunctionDeclaration, GenerateContentResponse } from "@google/genai";
import { Transaction, Budget, AIChallenge } from "../types";

export interface ScannedTransaction {
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  isTransfer: boolean;
  isSaving: boolean;
  isRefund: boolean;
  suggestedAccount?: string;
}

// Analiza una captura de pantalla o ticket extrayendo múltiples líneas y categorizando inteligentemente.
export const analyzeReceipt = async (base64Image: string): Promise<ScannedTransaction[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: `Analiza esta captura de pantalla de movimientos bancarios o ticket. 
        Extrae UNA LISTA de todas las transacciones visibles. 
        Para cada una, determina con precisión:
        1. description: concepto claro.
        2. amount: importe (siempre positivo, usa punto para decimales).
        3. date: fecha en formato YYYY-MM-DD.
        4. category: categoría lógica del presupuesto.
        5. type: 'income' si es un abono/entrada de dinero a la cuenta, 'expense' si es un cargo/salida.
        6. isTransfer: true si detectas que es un movimiento entre cuentas propias (ej: "Traspaso").
        7. isSaving: true si el concepto indica ahorro o inversión (ej: "A mi hucha", "Retirada de hucha", "S&P500"). IMPORTANTE: Si es dinero que SALE de la hucha hacia el banco, el type debe ser 'income'. Si es dinero que ENTRA a la hucha desde el banco, el type debe ser 'expense'.
        8. isRefund: true si el concepto sugiere un reembolso o pago de deuda compartida (ej: "Bizum cena").
        9. suggestedAccount: nombre de la cuenta bancaria si aparece en la captura.` }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            type: { type: Type.STRING, enum: ['income', 'expense'] },
            isTransfer: { type: Type.BOOLEAN },
            isSaving: { type: Type.BOOLEAN },
            isRefund: { type: Type.BOOLEAN },
            suggestedAccount: { type: Type.STRING }
          },
          required: ['description', 'amount', 'date', 'category', 'type', 'isTransfer', 'isSaving', 'isRefund']
        }
      }
    }
  });
  return JSON.parse(response.text || "[]");
};

