    } else if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories, type, isRefundLink, selectedRefundId, refunds, category]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory('');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setSelectedSavingId('');
    setMyPartManual('');
    setIsTransfer(false);
    setTransferTargetId('');
    setEditingTx(null);
    setSavingDirection('deposit');
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (isTransfer) {
      addTransaction({
        date,
        amount: Number(amount),
        description: `Transferencia a ${accounts.find(a => a.id === transferTargetId)?.name || 'Cuenta'}`,
        category: 'Traspaso',
        type: 'expense',
        accountId,
        isRefund: false
      });
      addTransaction({
        date,
        amount: Number(amount),
        description: `Transferencia desde ${accounts.find(a => a.id === accountId)?.name || 'Cuenta'}`,
        category: 'Traspaso',
        type: 'income',
        accountId: transferTargetId,
        isRefund: false
      });
    } else {
      const finalType = type === 'saving' 
        ? (savingDirection === 'deposit' ? 'expense' : 'income') 
        : type;
      const finalCategory = type === 'saving' ? 'Ahorro' : category;

      if (editingTx) {
        updateTransaction({
          ...editingTx,
          date,
          amount: Number(amount),
          description: desc,
          category: finalCategory,
          type: finalType as any,
          accountId,
          refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined,
          savingId: type === 'saving' ? selectedSavingId : undefined
        });
      } else {
        addTransaction({
          date,
          amount: Number(amount),
          description: desc,
          category: finalCategory,
          type: finalType as any,
          accountId,
          isRefund: isRefundLink,
          refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined,
          savingId: type === 'saving' ? selectedSavingId : undefined
        }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
      }
    }
    setIsAdding(false);
    resetForm();
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Transacciones</h2>
          <p className="text-slate-700 dark:text-slate-400 font-bold text-sm">Gestiona tus movimientos con céntimos (usa coma o punto).</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-6 py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 font-black rounded-2xl hover:bg-slate-50 transition-all"><Camera size={20} className="text-blue-500" /><span>Aura Vision</span></button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" />
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"><Plus size={20} /><span>Nueva</span></button>
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
             <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-10 shadow-2xl border border-slate-200 dark:border-slate-800 overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center mb-10">
                  <h3 className="text-3xl font-black text-slate-900 dark:text-white">{editingTx ? 'Editar Movimiento' : 'Nuevo Movimiento'}</h3>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-4 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={28} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 dark:bg-slate-800 p-2 rounded-[1.8rem] border border-slate-200">
                    <button type="button" onClick={() => {setType('expense'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' && !isTransfer ? 'bg-white dark:bg-slate-700 text-rose-600 shadow-md' : 'text-slate-500'}`}>GASTO</button>
                    <button type="button" onClick={() => {setType('income'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' && !isTransfer ? 'bg-white dark:bg-slate-700 text-emerald-600 shadow-md' : 'text-slate-500'}`}>INGRESO</button>
                    <button type="button" onClick={() => {setType('saving'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'saving' ? 'bg-white dark:bg-slate-700 text-amber-500 shadow-md' : 'text-slate-500'}`}>AHORRO</button>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[11px] font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest mb-3">Descripción</label>
                      <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest mb-3">Importe (€)</label>
                        <input 
                          type="number" 
                          step="0.01" 
                          inputMode="decimal"
                          value={amount} 
                          onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} 
                          className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-black text-xl outline-none text-slate-900 dark:text-white" 
                          required 
                        />
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest mb-3">Fecha</label>
                        <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required />
                      </div>
                    </div>

                    {isRefundLink && type === 'expense' && (
                      <div>
                         <label className="block text-[11px] font-black text-blue-700 dark:text-blue-400 uppercase mb-3">Tu Parte (€)</label>
                         <input type="number" step="0.01" value={myPartManual} onChange={e => setMyPartManual(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-blue-50 dark:bg-blue-900/20 border-2 border-blue-200 dark:border-blue-700 rounded-xl p-4 font-black outline-none text-slate-900 dark:text-white" />
                      </div>
                    )}
                  </div>

                  <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl active:scale-95 transition-all">
                    CONFIRMAR Y GUARDAR
                  </button>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { useNavigate } from 'react-router-dom';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2,
  ChevronRight,
  Sparkles,
  Loader2,
  ShoppingBag,
  AlertCircle,
  History,
  X,
  ArrowRightLeft
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { generateAIChallenges } from '../services/geminiService';
import { Budget, Transaction } from '../types';
import { ICON_MAP } from '../constants';

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    budgets,
    currentDate,
    dashboardLayout,
    updateLayout,
    setChallenges,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    getNetWorthHistorical, 
    viewMode,
    theme
  } = useFinance();

  const navigate = useNavigate();
  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');
  const [showBreakdown, setShowBreakdown] = useState(false);
  const [isGeneratingChallenges, setIsGeneratingChallenges] = useState(false);
  const [selectedBudgetForDetails, setSelectedBudgetForDetails] = useState<Budget | null>(null); 
  const [isBudgetsExpanded, setIsBudgetsExpanded] = useState(false); 

  const isSavingTx = (t: Transaction) => t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;
  const isTransferTx = (t: Transaction) => t.category === 'Traspaso' || t.category === 'Transferencia';

  const metrics = useMemo(() => {
    let prevDateStr: string;
    if (viewMode === 'year') {
      prevDateStr = (parseInt(currentDate) - 1).toString();
    } else {
      const parts = currentDate.split('-').map(Number);
      const date = new Date(parts[0], parts[1] - 2, 1);
      const y = date.getFullYear();
      const m = String(date.getMonth() + 1).padStart(2, '0');
      prevDateStr = `${y}-${m}`;
    }

    const pastLiquidBalance = accounts.reduce((sum, acc) => sum + getAccountHistoricalBalance(acc.id, prevDateStr), 0);
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));

    // 1. Ingresos Base (Nómina, etc) - Sin contar reembolsos ni ahorros
    const baseIncome = monthTx
      .filter(t => t.type === 'income' && !t.refundId && !isSavingTx(t) && !isTransferTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    // 2. Reembolsos recuperados (Reducen el gasto neto)
    const refundRecoveries = monthTx
      .filter(t => t.type === 'income' && t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    // 3. Gastos Base - Sin contar ahorros
    const baseSpending = monthTx
      .filter(t => t.type === 'expense' && !isSavingTx(t) && !isTransferTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    // 4. MOVIMIENTOS DE AHORRO (Algoritmo solicitado)
    // Aportaciones (Salen de cuenta a hucha): Se tratan como "gasto" de liquidez
    const savingDeposits = monthTx
      .filter(t => t.type === 'expense' && isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    // Retiradas (Entran a cuenta desde hucha): Se suman a los ingresos líquidos
    const savingWithdrawals = monthTx
      .filter(t => t.type === 'income' && isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    // Cálculos Finales de Liquidez
    const totalLiquidityInflow = baseIncome + savingWithdrawals;
    const netSpending = Math.max(0, baseSpending - refundRecoveries);

    // Resultado del mes = (Ingresos + Retiradas Ahorro) - (Gastos Netos + Aportaciones Ahorro)
    const monthResult = totalLiquidityInflow - netSpending - savingDeposits;

    const liquidity = pastLiquidBalance + monthResult;
    const totalSavingsAccumulated = savings.reduce((sum, s) => sum + getSavingHistoricalBalance(s.id, currentDate), 0);
    const netWorth = liquidity + totalSavingsAccumulated;

    return { 
      income: baseIncome, 
      expense: netSpending, 
      savingDeposits, 
      savingWithdrawals,
      monthResult, 
      pastLiquidBalance, 
      liquidity, 
      totalSavingsAccumulated, 
      netWorth, 
      refundRecoveries,
      totalLiquidityInflow
    };
  }, [transactions, currentDate, accounts, savings, getAccountHistoricalBalance, getSavingHistoricalBalance, viewMode]);

  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;
      if (ch.type === 'spending_limit') {
        const spent = monthTx.filter(t => t.type === 'expense' && t.category === ch.category).reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavingsAccumulated >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.income >= ch.target;
      }
      return { ...ch, completed: isCompleted || ch.completed };
    });
  }, [challenges, transactions, currentDate, metrics]);

  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;
    const currentYear = parseInt(currentDate.substring(0, 4));
    const currentMonthIndex = viewMode === 'month' ? parseInt(currentDate.substring(5, 7)) - 1 : 11;
    const data = Array.from({ length: limit }).map((_, i) => {
        const date = new Date(currentYear, currentMonthIndex, 1);
        date.setMonth(date.getMonth() - (limit - 1 - i));
        const displayMonthIndex = date.getMonth();
        const displayYear = date.getFullYear();
        const dateStrForCalculation = viewMode === 'year' ? displayYear.toString() : `${displayYear}-${String(displayMonthIndex + 1).padStart(2, '0')}`;
        const patrimonio = getNetWorthHistorical(dateStrForCalculation);
        return { name: monthNames[displayMonthIndex], fullLabel: `${monthNames[displayMonthIndex]} ${displayYear}`, patrimonio };
    });
    return data;
  }, [getNetWorthHistorical, chartFilter, currentDate, viewMode]);

  const handleGenerateChallenges = async () => {
    setIsGeneratingChallenges(true);
    try {
      const budgetsInfo = budgets.map(b => {
        const calculatedSpent = transactions.filter(t => t.date.startsWith(currentDate) && t.category === b.category).reduce((sum, t) => {
            if (b.type === 'expense') {
              if (t.type === 'expense') return sum + t.amount;
              if (t.type === 'income' && t.refundId) return sum - t.amount;
            }
            if (b.type === 'income' && t.type === 'income') return sum + t.amount;
            return sum;
          }, 0);
        return `${b.category}: ${calculatedSpent}/${b.limit}€`;
      }).join(", ");
      const context = `Presupuestos: ${budgetsInfo}. Patrimonio: ${metrics.netWorth}€. Ahorros: ${metrics.totalSavingsAccumulated}€.`;
      const newChallenges = await generateAIChallenges(context);
      setChallenges(newChallenges);
    } catch (error) { console.error("Error generating challenges:", error); } finally { setIsGeneratingChallenges(false); }
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newLayout = [...dashboardLayout];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLayout.length) return;
    [newLayout[index], newLayout[targetIndex]] = [newLayout[targetIndex], newLayout[index]];
    updateLayout(newLayout);
  };

  const budgetsWithCalculatedSpent = useMemo(() => {
    return budgets.map(b => {
      const calculatedSpent = transactions.filter(t => t.date.startsWith(currentDate) && t.category === b.category).reduce((sum, t) => {
          if (isTransferTx(t)) return sum; 
          if (b.type === 'expense') {
            if (t.type === 'expense') return sum + t.amount;
            if (t.type === 'income' && t.refundId) return sum - t.amount;
          }
          if (b.type === 'income') {
            if (t.type === 'income' && !t.refundId) return sum + t.amount;
          }
          return sum;
        }, 0);
      const totalRefundedForCategory = transactions.filter(t => t.date.startsWith(currentDate) && t.category === b.category && t.type === 'income' && !!t.refundId).reduce((sum, t) => sum + t.amount, 0);
      return { ...b, spent: calculatedSpent, totalRefunded: totalRefundedForCategory };
    });
  }, [budgets, transactions, currentDate]);

  const renderBlock = (key: string, index: number) => {
    const moveControls = isEditMode && (
      <div className="absolute top-4 right-4 flex gap-1 z-20">
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'up'); }} className="p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-95" disabled={index === 0}><ChevronUp size={16} className="text-slate-600 dark:text-slate-400" /></button>
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'down'); }} className="p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-95" disabled={index === dashboardLayout.length - 1}><ChevronDown size={16} className="text-slate-600 dark:text-slate-400" /></button>
      </div>
    );

    switch (key) {
      case 'balance':
        return (
          <div key={key} className="relative bg-[#2563eb] dark:bg-blue-600 rounded-[2.5rem] p-8 md:p-10 text-white shadow-2xl shadow-blue-200/50 dark:shadow-blue-900/20 overflow-hidden transition-colors duration-300">
            {moveControls}
            <div className="relative z-10 flex flex-col">
              <div className="flex justify-between items-start mb-10">
                <div><p className="text-blue-100 text-[9px] font-black uppercase tracking-[0.2em] mb-2 opacity-80">Patrimonio Neto en {currentDate}</p><h2 className="text-4xl md:text-5xl font-black tracking-tight">{metrics.netWorth.toLocaleString()}€</h2></div>
                <button onClick={() => setShowBreakdown(!showBreakdown)} className={`px-5 py-3 rounded-2xl flex items-center gap-2 text-xs font-black transition-all shadow-lg bg-white/20 backdrop-blur-md hover:bg-white/30 active:scale-95`}>{metrics.monthResult >= 0 ? <TrendingUp size={16} /> : <TrendingDown size={16} />}{metrics.monthResult >= 0 ? '+' : ''}{metrics.monthResult.toLocaleString()}€ este mes<ChevronDown size={14} className={`transition-transform duration-300 ${showBreakdown ? 'rotate-180' : ''}`} /></button>
              </div>
              {showBreakdown && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8 animate-in slide-in-from-top-4 duration-300">
                  <div className="p-5 bg-blue-400/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-blue-100">Entrada Líquida</p>
                    <p className="text-2xl font-black">{metrics.totalLiquidityInflow.toLocaleString()}€</p>
                    <p className="text-[8px] opacity-70 mt-1">Base: {metrics.income}€ + Retiradas Ahorro: {metrics.savingWithdrawals}€</p>
                  </div>
                  <div className="p-5 bg-[#4c51bf]/40 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-indigo-100">Gasto Neto Líquido</p>
                    <p className="text-2xl font-black">{metrics.expense.toLocaleString()}€</p>
                    {metrics.refundRecoveries > 0 && (<p className="text-[9px] font-bold text-indigo-200 opacity-80 mt-1">(-{metrics.refundRecoveries.toLocaleString()}€ de reembolsos)</p>)}
                  </div>
                  <div className="p-5 bg-amber-500/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-amber-100">Aportado al Ahorro</p>
                    <p className="text-2xl font-black">{metrics.savingDeposits.toLocaleString()}€</p>
                    <p className="text-[8px] opacity-70 mt-1">Restado de la liquidez mensual</p>
                  </div>
                </div>
              )}
              <div className="h-px bg-white/15 w-full mb-8"></div>
              <div className="grid grid-cols-3 gap-8">
                <div><p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Saldo Anterior</p><p className="text-xl md:text-2xl font-black">{metrics.pastLiquidBalance.toLocaleString()}€</p></div>
                <div><p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Variación Mes</p><p className="text-xl md:text-2xl font-black">{metrics.monthResult.toLocaleString()}€</p></div>
                <div><p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Líquido Disponible</p><p className="text-xl md:text-2xl font-black">{metrics.liquidity.toLocaleString()}€</p></div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
