import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  X, 
  UserCheck, 
  AlertCircle, 
  Check, 
  PiggyBank, 
  ChevronDown, 
  Split,
  Camera,
  Loader2,
  Sparkles,
  ArrowRightLeft,
  ArrowRight,
  Ban,
  ArrowDownCircle,
  ArrowUpCircle
} from 'lucide-react';
import { Transaction } from '../types';
import { analyzeReceipt, ScannedTransaction } from '../services/geminiService';

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, theme, currentDate, viewMode } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  const [isScanning, setIsScanning] = useState(false);
  const [scannedQueue, setScannedQueue] = useState<ScannedTransaction[]>([]);
  const [totalScannedCount, setTotalScannedCount] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const location = useLocation();

  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  const [isTransfer, setIsTransfer] = useState(false);
  const [transferTargetId, setTransferTargetId] = useState('');
  const [savingDirection, setSavingDirection] = useState<'deposit' | 'withdraw'>('deposit');

  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];
    if (type === 'income' && isRefundLink && selectedRefundId) {
      const selectedRefund = refunds.find(r => r.id === selectedRefundId);
      if (selectedRefund) return [selectedRefund.category];
    }
    if (type === 'income' && isRefundLink) {
      const expenseCats = budgets.filter(b => b.type === 'expense').map(b => b.category);
      return expenseCats.length > 0 ? Array.from(new Set(expenseCats)) : ["Sin Presupuesto de Gasto"];
    }
    const budgetList = budgets
      .filter(b => b.type === (type as any === 'saving' ? 'expense' : type as any))
      .map(b => b.category);
    const uniqueCategories = Array.from(new Set(budgetList));
    return uniqueCategories.length > 0 ? uniqueCategories : ["Sin Presupuesto"];
  }, [type, isRefundLink, selectedRefundId, budgets, refunds]);

  useEffect(() => {
    if (type === 'income' && isRefundLink && selectedRefundId) {
      const refundObj = refunds.find(r => r.id === selectedRefundId);
      if (refundObj) setCategory(refundObj.category);
    } else if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories, type, isRefundLink, selectedRefundId, refunds, category]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory('');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setSelectedSavingId('');
    setMyPartManual('');
    setIsTransfer(false);
    setTransferTargetId('');
    setEditingTx(null);
    setSavingDirection('deposit');
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (isTransfer) {
      addTransaction({
        date,
        amount: Number(amount),
        description: `Transferencia a ${accounts.find(a => a.id === transferTargetId)?.name || 'Cuenta'}`,
        category: 'Traspaso',
        type: 'expense',
        accountId,
        isRefund: false
      });
      addTransaction({
        date,
        amount: Number(amount),
        description: `Transferencia desde ${accounts.find(a => a.id === accountId)?.name || 'Cuenta'}`,
        category: 'Traspaso',
        type: 'income',
        accountId: transferTargetId,
        isRefund: false
      });
    } else {
      const finalType = type === 'saving' 
        ? (savingDirection === 'deposit' ? 'expense' : 'income') 
        : type;
      const finalCategory = type === 'saving' ? 'Ahorro' : category;

      if (editingTx) {
        updateTransaction({
          ...editingTx,
          date,
          amount: Number(amount),
          description: desc,
          category: finalCategory,
          type: finalType as any,
          accountId,
          refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined,
          savingId: type === 'saving' ? selectedSavingId : undefined
        });
      } else {
        addTransaction({
          date,
          amount: Number(amount),
          description: desc,
          category: finalCategory,
          type: finalType as any,
          accountId,
          isRefund: isRefundLink,
          refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined,
          savingId: type === 'saving' ? selectedSavingId : undefined
        }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
      }
    }
    setIsAdding(false);
    resetForm();
  };

  const filteredTx = useMemo(() => {
    return transactions
      .filter(t => {
        const matchesPeriod = t.date.startsWith(currentDate);
        if (!matchesPeriod) return false;

        let matchesType = true;
        const isSaving = t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;
        const isRefund = t.type === 'income' && !!t.refundId;

        if (filter === 'income') matchesType = t.type === 'income' && !t.refundId && !isSaving;
        else if (filter === 'expense') matchesType = t.type === 'expense' && !isSaving;
        else if (filter === 'savings') matchesType = isSaving;
        else if (filter === 'refunds') matchesType = isRefund;

        const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                              t.category.toLowerCase().includes(searchTerm.toLowerCase());

        return matchesType && matchesSearch;
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, filter, searchTerm, currentDate]);

  const getTxStyle = (t: Transaction) => {
    const isSaving = t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;
    const isRefund = t.type === 'income' && !!t.refundId;
    const isWithdrawal = isSaving && t.type === 'income';

    if (isSaving) {
        return { 
            color: isWithdrawal ? 'text-amber-600 dark:text-amber-400' : 'text-amber-500', 
            bg: 'bg-amber-50 dark:bg-amber-900/40', 
            icon: isWithdrawal ? <ArrowDownCircle size={18} /> : <ArrowUpRight size={18} /> 
        };
    }
    if (isRefund) return { color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-900/40', icon: <ArrowUpRight size={18} /> }; 
    if (t.type === 'income') return { color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-900/40', icon: <ArrowUpRight size={18} /> }; 
    return { color: 'text-rose-600 dark:text-rose-400', bg: 'bg-rose-50 dark:bg-rose-900/40', icon: <ArrowDownRight size={18} /> }; 
  };

  const isCategoryDisabled = type === 'income' && isRefundLink && !!selectedRefundId;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Transacciones</h2>
          <p className="text-slate-700 dark:text-slate-400 font-bold text-sm">Gestiona tus movimientos con céntimos (usa coma o punto).</p>
        </div>
        <div className="flex gap-2">
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-6 py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 font-black rounded-2xl hover:bg-slate-50 transition-all shadow-sm active:scale-95"><Camera size={20} className="text-blue-500" /><span>Aura Vision</span></button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" />
          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"><Plus size={20} /><span>Nueva</span></button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-xl shadow-slate-200/50 dark:shadow-none overflow-hidden transition-all duration-300">
        <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 flex flex-col gap-4 bg-slate-50/30 dark:bg-slate-800/20">
          <div className="flex items-center gap-1 bg-white dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 shadow-sm w-full overflow-x-auto no-scrollbar">
            <button onClick={() => setFilter('all')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 dark:bg-slate-700 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 dark:bg-emerald-600 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 dark:bg-rose-600 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 dark:bg-amber-600 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>AHORROS</button>
            <button onClick={() => setFilter('refunds')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 dark:bg-blue-600 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>REEMBOLSOS</button>
          </div>
          <div className="flex items-center gap-3 bg-white dark:bg-slate-800 px-5 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
            <Search size={18} className="text-slate-500" />
            <input type="text" placeholder="Buscar..." className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 dark:text-white" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/>
          </div>
        </div>
        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse">
            <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
              {filteredTx.map(tx => {
                const style = getTxStyle(tx);
                return (
                  <tr key={tx.id} onClick={() => setViewingTx(tx)} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-all cursor-pointer">
                    <td className="px-6 py-6 text-[11px] font-black text-slate-500 uppercase">{new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}</td>
                    <td className="px-6 py-6"><div className="flex items-center gap-4"><div className={`w-9 h-9 rounded-xl flex items-center justify-center ${style.bg} ${style.color}`}>{style.icon}</div><div><p className="font-black text-slate-800 dark:text-white text-sm">{tx.description}</p><p className="text-[9px] font-black text-slate-400 uppercase">{tx.category}</p></div></div></td>
                    <td className={`px-6 py-6 text-right font-black text-lg ${style.color}`}>{tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
             <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-10 shadow-2xl border border-slate-200 dark:border-slate-800 overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center mb-10">
                  <h3 className="text-3xl font-black text-slate-900 dark:text-white">{editingTx ? 'Editar' : 'Nuevo'} Movimiento</h3>
                  <button onClick={() => { setIsAdding(false); resetForm(); }} className="p-4 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={28} /></button>
                </div>
                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 dark:bg-slate-800 p-2 rounded-[1.8rem] border border-slate-200">
                    <button type="button" onClick={() => {setType('expense'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' && !isTransfer ? 'bg-white dark:bg-slate-700 text-rose-600 shadow-md' : 'text-slate-500'}`}>GASTO</button>
                    <button type="button" onClick={() => {setType('income'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' && !isTransfer ? 'bg-white dark:bg-slate-700 text-emerald-600 shadow-md' : 'text-slate-500'}`}>INGRESO</button>
                    <button type="button" onClick={() => {setType('saving'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'saving' ? 'bg-white dark:bg-slate-700 text-amber-500 shadow-md' : 'text-slate-500'}`}>AHORRO</button>
                  </div>
                  {type === 'saving' && (
                    <div className="bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl border-2 border-amber-100 dark:border-amber-800 grid grid-cols-2 gap-2">
                        <button type="button" onClick={() => setSavingDirection('deposit')} className={`py-3 rounded-xl text-[10px] font-black ${savingDirection === 'deposit' ? 'bg-amber-500 text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-amber-500 border border-amber-200'}`}>APORTACIÓN</button>
                        <button type="button" onClick={() => setSavingDirection('withdraw')} className={`py-3 rounded-xl text-[10px] font-black ${savingDirection === 'withdraw' ? 'bg-amber-600 text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-amber-600 border border-amber-200'}`}>RETIRADA</button>
                    </div>
                  )}
                  <div className="space-y-6">
                    <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold text-slate-900 dark:text-white" placeholder="Descripción..." required />
                    <div className="grid grid-cols-2 gap-6">
                      <input type="number" step="0.01" inputMode="decimal" value={amount} onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-black text-xl text-slate-900 dark:text-white" placeholder="Importe (€)" required />
                      <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold text-slate-900 dark:text-white" required />
                    </div>
                    <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold text-slate-900 dark:text-white">
                        {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                    </select>
                    {type === 'saving' ? (
                      <select value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold text-slate-900 dark:text-white" required>
                        <option value="">Selecciona hucha</option>
                        {savings.map(s => <option key={s.id} value={s.id}>{s.emoji} {s.name}</option>)}
                      </select>
                    ) : (
                      <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold text-slate-900 dark:text-white" required>
                        {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                    )}
                  </div>
                  <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl active:scale-95 transition-all">CONFIRMAR Y GUARDAR</button>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, PiggyBank, TrendingUp, ArrowRightLeft, Percent, X, Edit2, Trash2, Check } from 'lucide-react';
import { Saving } from '../types';

const Savings: React.FC = () => {
  const { savings, currentDate, getSavingHistoricalBalance, addSaving, updateSaving, deleteSaving } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [editingSaving, setEditingSaving] = useState<Saving | null>(null);
  const [adjustingSaving, setAdjustingSaving] = useState<Saving | null>(null);
  const [adjustmentMode, setAdjustmentMode] = useState<'amount' | 'percent'>('amount');
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // Form State (shared for New/Edit)
  const [name, setName] = useState('');
  const [amountInput, setAmountInput] = useState<number | ''>('');
  const [targetInput, setTargetInput] = useState<number | ''>('');
  const [isInvestment, setIsInvestment] = useState(false);
  const [growthRateInput, setGrowthRateInput] = useState<number | ''>('');
  const [emoji, setEmoji] = useState('💰');

  // Adjustment Modal State
  const [adjValue, setAdjValue] = useState<number | ''>('');

  const resetForm = () => {
    setName('');
    setAmountInput('');
    setTargetInput('');
    setIsInvestment(false);
    setGrowthRateInput('');
    setEmoji('💰');
    setIsAdding(false);
    setEditingSaving(null);
  };

  const handleOpenEdit = (s: Saving) => {
    setName(s.name);
    setAmountInput(s.currentAmount);
    setTargetInput(s.targetAmount || '');
    setIsInvestment(s.isInvestment);
    setGrowthRateInput(s.growthRate || '');
    setEmoji(s.emoji || (s.isInvestment ? '📈' : '💰'));
    setEditingSaving(s);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalAmount = amountInput === '' ? 0 : amountInput;
    const finalTarget = targetInput === '' ? undefined : targetInput;
    const finalGrowth = isInvestment && growthRateInput !== '' ? growthRateInput : undefined;

    if (editingSaving) {
      updateSaving({
        ...editingSaving,
        name,
        currentAmount: finalAmount,
        targetAmount: finalTarget,
        isInvestment,
        growthRate: finalGrowth,
        emoji,
      });
    } else {
      addSaving({
        name,
        currentAmount: finalAmount,
        targetAmount: finalTarget,
        isInvestment,
        growthRate: finalGrowth,
        color: '#f59e0b',
        emoji,
      });
    }
    resetForm();
  };

  const applyAdjustment = () => {
    if (!adjustingSaving || adjValue === '') return;

    let newAmount = adjustingSaving.currentAmount;
    if (adjustmentMode === 'amount') {
      newAmount += adjValue;
    } else {
      newAmount = newAmount * (1 + adjValue / 100);
    }

    updateSaving({ ...adjustingSaving, currentAmount: Math.max(0, newAmount) });
    setAdjustingSaving(null);
    setAdjValue('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Huchas e Inversiones</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight">Gestiona objetivos de ahorro. Mostrando estado a {currentDate}.</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
        >
          <Plus size={18} />
          Crear Hucha
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {savings.map(s => {
          const displayAmount = getSavingHistoricalBalance(s.id, currentDate);
          const progress = s.targetAmount ? Math.min((displayAmount / s.targetAmount) * 100, 100) : null;
          const isConfirming = confirmDeleteId === s.id;

          return (
            <div key={s.id} className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 shadow-sm relative group hover:shadow-md transition-all duration-300">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner dark:shadow-none ${s.isInvestment ? 'bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 dark:text-indigo-400' : 'bg-amber-50 dark:bg-amber-900/40 text-amber-600 dark:text-amber-400'} transition-colors`}>
                    {s.emoji || (s.isInvestment ? '📈' : '💰')}
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-800 dark:text-slate-100">{s.name}</h4>
                    <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">
                      {s.isInvestment ? 'Inversión' : 'Ahorro Manual'}
                    </p>
                  </div>
                </div>
                <div className={`flex gap-1 transition-opacity ${isConfirming ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                  {!isConfirming ? (
                    <>
                      <button 
                        onClick={() => handleOpenEdit(s)}
                        className="p-2 text-slate-300 dark:text-slate-600 hover:text-blue-500 dark:hover:text-blue-400 transition-all"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => setConfirmDeleteId(s.id)}
                        className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 transition-all"
                      >
                        <Trash2 size={18} />
                      </button>
                    </>
                  ) : (
                    <div className="flex gap-1 items-center animate-in slide-in-from-right-2">
                       <button 
                        onClick={() => { deleteSaving(s.id); setConfirmDeleteId(null); }}
                        className="flex items-center gap-1 px-3 py-1.5 bg-rose-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-700 transition-all"
                      >
                        <Check size={14} /> Confirmar
                      </button>
                      <button 
                        onClick={() => setConfirmDeleteId(null)}
                        className="p-1.5 bg-slate-100 dark:bg-slate-800 rounded-lg text-slate-400 hover:text-slate-600 transition-all"
                      >
                        <X size={16} />
                      </button>
                    </div>
                  )}
                </div>
              </div>

              <div className="mb-6">
                <div className="flex items-baseline gap-2">
                  <span className="text-4xl font-black text-slate-900 dark:text-white">{displayAmount.toLocaleString('es-ES', { maximumFractionDigits: 2 })}€</span>
                  {s.growthRate && (
                    <span className="text-xs font-bold text-emerald-500 dark:text-emerald-400 flex items-center gap-0.5">
                      <TrendingUp size={12} /> {s.growthRate}%
                    </span>
                  )}
                </div>

                {progress !== null && (
                  <div className="mt-6">
                    <div className="flex justify-between text-[10px] font-black uppercase tracking-wider mb-2">
                      <span className="text-blue-600 dark:text-blue-400">{progress.toFixed(1)}% Completado</span>
                      <span className="text-slate-400 dark:text-slate-500">Meta: {s.targetAmount}€</span>
                    </div>
                    <div className="w-full bg-slate-100 dark:bg-slate-800 h-2.5 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-blue-600 dark:bg-blue-50 rounded-full transition-all duration-1000 ease-out" 
                        style={{ width: `${progress}%` }}
                      ></div>
                    </div>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={() => { setAdjustingSaving(s); setAdjustmentMode('amount'); }}
                  className="flex items-center justify-center gap-2 py-3 bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-2xl font-bold text-xs hover:bg-slate-100 dark:hover:bg-slate-700 transition-all border border-slate-100 dark:border-slate-700"
                >
                  <ArrowRightLeft size={16} className="text-blue-500 dark:text-blue-400" /> Ajustar Saldo
                </button>
                <button 
                  onClick={() => { setAdjustingSaving(s); setAdjustmentMode('percent'); }}
                  className="flex items-center justify-center gap-2 py-3 bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-2xl font-bold text-xs hover:bg-slate-100 dark:hover:bg-slate-700 transition-all border border-slate-100 dark:border-slate-700"
                >
                  <Percent size={16} className="text-emerald-500 dark:text-emerald-400" /> Aplicar %
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {adjustingSaving && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-sm p-10 shadow-2xl animate-in fade-in zoom-in duration-300 border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-slate-800 dark:text-slate-100">
                {adjustmentMode === 'amount' ? 'Ajustar Cantidad' : 'Ajuste Porcentual'}
              </h3>
              <button onClick={() => { setAdjustingSaving(null); setAdjValue(''); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <div className="space-y-6">
              <div className="text-center">
                <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase mb-2">Hucha: {adjustingSaving.name}</p>
                <div className="flex items-center justify-center gap-3">
                  <input 
                    type="number" 
                    step="0.01"
                    inputMode="decimal"
                    value={adjValue} 
                    onChange={e => setAdjValue(e.target.value === '' ? '' : Number(e.target.value))}
                    autoFocus
                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-6 text-center text-4xl font-black outline-none focus:ring-2 focus:ring-blue-500 transition-all text-slate-900 dark:text-white"
                    placeholder="0"
                  />
                  <span className="text-2xl font-black text-slate-400 dark:text-slate-500">
                    {adjustmentMode === 'amount' ? '€' : '%'}
                  </span>
                </div>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => { setAdjustingSaving(null); setAdjValue(''); }}
                  className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  onClick={applyAdjustment}
                  disabled={adjValue === ''}
                  className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 dark:shadow-none transition-all active:scale-95 disabled:opacity-50"
                >
                  Confirmar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {(isAdding || editingSaving) && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300 overflow-y-auto max-h-[90vh] border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800 dark:text-slate-100">{editingSaving ? 'Editar Hucha' : 'Nueva Meta'}</h3>
              <button onClick={resetForm} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
                <X size={20} className="text-slate-400" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Nombre del objetivo</label>
                <input 
                  type="text" 
                  value={name} 
                  onChange={e => setName(e.target.value)}
                  className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium text-slate-900 dark:text-slate-100" 
                  placeholder="Ej: Fondo para el Coche" 
                  required 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Monto Actual</label>
                  <input 
                    type="number" 
                    step="0.01"
                    inputMode="decimal"
                    value={amountInput} 
                    onChange={e => setAmountInput(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white" 
                    placeholder="0"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Meta Final</label>
                  <input 
                    type="number" 
                    step="0.01"
                    inputMode="decimal"
                    value={targetInput} 
                    onChange={e => setTargetInput(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white" 
                    placeholder="Opcional"
                  />
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Emoticono</label>
                <input 
                  type="text" 
                  value={emoji} 
                  onChange={e => setEmoji(e.target.value)}
                  className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 text-center text-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900 dark:text-white" 
                  placeholder="💰"
                />
              </div>

              <div className="flex items-center gap-3 p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700 cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors" onClick={() => setIsInvestment(!isInvestment)}>
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isInvestment ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-700 text-slate-400 shadow-sm'}`}>
                  {isInvestment ? <TrendingUp size={20} /> : <PiggyBank size={20} />}
                </div>
                <div className="flex-1">
                  <p className="text-sm font-bold text-slate-700 dark:text-slate-200">¿Es una inversión?</p>
                  <p className="text-[10px] text-slate-400 font-medium">Habilita seguimiento de rendimiento.</p>
                </div>
                <div className={`w-6 h-6 rounded-full border-2 transition-all flex items-center justify-center ${isInvestment ? 'border-indigo-600 bg-indigo-600' : 'border-slate-300 dark:border-slate-600'}`}>
                  {isInvestment && <div className="w-2 h-2 bg-white rounded-full"></div>}
                </div>
              </div>

              {isInvestment && (
                <div className="animate-in slide-in-from-top-2 duration-200">
                  <label className="block text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Rendimiento Estimado Anual (%)</label>
                  <input 
                    type="number" 
                    step="0.01"
                    inputMode="decimal"
                    value={growthRateInput} 
                    onChange={e => setGrowthRateInput(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white" 
                    placeholder="Opcional"
                  />
                </div>
              )}

              <div className="flex gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={resetForm} 
                  className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 dark:shadow-none transition-all active:scale-95"
                >
                  {editingSaving ? 'Guardar Cambios' : 'Crear Hucha'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Savings;

import React, { useMemo, useState } from 'react';
import { useFinance } from '../App';
import { useNavigate } from 'react-router-dom';
import { 
  TrendingUp, 
  TrendingDown, 
  Target, 
  PiggyBank,
  Wallet,
  CheckCircle2,
  Circle,
  ChevronUp,
  ChevronDown,
  Settings2,
  ChevronRight,
  Sparkles,
  Loader2,
  ShoppingBag,
  AlertCircle,
  History,
  X
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { generateAIChallenges } from '../services/geminiService';
import { Budget, Transaction } from '../types';
import { ICON_MAP } from '../constants';

const Dashboard: React.FC = () => {
  const { 
    accounts, 
    savings, 
    transactions, 
    challenges, 
    budgets,
    currentDate,
    dashboardLayout,
    updateLayout,
    setChallenges,
    getAccountHistoricalBalance,
    getSavingHistoricalBalance,
    getNetWorthHistorical, 
    viewMode,
    theme
  } = useFinance();

  const navigate = useNavigate();
  const [isEditMode, setIsEditMode] = useState(false);
  const [chartFilter, setChartFilter] = useState<'6m' | '12m'>('12m');
  const [showBreakdown, setShowBreakdown] = useState(false);
  const [isGeneratingChallenges, setIsGeneratingChallenges] = useState(false);
  const [selectedBudgetForDetails, setSelectedBudgetForDetails] = useState<Budget | null>(null); 
  const [isBudgetsExpanded, setIsBudgetsExpanded] = useState(false); 

  const isSavingTx = (t: Transaction) => t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;
  const isTransferTx = (t: Transaction) => t.category === 'Traspaso' || t.category === 'Transferencia';

  const metrics = useMemo(() => {
    let prevDateStr: string;
    if (viewMode === 'year') {
      prevDateStr = (parseInt(currentDate) - 1).toString();
    } else {
      const parts = currentDate.split('-').map(Number);
      const date = new Date(parts[0], parts[1] - 2, 1);
      const y = date.getFullYear();
      const m = String(date.getMonth() + 1).padStart(2, '0');
      prevDateStr = `${y}-${m}`;
    }

    const pastLiquidBalance = accounts.reduce((sum, acc) => sum + getAccountHistoricalBalance(acc.id, prevDateStr), 0);
    const monthTx = transactions.filter(t => t.date.startsWith(currentDate));

    // 1. Ingresos Estándar (Nómina, ventas, etc)
    const baseIncome = monthTx
      .filter(t => t.type === 'income' && !t.refundId && !isSavingTx(t) && !isTransferTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    // 2. Reembolsos recuperados
    const refundRecoveries = monthTx
      .filter(t => t.type === 'income' && t.refundId)
      .reduce((sum, t) => sum + t.amount, 0);

    // 3. Gastos Estándar
    const baseSpending = monthTx
      .filter(t => t.type === 'expense' && !isSavingTx(t) && !isTransferTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    // 4. MOVIMIENTOS DE AHORRO (Algoritmo solicitado)
    // Dinero que ENTRA a cuenta desde ahorro -> Se suma a ingresos (Liquidez +)
    const savingWithdrawals = monthTx
      .filter(t => t.type === 'income' && isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    // Dinero que SALE de cuenta hacia ahorro -> Se resta del resultado (Liquidez -)
    const savingDeposits = monthTx
      .filter(t => t.type === 'expense' && isSavingTx(t))
      .reduce((sum, t) => sum + t.amount, 0);

    // Cálculos de Liquidez
    const totalInflow = baseIncome + savingWithdrawals;
    const netSpending = Math.max(0, baseSpending - refundRecoveries);

    // Resultado Líquido = Ingresos Reales + Retiradas Ahorro - (Gastos Netos + Aportaciones Ahorro)
    const monthResult = totalInflow - netSpending - savingDeposits;

    const liquidity = pastLiquidBalance + monthResult;
    const totalSavingsAccumulated = savings.reduce((sum, s) => sum + getSavingHistoricalBalance(s.id, currentDate), 0);
    const netWorth = liquidity + totalSavingsAccumulated;

    return { 
      baseIncome, 
      expense: netSpending, 
      savingDeposits, 
      savingWithdrawals,
      monthResult, 
      pastLiquidBalance, 
      liquidity, 
      totalSavingsAccumulated, 
      netWorth, 
      refundRecoveries,
      totalInflow
    };
  }, [transactions, currentDate, accounts, savings, getAccountHistoricalBalance, getSavingHistoricalBalance, viewMode]);

  const evaluatedChallenges = useMemo(() => {
    return challenges.map(ch => {
      const monthTx = transactions.filter(t => t.date.startsWith(currentDate));
      let isCompleted = false;
      if (ch.type === 'spending_limit') {
        const spent = monthTx.filter(t => t.type === 'expense' && t.category === ch.category).reduce((sum, t) => sum + t.amount, 0);
        isCompleted = spent <= ch.target && spent > 0;
      } else if (ch.type === 'savings_goal') {
        isCompleted = metrics.totalSavingsAccumulated >= ch.target;
      } else if (ch.type === 'income_target') {
        isCompleted = metrics.baseIncome >= ch.target;
      }
      return { ...ch, completed: isCompleted || ch.completed };
    });
  }, [challenges, transactions, currentDate, metrics]);

  const chartData = useMemo(() => {
    const monthNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    const limit = chartFilter === '6m' ? 6 : 12;
    const currentYear = parseInt(currentDate.substring(0, 4));
    const currentMonthIndex = viewMode === 'month' ? parseInt(currentDate.substring(5, 7)) - 1 : 11;
    const data = Array.from({ length: limit }).map((_, i) => {
        const date = new Date(currentYear, currentMonthIndex, 1);
        date.setMonth(date.getMonth() - (limit - 1 - i));
        const displayMonthIndex = date.getMonth();
        const displayYear = date.getFullYear();
        const dateStrForCalculation = viewMode === 'year' ? displayYear.toString() : `${displayYear}-${String(displayMonthIndex + 1).padStart(2, '0')}`;
        const patrimonio = getNetWorthHistorical(dateStrForCalculation);
        return { name: monthNames[displayMonthIndex], fullLabel: `${monthNames[displayMonthIndex]} ${displayYear}`, patrimonio };
    });
    return data;
  }, [getNetWorthHistorical, chartFilter, currentDate, viewMode]);

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newLayout = [...dashboardLayout];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newLayout.length) return;
    [newLayout[index], newLayout[targetIndex]] = [newLayout[targetIndex], newLayout[index]];
    updateLayout(newLayout);
  };

  const budgetsWithCalculatedSpent = useMemo(() => {
    return budgets.map(b => {
      const calculatedSpent = transactions.filter(t => t.date.startsWith(currentDate) && t.category === b.category).reduce((sum, t) => {
          if (isTransferTx(t)) return sum; 
          if (b.type === 'expense') {
            if (t.type === 'expense') return sum + t.amount;
            if (t.type === 'income' && t.refundId) return sum - t.amount;
          }
          if (b.type === 'income') {
            if (t.type === 'income' && !t.refundId) return sum + t.amount;
          }
          return sum;
        }, 0);
      const totalRefundedForCategory = transactions.filter(t => t.date.startsWith(currentDate) && t.category === b.category && t.type === 'income' && !!t.refundId).reduce((sum, t) => sum + t.amount, 0);
      return { ...b, spent: calculatedSpent, totalRefunded: totalRefundedForCategory };
    });
  }, [budgets, transactions, currentDate]);

  const renderBlock = (key: string, index: number) => {
    const moveControls = isEditMode && (
      <div className="absolute top-4 right-4 flex gap-1 z-20">
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'up'); }} className="p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-95" disabled={index === 0}><ChevronUp size={16} className="text-slate-600 dark:text-slate-400" /></button>
        <button onClick={(e) => { e.stopPropagation(); moveBlock(index, 'down'); }} className="p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-95" disabled={index === dashboardLayout.length - 1}><ChevronDown size={16} className="text-slate-600 dark:text-slate-400" /></button>
      </div>
    );

    switch (key) {
      case 'balance':
        return (
          <div key={key} className="relative bg-[#2563eb] dark:bg-blue-600 rounded-[2.5rem] p-8 md:p-10 text-white shadow-2xl shadow-blue-200/50 dark:shadow-blue-900/20 overflow-hidden transition-colors duration-300">
            {moveControls}
            <div className="relative z-10 flex flex-col">
              <div className="flex justify-between items-start mb-10">
                <div><p className="text-blue-100 text-[9px] font-black uppercase tracking-[0.2em] mb-2 opacity-80">Patrimonio Neto en {currentDate}</p><h2 className="text-4xl md:text-5xl font-black tracking-tight">{metrics.netWorth.toLocaleString()}€</h2></div>
                <button onClick={() => setShowBreakdown(!showBreakdown)} className={`px-5 py-3 rounded-2xl flex items-center gap-2 text-xs font-black transition-all shadow-lg bg-white/20 backdrop-blur-md hover:bg-white/30 active:scale-95`}>{metrics.monthResult >= 0 ? <TrendingUp size={16} /> : <TrendingDown size={16} />}{metrics.monthResult >= 0 ? '+' : ''}{metrics.monthResult.toLocaleString()}€ este mes<ChevronDown size={14} className={`transition-transform duration-300 ${showBreakdown ? 'rotate-180' : ''}`} /></button>
              </div>
              {showBreakdown && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8 animate-in slide-in-from-top-4 duration-300">
                  <div className="p-5 bg-blue-400/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-blue-100">Líquido Entrante</p>
                    <p className="text-2xl font-black">{metrics.totalInflow.toLocaleString()}€</p>
                    <p className="text-[8px] opacity-70 mt-1 font-bold">Base: {metrics.baseIncome}€ | Retiradas: {metrics.savingWithdrawals}€</p>
                  </div>
                  <div className="p-5 bg-[#4c51bf]/40 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-indigo-100">Gasto Neto Líquido</p>
                    <p className="text-2xl font-black">{metrics.expense.toLocaleString()}€</p>
                    {metrics.refundRecoveries > 0 && (<p className="text-[9px] font-bold text-indigo-200 opacity-80 mt-1">(-{metrics.refundRecoveries.toLocaleString()}€ reembolsos)</p>)}
                  </div>
                  <div className="p-5 bg-amber-500/30 backdrop-blur-md rounded-[1.8rem] border border-white/10 flex flex-col justify-between">
                    <p className="text-[9px] font-black uppercase tracking-wider text-amber-100">Ahorrado (Salida)</p>
                    <p className="text-2xl font-black">{metrics.savingDeposits.toLocaleString()}€</p>
                    <p className="text-[8px] opacity-70 mt-1 font-bold">Restado del resultado líquido</p>
                  </div>
                </div>
              )}
              <div className="h-px bg-white/15 w-full mb-8"></div>
              <div className="grid grid-cols-3 gap-8">
                <div><p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Saldo Anterior</p><p className="text-xl md:text-2xl font-black">{metrics.pastLiquidBalance.toLocaleString()}€</p></div>
                <div><p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Variación Mes</p><p className="text-xl md:text-2xl font-black">{metrics.monthResult.toLocaleString()}€</p></div>
                <div><p className="text-[9px] text-blue-200 font-black uppercase tracking-[0.15em] mb-3 opacity-90">Liquidez Actual</p><p className="text-xl md:text-2xl font-black">{metrics.liquidity.toLocaleString()}€</p></div>
              </div>
            </div>
          </div>
        );
      case 'challenges':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
            {moveControls}
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2"><div className="w-10 h-10 bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 rounded-xl flex items-center justify-center transition-colors"><Target size={20} /></div><h3 className="font-bold text-slate-800 dark:text-slate-100">Retos AI Aura</h3></div>
              <button onClick={() => {}} disabled={isGeneratingChallenges} className="p-2.5 bg-blue-600 text-white rounded-xl transition-all disabled:opacity-50 hover:bg-blue-700 shadow-md shadow-blue-100 dark:shadow-none">{isGeneratingChallenges ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}</button>
            </div>
            <div className="space-y-3">{evaluatedChallenges.map(ch => (<div key={ch.id} className={`p-4 rounded-2xl border flex items-center gap-3 transition-all ${ch.completed ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-100 dark:border-emerald-800/50' : 'bg-slate-50 dark:bg-slate-800/50 border-slate-100 dark:border-slate-800'}`}>{ch.completed ? <CheckCircle2 className="text-emerald-500" size={20}/> : <Circle className="text-slate-300 dark:text-slate-600" size={20}/>}<div className="flex-1"><p className={`text-sm font-bold ${ch.completed ? 'text-emerald-700 dark:text-emerald-300' : 'text-slate-700 dark:text-slate-300'}`}>{ch.title}</p><p className="text-[10px] text-slate-500 dark:text-slate-400 font-medium">Objetivo: {ch.target}€</p></div></div>))}{evaluatedChallenges.length === 0 && (<p className="text-slate-400 dark:text-slate-500 text-xs text-center py-4 italic">Pulsa en el destello para que Aura te proponga retos.</p>)}</div>
          </div>
        );
      case 'savings':
        return (
          <div key={key} className="relative bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm h-full hover:shadow-md transition-all duration-300">
