            </div>
            <div className="space-y-6">
              {displayedBudgets.map(b => {
                const progress = b.limit > 0 ? Math.min((b.spent / b.limit) * 100, 100) : 0;
                const isOverBudget = b.type === 'expense' && b.spent > b.limit;
                return (
                  <div key={b.id} onClick={() => setSelectedBudgetForDetails(b)} className="cursor-pointer group space-y-1.5">
                    <div className="flex justify-between text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider"><span>{b.category}</span><span style={{ color: isOverBudget ? '#f43f5e' : b.color }}>{b.spent.toLocaleString('es-ES')}€ / {b.limit.toLocaleString('es-ES')}€ ({Math.round(progress)}%)</span></div>
                    <div className="w-full h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden"><div className={`h-full transition-all duration-700`} style={{ width: `${progress}%`, backgroundColor: isOverBudget ? '#f43f5e' : b.color || '#3b82f6' }}></div></div>
                  </div>
                );
              })}{budgets.length === 0 && <p className="text-xs text-slate-400 dark:text-slate-500 italic text-center py-4">Sin límites definidos.</p>}
            </div>
          </div>
        );
      default: return null;
    }
  };

  const budgetTransactions = useMemo(() => {
    if (!selectedBudgetForDetails) return [];
    return transactions.filter(t => t.category === selectedBudgetForDetails.category && t.date.startsWith(currentDate)).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedBudgetForDetails, transactions, currentDate]);

  return (
    <div className="space-y-6 pb-20 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
        <div><h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Dashboard</h2><p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight transition-colors">Análisis de {currentDate}. Ahorro y liquidez sincronizados.</p></div>
        <button onClick={() => setIsEditMode(!isEditMode)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-sm transition-all shadow-sm ${isEditMode ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 dark:shadow-blue-900/40' : 'bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700'}`}><Settings2 size={18}/> {isEditMode ? 'Guardar Cambios' : 'Personalizar Diseño'}</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 auto-rows-min">{dashboardLayout.map((key, idx) => { const isFullWidth = key === 'balance' || key === 'chart'; return (<div key={key} className={`${isFullWidth ? 'lg:col-span-2' : 'lg:col-span-1'} transition-all duration-300`}>{renderBlock(key, idx)}</div>); })}</div>
      {selectedBudgetForDetails && (
        <div className="fixed inset-0 bg-slate-900/90 z-[60] flex items-center justify-center p-4" onClick={() => setSelectedBudgetForDetails(null)}>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-8 md:p-10 shadow-2xl animate-in fade-in zoom-in duration-300 border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-start mb-8 flex-shrink-0"><div className="flex items-center gap-5"><div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-lg dark:shadow-none transition-colors`} style={{ backgroundColor: `${selectedBudgetForDetails.color}${theme === 'dark' ? '30' : '15'}`, color: selectedBudgetForDetails.color }}>{ICON_MAP[selectedBudgetForDetails.icon] ? (React.cloneElement(ICON_MAP[selectedBudgetForDetails.icon] as React.ReactElement, { size: 28 })) : (<span className="text-3xl">{selectedBudgetForDetails.icon || <ShoppingBag size={28} />}</span>)}</div><div><h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{selectedBudgetForDetails.category}</h3><p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Movimientos de {currentDate}</p></div></div><button onClick={() => setSelectedBudgetForDetails(null)} className="p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={24} /></button></div>
            <div className="bg-slate-50 dark:bg-slate-800/50 rounded-3xl p-6 mb-8 border border-slate-100 dark:border-slate-800 flex-shrink-0 transition-colors"><div className="flex justify-between items-end mb-4"><div><p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-1">Total acumulado</p><p className="text-3xl font-black text-slate-900 dark:text-white transition-colors">{selectedBudgetForDetails.spent.toLocaleString()}€</p></div><div className="text-right"><p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-1">Límite</p><p className="text-lg font-bold text-slate-600 dark:text-slate-400 transition-colors">{selectedBudgetForDetails.limit.toLocaleString()}€</p></div></div><div className="w-full h-3 bg-white dark:bg-slate-800 rounded-full overflow-hidden border border-slate-200 dark:border-slate-700"><div className={`h-full rounded-full transition-all duration-1000`} style={{ width: `${Math.min((selectedBudgetForDetails.spent / selectedBudgetForDetails.limit) * 100, 100)}%`, backgroundColor: (selectedBudgetForDetails.type === 'expense' && selectedBudgetForDetails.spent > selectedBudgetForDetails.limit) ? '#f43f5e' : selectedBudgetForDetails.color }}></div></div></div>
            <div className="flex items-center gap-2 mb-4 flex-shrink-0"><History size={16} className="text-slate-400 dark:text-slate-600" /><h4 className="text-xs font-black text-slate-500 dark:text-slate-500 uppercase tracking-widest">Historial Reciente</h4></div>
            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 pr-2">{budgetTransactions.length > 0 ? budgetTransactions.map(tx => (<div key={tx.id} className="flex justify-between items-center p-4 bg-white dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 rounded-2xl hover:border-blue-200 dark:hover:border-blue-800 transition-colors duration-300"><div className="flex items-center gap-4"><div className="text-center bg-slate-50 dark:bg-slate-900 w-10 py-1.5 rounded-xl border border-slate-100 dark:border-slate-700 transition-colors"><p className="text-[8px] font-black text-slate-400 dark:text-slate-600 uppercase">{new Date(tx.date).toLocaleDateString('es-ES', { month: 'short' })}</p><p className="text-xs font-black text-slate-700 dark:text-slate-300 transition-colors">{new Date(tx.date).getDate()}</p></div><div><p className="text-sm font-bold text-slate-800 dark:text-slate-200 line-clamp-1 transition-colors">{tx.description}</p><p className="text-[10px] font-medium text-slate-400 dark:text-slate-500">{accounts.find(a => a.id === tx.accountId)?.name || 'Cuenta'}</p></div></div><div className="text-right"><p className={`font-black ${tx.type === 'income' ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-900 dark:text-white'} transition-colors`}>{tx.type === 'income' ? '+' : '-'}{tx.amount.toLocaleString()}€</p></div></div>)) : (<div className="text-center py-12 bg-slate-50 dark:bg-slate-800/30 rounded-[2rem] border-2 border-dashed border-slate-200 dark:border-slate-700 transition-colors"><AlertCircle size={32} className="mx-auto text-slate-300 dark:text-slate-700 mb-3" /><p className="text-xs font-bold text-slate-400 dark:text-slate-600 uppercase tracking-widest">No hay transacciones aún</p></div>)}</div>
            <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex-shrink-0"><button onClick={() => setSelectedBudgetForDetails(null)} className="w-full py-4 bg-slate-900 dark:bg-blue-600 text-white font-black rounded-2xl hover:bg-slate-800 dark:hover:bg-blue-700 transition-all active:scale-[0.98]">ENTENDIDO</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useFinance } from '../App';
import { 
  Plus, 
  Search, 
  ArrowUpRight, 
  ArrowDownRight, 
  Trash2, 
  Edit2, 
  X, 
  UserCheck, 
  AlertCircle, 
  Check, 
  PiggyBank, 
  ChevronDown, 
  Split,
  Camera,
  Loader2,
  Sparkles,
  ArrowRightLeft,
  ArrowRight,
  Ban,
  ArrowDownCircle,
  ArrowUpCircle
} from 'lucide-react';
import { Transaction } from '../types';
import { analyzeReceipt, ScannedTransaction } from '../services/geminiService';

const Transactions: React.FC = () => {
  const { transactions, accounts, savings, refunds, budgets, addTransaction, updateTransaction, deleteTransaction, theme, currentDate, viewMode } = useFinance();
  const [filter, setFilter] = useState<'all' | 'income' | 'expense' | 'savings' | 'refunds'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const [viewingTx, setViewingTx] = useState<Transaction | null>(null);
  const [confirmDeleteInModal, setConfirmDeleteInModal] = useState(false);

  // Aura Vision States
  const [isScanning, setIsScanning] = useState(false);
  const [scannedQueue, setScannedQueue] = useState<ScannedTransaction[]>([]);
  const [totalScannedCount, setTotalScannedCount] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const location = useLocation();

  // Form states
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState<number | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<'income' | 'expense' | 'saving'>('expense');
  const [category, setCategory] = useState('');
  const [accountId, setAccountId] = useState(accounts[0]?.id || '');
  const [isRefundLink, setIsRefundLink] = useState(false);
  const [selectedRefundId, setSelectedRefundId] = useState('');
  const [selectedSavingId, setSelectedSavingId] = useState('');
  const [myPartManual, setMyPartManual] = useState<number | ''>('');

  // Extra states for Transfer
  const [isTransfer, setIsTransfer] = useState(false);
  const [transferTargetId, setTransferTargetId] = useState('');

  // Dirección del flujo de ahorro (Aportación vs Retirada)
  const [savingDirection, setSavingDirection] = useState<'deposit' | 'withdraw'>('deposit');

  // Lógica de Categorías Disponibles Refinada
  const availableCategories = useMemo(() => {
    if (type === 'saving') return ["Ahorro"];

    if (type === 'income' && isRefundLink && selectedRefundId) {
      const selectedRefund = refunds.find(r => r.id === selectedRefundId);
      if (selectedRefund) return [selectedRefund.category];
    }

    if (type === 'income' && isRefundLink) {
      const expenseCats = budgets.filter(b => b.type === 'expense').map(b => b.category);
      return expenseCats.length > 0 ? Array.from(new Set(expenseCats)) : ["Sin Presupuesto de Gasto"];
    }

    const budgetList = budgets
      .filter(b => b.type === (type as any === 'saving' ? 'expense' : type as any))
      .map(b => b.category);
    const uniqueCategories = Array.from(new Set(budgetList));
    return uniqueCategories.length > 0 ? uniqueCategories : ["Sin Presupuesto"];
  }, [type, isRefundLink, selectedRefundId, budgets, refunds]);

  useEffect(() => {
    if (type === 'income' && isRefundLink && selectedRefundId) {
      const refundObj = refunds.find(r => r.id === selectedRefundId);
      if (refundObj) {
        setCategory(refundObj.category);
      }
    } else if (!availableCategories.includes(category)) {
      setCategory(availableCategories[0] || '');
    }
  }, [availableCategories, type, isRefundLink, selectedRefundId, refunds]);

  useEffect(() => {
    if (location.state?.openModal) {
      setIsAdding(true);
      setEditingTx(null);
    }
  }, [location.state]);

  const resetForm = () => {
    setDesc('');
    setAmount('');
    setDate(new Date().toISOString().split('T')[0]);
    setType('expense');
    setCategory('');
    setAccountId(accounts[0]?.id || '');
    setIsRefundLink(false);
    setSelectedRefundId('');
    setSelectedSavingId('');
    setMyPartManual('');
    setIsTransfer(false);
    setTransferTargetId('');
    setEditingTx(null);
    setSavingDirection('deposit');
  };

  const startEdit = (tx: Transaction) => {
    setEditingTx(tx);
    setDesc(tx.description);
    setAmount(tx.amount);
    setDate(tx.date);
    const isSavingType = tx.category === 'Ahorro' || !!tx.savingId;
    setType(isSavingType ? 'saving' : tx.type);
    setCategory(tx.category);
    setAccountId(tx.accountId);
    setIsRefundLink(tx.isRefund || !!tx.refundId);
    setSelectedRefundId(tx.refundId || '');
    setSelectedSavingId(tx.savingId || '');

    // Si era ahorro, detectar la dirección original
    if (isSavingType) {
        setSavingDirection(tx.type === 'expense' ? 'deposit' : 'withdraw');
    }

    setIsAdding(true);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleDeleteFromModal = (id: string) => {
    deleteTransaction(id);
    setViewingTx(null);
    setConfirmDeleteInModal(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onload = async () => {
      const base64 = (reader.result as string).split(',')[1];
      try {
        const items = await analyzeReceipt(base64);
        const reversedItems = [...items].reverse();
        setScannedQueue(reversedItems);
        setTotalScannedCount(reversedItems.length);
        if (reversedItems.length > 0) {
          loadScannedItem(reversedItems[0]);
          setIsAdding(true);
        }
      } catch (err) {
        console.error(err);
      } finally {
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const loadScannedItem = (item: ScannedTransaction) => {
    setDesc(item.description);
    setAmount(item.amount);
    setDate(item.date);

    if (item.isSaving) {
        setType('saving');
        setSavingDirection(item.type === 'expense' ? 'deposit' : 'withdraw');
    } else {
        setType(item.type);
    }

    setIsTransfer(item.isTransfer);
    setIsRefundLink(item.isRefund);
    setCategory(item.category);

    if (item.suggestedAccount) {
      const matched = accounts.find(a => a.name.toLowerCase().includes(item.suggestedAccount!.toLowerCase()));
      if (matched) setAccountId(matched.id);
    }
  };

  const handleDiscardCurrentScanned = () => {
    const nextQueue = scannedQueue.slice(1);
    setScannedQueue(nextQueue);
    if (nextQueue.length > 0) {
      loadScannedItem(nextQueue[0]);
    } else {
      setIsAdding(false);
      resetForm();
    }
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount === '') return;

    if (isTransfer) {
      addTransaction({
        date,
        amount: Number(amount),
        description: `Transferencia a ${accounts.find(a => a.id === transferTargetId)?.name || 'Cuenta'}`,
        category: 'Traspaso',
        type: 'expense',
        accountId,
        isRefund: false
      });
      addTransaction({
        date,
        amount: Number(amount),
        description: `Transferencia desde ${accounts.find(a => a.id === accountId)?.name || 'Cuenta'}`,
        category: 'Traspaso',
        type: 'income',
        accountId: transferTargetId,
        isRefund: false
      });
    } else {
      // Si es Depósito -> Sale del banco (expense) -> Resta de liquidez en Dashboard
      // Si es Retirada -> Entra al banco (income) -> Suma a ingresos en Dashboard
      const finalType = type === 'saving' 
        ? (savingDirection === 'deposit' ? 'expense' : 'income') 
        : type;

      const finalCategory = type === 'saving' ? 'Ahorro' : category;

      if (editingTx) {
        updateTransaction({
          ...editingTx,
          date,
          amount: Number(amount),
          description: desc,
          category: finalCategory,
          type: finalType as any,
          accountId,
          refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined,
          savingId: type === 'saving' ? selectedSavingId : undefined
        });
      } else {
        addTransaction({
          date,
          amount: Number(amount),
          description: desc,
          category: finalCategory,
          type: finalType as any,
          accountId,
          isRefund: isRefundLink,
          refundId: (finalType === 'income' && isRefundLink) ? selectedRefundId : undefined,
          savingId: type === 'saving' ? selectedSavingId : undefined
        }, finalType === 'expense' && isRefundLink ? (myPartManual === '' ? Number(amount) / 2 : Number(myPartManual)) : undefined);
      }
    }

    const nextQueue = scannedQueue.slice(1);
    setScannedQueue(nextQueue);
    if (nextQueue.length > 0) {
      loadScannedItem(nextQueue[0]);
    } else {
      setIsAdding(false);
      resetForm();
    }
  };

  const filteredTx = useMemo(() => {
    return transactions
      .filter(t => {
        const matchesPeriod = t.date.startsWith(currentDate);
        if (!matchesPeriod) return false;

        let matchesType = true;
        const isSaving = t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;
        const isRefund = t.type === 'income' && !!t.refundId;

        if (filter === 'income') matchesType = t.type === 'income' && !t.refundId && !isSaving;
        else if (filter === 'expense') matchesType = t.type === 'expense' && !isSaving;
        else if (filter === 'savings') matchesType = isSaving;
        else if (filter === 'refunds') matchesType = isRefund;

        const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                              t.category.toLowerCase().includes(searchTerm.toLowerCase());

        return matchesType && matchesSearch;
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, filter, searchTerm, currentDate]);

  const getTxStyle = (t: Transaction) => {
    const isSaving = t.category === 'Ahorro' || t.category === 'Ahorros' || !!t.savingId;
    const isRefund = t.type === 'income' && !!t.refundId;
    const isWithdrawal = isSaving && t.type === 'income';

    if (isSaving) {
        return { 
            color: isWithdrawal ? 'text-amber-600 dark:text-amber-400' : 'text-amber-500', 
            bg: 'bg-amber-50 dark:bg-amber-900/40', 
            icon: isWithdrawal ? <ArrowDownCircle size={18} /> : <ArrowUpRight size={18} /> 
        };
    }
    if (isRefund) return { color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-900/40', icon: <ArrowUpRight size={18} /> }; 
    if (t.type === 'income') return { color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-900/40', icon: <ArrowUpRight size={18} /> }; 
    return { color: 'text-rose-600 dark:text-rose-400', bg: 'bg-rose-50 dark:bg-rose-900/40', icon: <ArrowDownRight size={18} /> }; 
  };

  const isCategoryDisabled = type === 'income' && isRefundLink && !!selectedRefundId;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 max-w-6xl mx-auto px-4 transition-colors">

      {isScanning && (
        <div className="fixed inset-0 bg-slate-900/90 z-[100] flex flex-col items-center justify-center p-6 text-center">
          <div className="relative mb-8">
            <div className="w-32 h-32 border-4 border-blue-500/20 rounded-full border-t-blue-500 animate-spin"></div>
            <Sparkles className="absolute inset-0 m-auto text-blue-500 animate-pulse" size={48} />
          </div>
          <h3 className="text-2xl font-black text-white mb-2">Aura Vision Procesando</h3>
          <p className="text-slate-400 max-w-xs">Analizando movimientos y ajustando balances...</p>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Transacciones</h2>
          <p className="text-slate-700 dark:text-slate-400 font-bold text-sm tracking-tight transition-colors">Historial de {viewMode === 'year' ? `todo el año ${currentDate}` : currentDate}. Gestiona céntimos con decimales.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isScanning}
            className="flex items-center gap-2 px-6 py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 font-black rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-700 transition-all shadow-sm active:scale-95 disabled:opacity-50"
          >
            <Camera size={20} className="text-blue-500" />
            <span>Aura Vision</span>
          </button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />

          <button onClick={() => { setEditingTx(null); setIsAdding(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95">
            <Plus size={20} /> 
            <span>Nueva</span>
          </button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-xl shadow-slate-200/50 dark:shadow-none overflow-hidden transition-all duration-300">
        <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 flex flex-col gap-4 bg-slate-50/30 dark:bg-slate-800/20">
          <div className="flex items-center gap-1 bg-white dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm w-full overflow-x-auto no-scrollbar">
            <button onClick={() => setFilter('all')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'all' ? 'bg-slate-900 dark:bg-slate-700 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>TODOS</button>
            <button onClick={() => setFilter('income')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'income' ? 'bg-emerald-500 dark:bg-emerald-600 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>INGRESOS</button>
            <button onClick={() => setFilter('expense')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'expense' ? 'bg-rose-500 dark:bg-rose-600 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>GASTOS</button>
            <button onClick={() => setFilter('savings')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'savings' ? 'bg-amber-500 dark:bg-amber-600 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>AHORROS</button>
            <button onClick={() => setFilter('refunds')} className={`whitespace-nowrap flex-1 px-4 py-3 text-[10px] font-black rounded-xl transition-all ${filter === 'refunds' ? 'bg-blue-500 dark:bg-blue-600 text-white shadow-lg' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'}`}>REEMBOLSOS</button>
          </div>

          <div className="flex items-center gap-3 bg-white dark:bg-slate-800 px-5 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 w-full shadow-sm focus-within:ring-2 focus-within:ring-blue-500 transition-all">
            <Search size={18} className="text-slate-500 dark:text-slate-400" />
            <input 
              type="text" 
              placeholder="Buscar transacción..." 
              className="bg-transparent border-none focus:ring-0 text-sm w-full font-bold text-slate-800 dark:text-slate-100 placeholder:text-slate-300 dark:placeholder:text-slate-600" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse table-fixed">
            <thead>
              <tr className="bg-slate-50/50 dark:bg-slate-800/30 text-[10px] uppercase tracking-[0.15em] text-slate-400 dark:text-slate-500 font-black border-b border-slate-100 dark:border-slate-800">
                <th className="px-6 py-5 text-left w-[25%] md:w-[20%] transition-colors">Fecha</th>
                <th className="px-6 py-5 text-left w-[45%] md:w-[50%] transition-colors">Detalle</th>
                <th className="px-6 py-5 text-right w-[30%] transition-colors">Importe</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
              {filteredTx.map(tx => {
                const style = getTxStyle(tx);
                return (
                  <tr 
                    key={tx.id} 
                    onClick={() => { setViewingTx(tx); setConfirmDeleteInModal(false); }}
                    className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-all group cursor-pointer active:bg-slate-100 dark:active:bg-slate-800"
                  >
                    <td className="px-6 py-6 text-[11px] font-black text-slate-500 dark:text-slate-500 uppercase">
                      {new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex items-center gap-4 overflow-hidden">
                        <div className={`flex w-9 h-9 rounded-xl items-center justify-center flex-shrink-0 shadow-sm ${style.bg} ${style.color}`}>
                          {style.icon}
                        </div>
                        <div className="min-w-0 flex flex-col">
                          <span className="font-black text-slate-800 dark:text-slate-100 text-[13px] truncate leading-tight transition-colors">
                            {tx.description}
                          </span>
                          <span className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-wider mt-0.5 truncate transition-colors">{tx.category}</span>
                        </div>
                      </div>
                    </td>
                    <td className={`px-6 py-6 text-right font-black text-lg ${style.color} transition-colors`}>
                      {tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTx.length === 0 && (
            <div className="py-24 text-center flex flex-col items-center gap-4">
               <div className="w-16 h-16 bg-slate-50 dark:bg-slate-800 text-slate-300 dark:text-slate-700 rounded-full flex items-center justify-center"><AlertCircle size={32} /></div>
               <p className="text-slate-400 dark:text-slate-600 font-bold italic uppercase tracking-widest text-[11px] transition-colors">No se encontraron movimientos en este periodo</p>
            </div>
          )}
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
             <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-200 dark:border-slate-800 overflow-y-auto max-h-[90vh] custom-scrollbar">
                <div className="flex justify-between items-center mb-10">
                  <div className="flex flex-col">
                    <h3 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight transition-colors">
                      {editingTx ? 'Editar Movimiento' : scannedQueue.length > 0 ? 'Aura Vision: Confirmación' : 'Nuevo Movimiento'}
                    </h3>
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); setScannedQueue([]); }} className="p-4 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={28} /></button>
                </div>

                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 dark:bg-slate-800 p-2 rounded-[1.8rem] border border-slate-200 dark:border-slate-700 shadow-inner">
                    <button type="button" onClick={() => {setType('expense'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' && !isTransfer ? 'bg-white dark:bg-slate-700 shadow-md text-rose-600 dark:text-rose-400' : 'text-slate-500 dark:text-slate-500'}`}>GASTO</button>
                    <button type="button" onClick={() => {setType('income'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' && !isTransfer ? 'bg-white dark:bg-slate-700 shadow-md text-emerald-600 dark:text-emerald-400' : 'text-slate-500 dark:text-slate-500'}`}>INGRESO</button>
                    <button type="button" onClick={() => {setType('saving'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'saving' ? 'bg-white dark:bg-slate-700 shadow-md text-amber-500 dark:text-amber-400' : 'text-slate-500 dark:text-slate-500'}`}>AHORRO</button>
                  </div>

                  {type === 'saving' && (
                    <div className="bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl border-2 border-amber-100 dark:border-amber-800 flex flex-col gap-3 animate-in slide-in-from-top-2">
                        <label className="block text-[11px] font-black text-amber-700 dark:text-amber-400 uppercase tracking-widest pl-1">Tipo de movimiento de ahorro</label>
                        <div className="grid grid-cols-2 gap-2">
                            <button 
                                type="button" 
                                onClick={() => setSavingDirection('deposit')}
                                className={`flex items-center justify-center gap-2 py-3 rounded-xl text-[10px] font-black transition-all ${savingDirection === 'deposit' ? 'bg-amber-500 text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-amber-500 border border-amber-200'}`}
                            >
                                <ArrowUpCircle size={14} /> APORTACIÓN
                            </button>
                            <button 
                                type="button" 
                                onClick={() => setSavingDirection('withdraw')}
                                className={`flex items-center justify-center gap-2 py-3 rounded-xl text-[10px] font-black transition-all ${savingDirection === 'withdraw' ? 'bg-amber-600 text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-amber-600 border border-amber-200'}`}
                            >
                                <ArrowDownCircle size={14} /> RETIRADA
                            </button>
                        </div>
                    </div>
                  )}

                  <div className="space-y-6">
                    <div>
                      <label className="block text-[11px] font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest mb-3">Descripción</label>
                      <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none focus:border-blue-400 dark:focus:border-blue-600 transition-all placeholder:text-slate-300 dark:placeholder:text-slate-600 text-slate-900 dark:text-white" placeholder="Ej: Supermercado..." required />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest mb-3">Importe (€)</label>
                        <input 
                          type="number" 
                          step="0.01" 
                          inputMode="decimal"
                          value={amount} 
                          onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} 
                          className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-black text-xl outline-none text-slate-900 dark:text-white" 
                          required 
                        />
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest mb-3">Fecha</label>
                        <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required />
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest mb-3">
                          {isTransfer ? 'Cuenta Origen' : savingDirection === 'withdraw' ? 'Cuenta Destino' : 'Desde Cuenta'}
                        </label>
                        <div className="relative">
                          <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none appearance-none text-slate-900 dark:text-white">
                            {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                          </select>
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                      <div>
                        <label className="block text-[11px] font-black text-slate-700 dark:text-slate-400 uppercase tracking-widest mb-3">
                          {isTransfer ? 'Cuenta Destino' : type === 'saving' ? 'Hucha' : 'Categoría'}
                        </label>
                        <div className="relative">
                          {isTransfer ? (
                            <select value={transferTargetId} onChange={e => setTransferTargetId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none appearance-none text-slate-900 dark:text-white" required>
                              <option value="">Selecciona destino</option>
                              {accounts.filter(a => a.id !== accountId).map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                            </select>
                          ) : type === 'saving' ? (
                            <select value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none appearance-none text-slate-900 dark:text-white" required>
                              <option value="">Selecciona hucha</option>
                              {savings.map(s => <option key={s.id} value={s.id}>{s.emoji} {s.name}</option>)}
                            </select>
                          ) : (
                            <select 
                              value={category} 
                              onChange={e => setCategory(e.target.value)} 
                              disabled={isCategoryDisabled}
                              className={`w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none appearance-none text-slate-900 dark:text-white ${isCategoryDisabled ? 'opacity-60 cursor-not-allowed bg-slate-100 dark:bg-slate-900' : ''}`} 
                              required
                            >
                              {availableCategories.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                          )}
                          <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="flex flex-col gap-3 pt-6">
                    <button 
                      type="submit" 
                      className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl shadow-blue-100 dark:shadow-none transition-all active:scale-95"
                    >
                      {editingTx ? 'GUARDAR' : 'CONFIRMAR Y FINALIZAR'}
                    </button>
                    <button 
                        type="button" 
                        onClick={() => { setIsAdding(false); resetForm(); setScannedQueue([]); }} 
                        className="w-full py-5 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-400 font-black rounded-2xl transition-colors"
                      >
                        CANCELAR
                    </button>
                  </div>
                </form>
             </div>
         </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, Trash2, Edit2, ArrowRightLeft, CreditCard, Banknote, Landmark, X, Check } from 'lucide-react';
import { Account } from '../types';

const Accounts: React.FC = () => {
  const { accounts, currentDate, getAccountHistoricalBalance, addAccount, updateAccount, deleteAccount, addTransaction, theme } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [editingAccount, setEditingAccount] = useState<Account | null>(null);
  const [isTransferring, setIsTransferring] = useState(false);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // New/Edit account form state
  const [name, setName] = useState('');
  const [type, setType] = useState<Account['type']>('Bank');
  const [balanceInput, setBalanceInput] = useState<number | ''>('');
  const [color, setColor] = useState('#3b82f6');
  const [emoji, setEmoji] = useState('🏦');

  // Transfer form
  const [fromId, setFromId] = useState('');
  const [toId, setToId] = useState('');
  const [transferAmount, setTransferAmount] = useState<number | ''>('');

  const resetForm = () => {
    setName('');
    setType('Bank');
    setBalanceInput('');
    setColor('#3b82f6');
    setEmoji('🏦');
  };

  const handleOpenAdd = () => {
    resetForm();
    setIsAdding(true);
  };

  const handleOpenEdit = (acc: Account) => {
    setName(acc.name);
    setType(acc.type);
    setBalanceInput(acc.initialBalance);
    setColor(acc.color);
    setEmoji(acc.emoji || '🏦');
    setEditingAccount(acc);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalBalance = balanceInput === '' ? 0 : balanceInput;
    if (editingAccount) {
      updateAccount({ 
        ...editingAccount, 
        name, 
        type, 
        initialBalance: finalBalance, 
        color, 
        emoji 
      });
      setEditingAccount(null);
    } else {
      addAccount({ 
        name, 
        type, 
        initialBalance: finalBalance, 
        color, 
        emoji 
      });
      setIsAdding(false);
    }
    resetForm();
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    const amountValue = transferAmount === '' ? 0 : transferAmount;
    if (!fromId || !toId) return alert("Selecciona ambas cuentas");
    if (fromId === toId) return alert("Las cuentas deben ser diferentes");
    if (amountValue <= 0) return alert("Introduce una cantidad válida");

    const date = new Date().toISOString().split('T')[0];
    addTransaction({
      date,
      amount: amountValue,
      description: `Transferencia a ${accounts.find(a => a.id === toId)?.name}`,
      category: 'Traspaso',
      type: 'expense',
      accountId: fromId,
      isRefund: false
    });
    addTransaction({
      date,
      amount: amountValue,
      description: `Transferencia desde ${accounts.find(a => a.id === fromId)?.name}`,
      category: 'Traspaso',
      type: 'income',
      accountId: toId,
      isRefund: false
    });

    setIsTransferring(false);
    setTransferAmount('');
    setFromId('');
    setToId('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Cuentas y Efectivo</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight transition-colors">Gestiona tu liquidez. Soporte completo de decimales.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsTransferring(true)}
            className="flex items-center gap-2 px-6 py-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 font-bold rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-700 transition-all shadow-sm active:scale-95"
          >
            <ArrowRightLeft size={18} />
            Transferir
          </button>
          <button 
            onClick={handleOpenAdd}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
          >
            <Plus size={18} />
            Nueva Cuenta
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {accounts.map(acc => {
          const displayBalance = getAccountHistoricalBalance(acc.id, currentDate);
          const isConfirming = confirmDeleteId === acc.id;
          return (
            <div key={acc.id} className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden hover:shadow-md transition-all duration-300">
              <div className="flex justify-between items-start mb-6">
                <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner dark:shadow-none" style={{ backgroundColor: `${acc.color}${theme === 'dark' ? '30' : '20'}` }}>
                  {acc.emoji || (acc.type === 'Bank' ? '🏦' : acc.type === 'Cash' ? '💵' : '💳')}
                </div>
                <div className={`flex gap-1 transition-opacity ${isConfirming ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                  {!isConfirming ? (
                    <>
                      <button onClick={() => handleOpenEdit(acc)} className="p-2.5 hover:bg-blue-50 dark:hover:bg-blue-900/40 rounded-xl text-blue-500 transition-colors"><Edit2 size={18} /></button>
                      <button onClick={() => setConfirmDeleteId(acc.id)} className="p-2.5 hover:bg-rose-50 dark:hover:bg-rose-900/40 rounded-xl text-rose-400 transition-colors"><Trash2 size={18} /></button>
                    </>
                  ) : (
                    <div className="flex gap-1 items-center animate-in slide-in-from-right-2">
                       <button onClick={() => { deleteAccount(acc.id); setConfirmDeleteId(null); }} className="flex items-center gap-1 px-3 py-1.5 bg-rose-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-700 transition-all"><Check size={14} /> Confirmar</button>
                       <button onClick={() => setConfirmDeleteId(null)} className="p-1.5 bg-slate-100 dark:bg-slate-800 rounded-lg text-slate-400 hover:text-slate-600 transition-all"><X size={16} /></button>
                    </div>
                  )}
                </div>
              </div>
              <h4 className="text-xl font-bold text-slate-800 dark:text-slate-100 transition-colors">{acc.name}</h4>
              <p className="text-xs text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest mb-4 transition-colors">{acc.type}</p>
              <div className="flex items-baseline gap-2">
                <span className="text-3xl font-black text-slate-900 dark:text-white transition-colors">{displayBalance.toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</span>
              </div>
            </div>
          );
        })}
      </div>

      {(isAdding || editingAccount) && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300 overflow-y-auto max-h-[90vh] border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800 dark:text-slate-100 transition-colors">{editingAccount ? 'Editar Cuenta' : 'Nueva Cuenta'}</h3>
              <button onClick={() => { setIsAdding(false); setEditingAccount(null); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Nombre de la cuenta</label>
                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-medium text-slate-900 dark:text-slate-100 outline-none transition-all" placeholder="Ej: Nómina..." required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Saldo Inicial</label>
                  <input type="number" step="0.01" inputMode="decimal" value={balanceInput} onChange={e => setBalanceInput(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold text-slate-900 dark:text-slate-100 outline-none" required />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Tipo</label>
                  <select value={type} onChange={e => setType(e.target.value as any)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-medium outline-none text-slate-900 dark:text-slate-100"><option value="Bank">Banco</option><option value="Cash">Efectivo</option><option value="Card">Tarjeta</option></select>
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => { setIsAdding(false); setEditingAccount(null); }} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-100 dark:shadow-none">{editingAccount ? 'Guardar' : 'Crear'}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {isTransferring && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300 border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-800 dark:text-slate-100 transition-colors">Transferencia</h3>
              <button onClick={() => setIsTransferring(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <form onSubmit={handleTransfer} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Cantidad</label>
                <input type="number" step="0.01" inputMode="decimal" value={transferAmount} onChange={e => setTransferAmount(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 text-center text-3xl font-black outline-none text-slate-900 dark:text-white" placeholder="0.00" required />
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsTransferring(false)} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl shadow-xl shadow-blue-100 dark:shadow-none transition-all">Confirmar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

