      )}

      {adjustingSaving && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-sm p-10 shadow-2xl animate-in fade-in zoom-in duration-300 border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-slate-800 dark:text-slate-100 transition-colors">Ajustar Saldo</h3>
              <button onClick={() => { setAdjustingSaving(null); setAdjValue(''); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <div className="space-y-6">
              <input type="number" step="0.01" inputMode="decimal" value={adjValue} onChange={e => setAdjValue(e.target.value === '' ? '' : Number(e.target.value))} autoFocus className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-6 text-center text-4xl font-black outline-none focus:ring-2 focus:ring-blue-500 transition-all text-slate-900 dark:text-white" placeholder="0.00" />
              <div className="flex gap-3">
                <button onClick={() => { setAdjustingSaving(null); setAdjValue(''); }} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl transition-colors">Cancelar</button>
                <button onClick={applyAdjustment} disabled={adjValue === ''} className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 dark:shadow-none transition-all active:scale-95 disabled:opacity-50">Confirmar</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

