import React, { useState, useMemo } from 'react';
import { useFinance } from '../App';
import { 
  Plus, 
  Edit2, 
  Trash2, 
  ShoppingBag, 
  ChevronRight, 
  X, 
  ArrowUpRight, 
  ArrowDownRight, 
  ArrowLeftRight,
  TrendingDown,
  TrendingUp,
  AlertCircle,
  Calendar,
  Wallet,
  Tag,
  ArrowDownLeft,
  ChevronDown,
  History,
  ArrowRight,
  Palette,
  Check
} from 'lucide-react';
import { Budget, Transaction } from '../types';
import { CATEGORIES, INCOME_CATEGORIES, ICON_MAP, BUDGET_PRESET_COLORS } from '../constants';

const BudgetManager: React.FC = () => {
  const { budgets, transactions, currentDate, updateBudget, addBudget, deleteBudget, accounts, theme } = useFinance();

  // UI States
  const [activeTab, setActiveTab] = useState<'expense' | 'income'>('expense');
  const [selectedBudget, setSelectedBudget] = useState<Budget | null>(null);
  const [isEditing, setIsEditing] = useState<Budget | null>(null);
  const [isCreating, setIsCreating] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Form States
  const [category, setCategory] = useState('');
  const [limit, setLimit] = useState<number | ''>('');
  const [customCategory, setCustomCategory] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [selectedIcon, setSelectedIcon] = useState('ShoppingBag');
  const [selectedColor, setSelectedColor] = useState('#3b82f6');

  // Cálculo dinámico de presupuestos con su gasto real
  const budgetsWithCalculatedSpent = useMemo(() => {
    return budgets.map(b => {
      const calculatedSpent = transactions
        .filter(t => t.date.startsWith(currentDate) && t.category === b.category)
        .reduce((sum, t) => {
          // Para presupuestos de gasto:
          if (b.type === 'expense') {
            if (t.type === 'expense') {
              return sum + t.amount; // Gastos regulares aumentan el 'spent'
            }
            if (t.type === 'income' && t.refundId) {
              return sum - t.amount; // Ingresos por reembolso disminuyen el 'spent'
            }
          }
          // Para presupuestos de ingreso:
          if (b.type === 'income') {
            // Solo cuenta ingresos que NO son reembolsos
            if (t.type === 'income' && !t.refundId) {
              return sum + t.amount; // Ingresos regulares (ej: nómina) aumentan el 'spent'
            }
          }
          return sum; // No cuenta otros tipos de transacciones
        }, 0);

      const totalRefunded = transactions
        .filter(t => t.date.startsWith(currentDate) && t.category === b.category && t.type === 'income' && !!t.refundId)
        .reduce((sum, t) => sum + t.amount, 0);

      return { ...b, spent: calculatedSpent, totalRefunded };
    });
  }, [budgets, transactions, currentDate]);

  const filteredBudgets = useMemo(() => {
    return budgetsWithCalculatedSpent.filter(b => b.type === activeTab);
  }, [budgetsWithCalculatedSpent, activeTab]);

  const budgetTransactions = useMemo(() => {
    if (!selectedBudget) return [];
    return transactions.filter(t => 
      t.category === selectedBudget.category && 
      t.date.startsWith(currentDate)
    ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedBudget, transactions, currentDate]);

  const totals = useMemo(() => {
    const b = budgetsWithCalculatedSpent.filter(x => x.type === activeTab);
    return {
      limit: b.reduce((s, x) => s + x.limit, 0),
      actual: b.reduce((s, x) => s + x.spent, 0)
    };
  }, [budgetsWithCalculatedSpent, activeTab]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const finalCategory = isCustomMode ? customCategory : category;
    if (!finalCategory || limit === '') return;

    if (isEditing) {
      updateBudget({ 
        ...isEditing, 
        category: finalCategory, 
        limit: Number(limit), 
        icon: selectedIcon, 
        color: selectedColor 
      });
      setIsEditing(null);
    } else {
      addBudget({ 
        category: finalCategory, 
        limit: Number(limit), 
        type: activeTab,
        icon: selectedIcon,
        color: selectedColor
      });
      setIsCreating(false);
    }
    resetForm();
  };

  const resetForm = () => {
    setCategory('');
    setLimit('');
    setCustomCategory('');
    setIsCustomMode(false);
    setSelectedIcon('ShoppingBag');
    setSelectedColor('#3b82f6');
  };

  const openCreate = () => {
    resetForm();
    const defaultCats = activeTab === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    setCategory(defaultCats[0].name);
    setSelectedIcon(defaultCats[0].icon);
    setSelectedColor(defaultCats[0].color);
    setIsCreating(true);
  };

  const openEdit = (b: Budget) => {
    const defaultCats = b.type === 'expense' ? CATEGORIES : INCOME_CATEGORIES;
    const isStandard = defaultCats.some(c => c.name === b.category);

    setCategory(isStandard ? b.category : 'Otra');
    setCustomCategory(isStandard ? '' : b.category);
    setIsCustomMode(!isStandard);
    setLimit(b.limit);
    setSelectedIcon(b.icon);
    setSelectedColor(b.color || '#3b82f6');
    setIsEditing(b);
  };

  const handleDeleteClick = (e: React.MouseEvent, budgetId: string) => {
    e.stopPropagation();
    if (deletingId === budgetId) {
      deleteBudget(budgetId);
      setDeletingId(null);
    } else {
      setDeletingId(budgetId);
      setTimeout(() => {
        setDeletingId(prev => prev === budgetId ? null : prev);
      }, 3000);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight transition-colors">Presupuestos</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight transition-colors">Gestiona límites y objetivos con céntimos.</p>
        </div>
        <button 
          onClick={openCreate}
          className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
        >
          <Plus size={20} />
          Nuevo Límite
        </button>
      </div>

      <div className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-1.5 rounded-3xl w-full md:w-fit border border-slate-200 dark:border-slate-700 shadow-inner">
        <button onClick={() => setActiveTab('expense')} className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'expense' ? 'bg-white dark:bg-slate-700 text-rose-600 dark:text-rose-400 shadow-md' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700'}`}>GASTOS</button>
        <button onClick={() => setActiveTab('income')} className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 text-xs font-black rounded-2xl transition-all ${activeTab === 'income' ? 'bg-white dark:bg-slate-700 text-emerald-600 dark:text-emerald-400 shadow-md' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700'}`}>INGRESOS</button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {filteredBudgets.map(b => {
          const progress = b.limit > 0 ? Math.min((b.spent / b.limit) * 100, 100) : 0;
          return (
            <div key={b.id} onClick={() => setSelectedBudget(b)} className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-all group cursor-pointer active:scale-[0.99]">
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div className="w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner dark:shadow-none" style={{ backgroundColor: `${b.color}${theme === 'dark' ? '30' : '15'}`, color: b.color }}>
                    {ICON_MAP[b.icon] || <Tag size={24} />}
                  </div>
                  <div><h4 className="text-lg font-black text-slate-800 dark:text-white transition-colors">{b.category}</h4></div>
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all"><button onClick={(e) => { e.stopPropagation(); openEdit(b); }} className="p-2.5 text-slate-400 hover:text-blue-600 transition-colors"><Edit2 size={18} /></button></div>
              </div>
              <p className="text-4xl font-black text-slate-900 dark:text-white transition-colors">{b.spent.toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</p>
              <p className="text-xs text-slate-400 font-bold uppercase mt-1">de {b.limit.toLocaleString()}€</p>
              <div className="w-full bg-slate-100 dark:bg-slate-800 h-3 rounded-full overflow-hidden mt-5 transition-colors">
                <div className="h-full rounded-full transition-all duration-1000" style={{ width: `${progress}%`, backgroundColor: b.color }}></div>
              </div>
            </div>
          );
        })}
      </div>

      {(isCreating || isEditing) && (
        <div className="fixed inset-0 bg-slate-900/90 z-[60] flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[3.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100 dark:border-slate-800 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-slate-900 dark:text-white transition-colors">{isEditing ? 'Editar Límite' : 'Nueva Categoría'}</h3>
              <button onClick={() => { setIsCreating(false); setIsEditing(null); }} className="p-3 text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"><X size={24} /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-6">
              <div>
                <label className="block text-[11px] font-black text-slate-500 uppercase mb-2">Importe Mensual (€)</label>
