  Check,
  TrendingUp,
  AlertCircle,
  AlignLeft,
  ChevronDown
} from 'lucide-react';
import { Refund } from '../types';

const Refunds: React.FC = () => {
  const { budgets, refunds, addRefund, updateRefund, deleteRefund, mergeRefunds } = useFinance();

  // UI States
  const [isAdding, setIsAdding] = useState(false);
  const [isMerging, setIsMerging] = useState(false);
  const [mergeSelection, setMergeSelection] = useState<string[]>([]);
  const [filter, setFilter] = useState<'all' | 'open' | 'closed'>('open');
  const [selectedRefundId, setSelectedRefundId] = useState<string | null>(null);

  // Obtener categorías de presupuesto (únicamente de gastos)
  const budgetExpenseCategories = useMemo(() => {
    return budgets.filter(b => b.type === 'expense').map(b => b.category);
  }, [budgets]);

  // Form state
  const [name, setName] = useState('');
  const [total, setTotal] = useState<number | ''>('');
  const [myPart, setMyPart] = useState<number | ''>('');
  const [notes, setNotes] = useState('');
  const [category, setCategory] = useState('');

  // Sincronizar categoría inicial al abrir el modal basada en los presupuestos existentes
  useEffect(() => {
    if (isAdding && budgetExpenseCategories.length > 0 && !category) {
      setCategory(budgetExpenseCategories[0]);
    }
  }, [isAdding, budgetExpenseCategories]);

  // Notes editing in Modal
  const [modalNotes, setModalNotes] = useState('');

  // Encuentra el reembolso actualmente seleccionado desde el estado global
  const selectedRefund = refunds.find(r => r.id === selectedRefundId);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (total === '' || myPart === '' || !category) return;
    const pending = total - myPart;
    addRefund({
      name,
      totalAmount: total,
      paidByMe: myPart,
      pendingAmount: pending,
      status: pending <= 0 ? 'closed' : 'open',
      notes,
      date: new Date().toISOString(),
      category: category
    });
    setIsAdding(false);
    resetForm();
  };

  const resetForm = () => { 
    setName(''); 
    setTotal(''); 
    setMyPart(''); 
    setNotes(''); 
    setCategory(budgetExpenseCategories[0] || ''); 
  };

  const handleCardClick = (r: Refund) => {
    if (isMerging) {
      setMergeSelection(prev => {
        if (prev.includes(r.id)) return prev.filter(x => x !== r.id);
        if (prev.length >= 2) return prev; 
        return [...prev, r.id];
      });
    } else {
      setSelectedRefundId(r.id);
      setModalNotes(r.notes || '');
    }
  };

  const executeMerge = () => {
    if (mergeSelection.length === 2) {
      mergeRefunds(mergeSelection[0], mergeSelection[1]);
      setMergeSelection([]);
      setIsMerging(false);
    }
  };

  const handleActionClick = (e: React.MouseEvent, action: () => void) => {
    e.stopPropagation();
    e.preventDefault();
    action();
  };

  const handleSaveNotes = () => {
    if (selectedRefund) {
        updateRefund({ ...selectedRefund, notes: modalNotes });
        setSelectedRefundId(null);
    }
  };

  const filteredRefunds = refunds.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight transition-colors">Reembolsos</h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight transition-colors">Gestiona deudas pendientes con decimales.</p>
        </div>
        <div className="flex gap-2">
          <button 
            type="button"
            onClick={() => setIsAdding(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 dark:shadow-none active:scale-95"
          >
            <Plus size={18} />
            Nuevo Reembolso
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredRefunds.map(r => (
          <div 
            key={r.id} 
            onClick={() => handleCardClick(r)}
            className={`bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border transition-all relative overflow-hidden group flex flex-col duration-300 cursor-pointer ${
              r.status === 'closed' ? 'border-slate-100 dark:border-slate-800 opacity-80' : 'border-slate-100 dark:border-slate-800 shadow-sm'
            }`}
          >
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${r.status === 'closed' ? 'bg-slate-100 dark:bg-slate-800 text-slate-400' : 'bg-blue-50 dark:bg-blue-900/40 text-blue-600'}`}>
                  <Users size={22} />
                </div>
                <div>
                  <h4 className="font-bold text-slate-800 dark:text-slate-100 transition-colors">{r.name}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{r.category}</p>
                </div>
              </div>
            </div>
            <div className={`rounded-3xl p-6 border transition-all space-y-4 ${r.status === 'closed' ? 'bg-slate-50 dark:bg-slate-800/50' : 'bg-blue-50/50 dark:bg-blue-900/20 border-blue-100 shadow-sm'}`}>
              <p className={`text-3xl font-black ${r.status === 'closed' ? 'text-slate-400 line-through' : 'text-blue-600 dark:text-blue-400'}`}>{r.pendingAmount.toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</p>
            </div>
          </div>
        ))}
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8">
               <h3 className="text-2xl font-black text-slate-800 dark:text-white transition-colors">Nuevo Reembolso</h3>
               <button type="button" onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Importe Total (€)</label>
                <input type="number" step="0.01" inputMode="decimal" value={total} onChange={e => setTotal(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white" placeholder="0.00" required />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Concepto</label>
                  <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 outline-none font-medium text-slate-900 dark:text-white" placeholder="Cena..." required />
                </div>
                <div className="col-span-2">
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Tu parte (€)</label>
                  <input type="number" step="0.01" inputMode="decimal" value={myPart} onChange={e => setMyPart(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white" placeholder="0.00" required />
