                <div>
                  <h4 className="font-bold text-slate-800 dark:text-slate-100 transition-colors">{r.name}</h4>
                  <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{r.category}</p>
                </div>
              </div>
              <button onClick={() => deleteRefund(r.id)} className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 transition-colors"><Trash2 size={18} /></button>
            </div>
            <div className={`rounded-3xl p-6 border transition-all ${r.status === 'closed' ? 'bg-slate-50 dark:bg-slate-800/50' : 'bg-blue-50/50 dark:bg-blue-900/20 border-blue-100 shadow-sm'}`}>
              <p className={`text-3xl font-black ${r.status === 'closed' ? 'text-slate-400 line-through' : 'text-blue-600 dark:text-blue-400'}`}>{r.pendingAmount.toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</p>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Pendiente de cobro</p>
            </div>
          </div>
        ))}
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8">
               <h3 className="text-2xl font-black text-slate-800 dark:text-white transition-colors">Nuevo Reembolso</h3>
               <button type="button" onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"><X size={20} className="text-slate-400" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 pl-1">Importe Total (€)</label>
                <input type="number" step="0.01" inputMode="decimal" value={total} onChange={e => setTotal(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white focus:border-blue-500 transition-all" placeholder="0.00" required />
