                      <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required />
                    </div>
                    <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white transition-colors">{accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}</select>
                    {type === 'saving' ? (
                      <select value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required><option value="">Selecciona hucha</option>{savings.map(s => <option key={s.id} value={s.id}>{s.emoji} {s.name}</option>)}</select>
                    ) : (
                      <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required>{availableCategories.map(c => <option key={c} value={c}>{c}</option>)}</select>
                    )}
                  </div>
                  <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl active:scale-95 transition-all">CONFIRMAR</button>
                </form>
             </div>
         </div>
      )}

      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/90 z-[80] flex items-center justify-center p-4" onClick={() => setViewingTx(null)}>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100 dark:border-slate-800" onClick={e => e.stopPropagation()}>
            <div className="flex flex-col items-center text-center gap-8">
              <div className={`w-24 h-24 rounded-[2rem] flex items-center justify-center shadow-lg ${getTxStyle(viewingTx).bg} ${getTxStyle(viewingTx).color}`}>{React.cloneElement(getTxStyle(viewingTx).icon as React.ReactElement<{size: number}>, { size: 48 })}</div>
              <div><p className="text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em] mb-2">{viewingTx.category}</p><h3 className="text-2xl font-black text-slate-900 dark:text-white leading-tight transition-colors">{viewingTx.description}</h3></div>
              <div className="w-full bg-slate-50 dark:bg-slate-800 rounded-[2.5rem] p-8 space-y-5 border border-slate-100 dark:border-slate-700 transition-colors"><div className="flex justify-between items-center"><span className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase">Monto</span><span className={`text-3xl font-black ${getTxStyle(viewingTx).color}`}>{viewingTx.type === 'income' ? '+' : '-'}{Math.abs(viewingTx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</span></div></div>
              <div className="grid grid-cols-2 gap-4 w-full">
                <button onClick={() => startEdit(viewingTx)} className="py-5 bg-white dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 text-slate-800 dark:text-slate-200 font-black rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-50 transition-all"><Edit2 size={18} /> EDITAR</button>
                {confirmDeleteInModal ? <button onClick={() => handleDeleteFromModal(viewingTx.id)} className="py-5 bg-rose-600 text-white font-black rounded-2xl animate-in zoom-in">CONFIRMAR</button> : <button onClick={() => setConfirmDeleteInModal(true)} className="py-5 bg-rose-50 dark:bg-rose-900/40 text-rose-600 dark:text-rose-400 border-2 border-rose-100 dark:border-rose-900/50 font-black rounded-2xl flex items-center justify-center gap-2 transition-all"><Trash2 size={18} /> BORRAR</button>}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, Trash2, Edit2, ArrowRightLeft, CreditCard, Banknote, Landmark, X, Check } from 'lucide-react';
import { Account } from '../types';

const Accounts: React.FC = () => {
  const { accounts, currentDate, getAccountHistoricalBalance, addAccount, updateAccount, deleteAccount, addTransaction, theme } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [editingAccount, setEditingAccount] = useState<Account | null>(null);
  const [isTransferring, setIsTransferring] = useState(false);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [type, setType] = useState<Account['type']>('Bank');
  const [balanceInput, setBalanceInput] = useState<number | ''>('');
  const [color, setColor] = useState('#3b82f6');
  const [emoji, setEmoji] = useState('🏦');

  const [fromId, setFromId] = useState('');
  const [toId, setToId] = useState('');
  const [transferAmount, setTransferAmount] = useState<number | ''>('');

  const resetForm = () => {
    setName('');
    setType('Bank');
    setBalanceInput('');
    setColor('#3b82f6');
    setEmoji('🏦');
  };

  const handleOpenAdd = () => { resetForm(); setIsAdding(true); };

  const handleOpenEdit = (acc: Account) => {
    setName(acc.name);
    setType(acc.type);
    setBalanceInput(acc.initialBalance);
    setColor(acc.color);
    setEmoji(acc.emoji || '🏦');
    setEditingAccount(acc);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalBalance = balanceInput === '' ? 0 : balanceInput;
    if (editingAccount) {
      updateAccount({ ...editingAccount, name, type, initialBalance: finalBalance, color, emoji });
      setEditingAccount(null);
    } else {
      addAccount({ name, type, initialBalance: finalBalance, color, emoji });
      setIsAdding(false);
    }
    resetForm();
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    const amountValue = transferAmount === '' ? 0 : transferAmount;
    if (!fromId || !toId || fromId === toId || amountValue <= 0) return alert("Verifica los datos de la transferencia");
    const date = new Date().toISOString().split('T')[0];
    addTransaction({ date, amount: amountValue, description: `Transferencia a ${accounts.find(a => a.id === toId)?.name}`, category: 'Traspaso', type: 'expense', accountId: fromId, isRefund: false });
    addTransaction({ date, amount: amountValue, description: `Transferencia desde ${accounts.find(a => a.id === fromId)?.name}`, category: 'Traspaso', type: 'income', accountId: toId, isRefund: false });
    setIsTransferring(false);
    setTransferAmount('');
    setFromId('');
    setToId('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div><h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Cuentas y Efectivo</h2><p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight">Gestiona tu liquidez. Soporte nativo de decimales para {currentDate}.</p></div>
        <div className="flex gap-2">
          <button onClick={() => setIsTransferring(true)} className="flex items-center gap-2 px-6 py-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 font-bold rounded-2xl hover:bg-slate-50 transition-all shadow-sm active:scale-95"><ArrowRightLeft size={18} />Transferir</button>
          <button onClick={handleOpenAdd} className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl active:scale-95"><Plus size={18} />Nueva Cuenta</button>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {accounts.map(acc => {
          const displayBalance = getAccountHistoricalBalance(acc.id, currentDate);
          const isConfirming = confirmDeleteId === acc.id;
          return (
            <div key={acc.id} className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden hover:shadow-md transition-all duration-300">
              <div className="flex justify-between items-start mb-6">
                <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner dark:shadow-none" style={{ backgroundColor: `${acc.color}${theme === 'dark' ? '30' : '20'}` }}>{acc.emoji || (acc.type === 'Bank' ? '🏦' : acc.type === 'Cash' ? '💵' : '💳')}</div>
                <div className={`flex gap-1 transition-opacity ${isConfirming ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                  {!isConfirming ? (
                    <><button onClick={() => handleOpenEdit(acc)} className="p-2.5 hover:bg-blue-50 dark:hover:bg-blue-900/40 rounded-xl text-blue-500 transition-colors"><Edit2 size={18} /></button><button onClick={() => setConfirmDeleteId(acc.id)} className="p-2.5 hover:bg-rose-50 dark:hover:bg-rose-900/40 rounded-xl text-rose-400 transition-colors"><Trash2 size={18} /></button></>
                  ) : (
                    <div className="flex gap-1 items-center animate-in slide-in-from-right-2"><button onClick={() => { deleteAccount(acc.id); setConfirmDeleteId(null); }} className="flex items-center gap-1 px-3 py-1.5 bg-rose-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-700 transition-all"><Check size={14} /> Confirmar</button><button onClick={() => setConfirmDeleteId(null)} className="p-1.5 bg-slate-100 dark:bg-slate-800 rounded-lg text-slate-400 hover:text-slate-600 transition-all"><X size={16} /></button></div>
                  )}
                </div>
              </div>
              <h4 className="text-xl font-bold text-slate-800 dark:text-slate-100 transition-colors">{acc.name}</h4><p className="text-xs text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest mb-4">{acc.type}</p>
              <div className="flex items-baseline gap-2"><span className="text-3xl font-black text-slate-900 dark:text-white transition-colors">{displayBalance.toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</span><span className="text-[10px] text-slate-400 font-bold uppercase tracking-wider transition-colors">Saldo</span></div>
            </div>
          );
        })}
      </div>
      {(isAdding || editingAccount) && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 overflow-y-auto max-h-[90vh] border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8"><h3 className="text-2xl font-black text-slate-800 dark:text-white">{editingAccount ? 'Editar' : 'Nueva'} Cuenta</h3><button onClick={() => { setIsAdding(false); setEditingAccount(null); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"><X size={20} className="text-slate-400" /></button></div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div><label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-2">Nombre</label><input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl p-4 font-medium outline-none text-slate-900 dark:text-white transition-all focus:ring-2 focus:ring-blue-500" required /></div>
              <div className="grid grid-cols-2 gap-4">
                <div><label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Saldo Inicial</label><input type="number" step="0.01" inputMode="decimal" value={balanceInput} onChange={e => setBalanceInput(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white transition-all" required /></div>
                <div><label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Tipo</label><select value={type} onChange={e => setType(e.target.value as any)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 rounded-2xl p-4 font-medium outline-none text-slate-900 dark:text-white"><option value="Bank">Banco</option><option value="Cash">Efectivo</option><option value="Card">Tarjeta</option></select></div>
              </div>
              <div className="flex gap-3 pt-4"><button type="button" onClick={() => { setIsAdding(false); setEditingAccount(null); }} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl transition-colors">Cancelar</button><button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl">{editingAccount ? 'Guardar' : 'Crear'}</button></div>
            </form>
          </div>
        </div>
      )}
      {isTransferring && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in duration-300 border border-transparent dark:border-slate-800">
            <div className="flex justify-between items-center mb-8"><h3 className="text-2xl font-black text-slate-800 dark:text-white">Transferencia</h3><button onClick={() => setIsTransferring(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"><X size={20} className="text-slate-400" /></button></div>
            <form onSubmit={handleTransfer} className="space-y-6">
              <div><label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Cantidad (€)</label><input type="number" step="0.01" inputMode="decimal" value={transferAmount} onChange={e => setTransferAmount(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 rounded-2xl p-4 text-center text-3xl font-black outline-none text-slate-900 dark:text-white transition-all" placeholder="0.00" required /></div>
              <div className="flex gap-3 pt-4"><button type="button" onClick={() => setIsTransferring(false)} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl">Cancelar</button><button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl shadow-xl transition-all">Confirmar</button></div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Accounts;

import React, { useState } from 'react';
import { useFinance } from '../App';
import { Plus, PiggyBank, TrendingUp, ArrowRightLeft, Percent, X, Edit2, Trash2, Check } from 'lucide-react';
import { Saving } from '../types';

const Savings: React.FC = () => {
  const { savings, currentDate, getSavingHistoricalBalance, addSaving, updateSaving, deleteSaving } = useFinance();
  const [isAdding, setIsAdding] = useState(false);
  const [editingSaving, setEditingSaving] = useState<Saving | null>(null);
  const [adjustingSaving, setAdjustingSaving] = useState<Saving | null>(null);
  const [adjustmentMode, setAdjustmentMode] = useState<'amount' | 'percent'>('amount');
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [amountInput, setAmountInput] = useState<number | ''>('');
  const [targetInput, setTargetInput] = useState<number | ''>('');
  const [isInvestment, setIsInvestment] = useState(false);
  const [growthRateInput, setGrowthRateInput] = useState<number | ''>('');
  const [emoji, setEmoji] = useState('💰');
  const [adjValue, setAdjValue] = useState<number | ''>('');

  const resetForm = () => {
    setName(''); setAmountInput(''); setTargetInput(''); setIsInvestment(false);
    setGrowthRateInput(''); setEmoji('💰'); setIsAdding(false); setEditingSaving(null);
  };

  const handleOpenEdit = (s: Saving) => {
    setName(s.name); setAmountInput(s.currentAmount); setTargetInput(s.targetAmount || '');
    setIsInvestment(s.isInvestment); setGrowthRateInput(s.growthRate || '');
    setEmoji(s.emoji || (s.isInvestment ? '📈' : '💰')); setEditingSaving(s);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalAmount = amountInput === '' ? 0 : amountInput;
    const finalTarget = targetInput === '' ? undefined : targetInput;
    const finalGrowth = isInvestment && growthRateInput !== '' ? growthRateInput : undefined;

    if (editingSaving) {
      updateSaving({ ...editingSaving, name, currentAmount: finalAmount, targetAmount: finalTarget, isInvestment, growthRate: finalGrowth, emoji });
    } else {
      addSaving({ name, currentAmount: finalAmount, targetAmount: finalTarget, isInvestment, growthRate: finalGrowth, color: '#f59e0b', emoji });
    }
    resetForm();
  };

  const applyAdjustment = () => {
    if (!adjustingSaving || adjValue === '') return;
    let newAmount = adjustingSaving.currentAmount;
    if (adjustmentMode === 'amount') newAmount += adjValue;
    else newAmount = newAmount * (1 + adjValue / 100);
    updateSaving({ ...adjustingSaving, currentAmount: Math.max(0, newAmount) });
    setAdjustingSaving(null); setAdjValue('');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 transition-colors">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div><h2 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">Huchas e Inversiones</h2><p className="text-slate-500 dark:text-slate-400 font-medium tracking-tight">Gestiona tus ahorros con precisión decimal para {currentDate}.</p></div>
        <button onClick={() => setIsAdding(true)} className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-xl active:scale-95"><Plus size={18} />Crear Hucha</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {savings.map(s => {
          const displayAmount = getSavingHistoricalBalance(s.id, currentDate);
          const progress = s.targetAmount ? Math.min((displayAmount / s.targetAmount) * 100, 100) : null;
          const isConfirming = confirmDeleteId === s.id;
          return (
            <div key={s.id} className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 shadow-sm relative group hover:shadow-md transition-all duration-300">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner ${s.isInvestment ? 'bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 dark:text-indigo-400' : 'bg-amber-50 dark:bg-amber-900/40 text-amber-600 dark:text-amber-400'}`}>{s.emoji || (s.isInvestment ? '📈' : '💰')}</div>
                  <div><h4 className="font-bold text-slate-800 dark:text-slate-100 transition-colors">{s.name}</h4><p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{s.isInvestment ? 'Inversión' : 'Ahorro'}</p></div>
                </div>
                <div className={`flex gap-1 transition-opacity ${isConfirming ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                  {!isConfirming ? (
                    <><button onClick={() => handleOpenEdit(s)} className="p-2 text-slate-300 hover:text-blue-500 transition-all"><Edit2 size={18} /></button><button onClick={() => setConfirmDeleteId(s.id)} className="p-2 text-slate-300 hover:text-rose-500 transition-all"><Trash2 size={18} /></button></>
                  ) : (
                    <div className="flex gap-1 items-center animate-in slide-in-from-right-2"><button onClick={() => { deleteSaving(s.id); setConfirmDeleteId(null); }} className="flex items-center gap-1 px-3 py-1.5 bg-rose-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-700 transition-all"><Check size={14} /> Confirmar</button><button onClick={() => setConfirmDeleteId(null)} className="p-1.5 bg-slate-100 dark:bg-slate-800 rounded-lg text-slate-400 hover:text-slate-600 transition-all"><X size={16} /></button></div>
                  )}
                </div>
              </div>
              <div className="mb-6"><span className="text-4xl font-black text-slate-900 dark:text-white transition-colors">{displayAmount.toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</span>{progress !== null && (<div className="mt-6"><div className="flex justify-between text-[10px] font-black uppercase mb-2"><span className="text-blue-600">{progress.toFixed(1)}%</span><span className="text-slate-400">Meta: {s.targetAmount}€</span></div><div className="w-full bg-slate-100 dark:bg-slate-800 h-2.5 rounded-full overflow-hidden transition-colors"><div className="h-full bg-blue-600 rounded-full transition-all duration-1000" style={{ width: `${progress}%` }}></div></div></div>)}</div>
              <div className="grid grid-cols-2 gap-3"><button onClick={() => { setAdjustingSaving(s); setAdjustmentMode('amount'); }} className="flex items-center justify-center gap-2 py-3 bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-2xl font-bold text-xs hover:bg-slate-100 transition-all border border-slate-100 dark:border-slate-700"><ArrowRightLeft size={16} className="text-blue-500" /> Ajustar</button><button onClick={() => { setAdjustingSaving(s); setAdjustmentMode('percent'); }} className="flex items-center justify-center gap-2 py-3 bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-2xl font-bold text-xs hover:bg-slate-100 transition-all border border-slate-100 dark:border-slate-700"><Percent size={16} className="text-emerald-500" /> Aplicar %</button></div>
            </div>
          );
        })}
      </div>
      {(isAdding || editingSaving) && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-transparent dark:border-slate-800">
