              <div className="grid grid-cols-2 gap-4">
                <div><label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Monto Actual</label><input type="number" step="0.01" inputMode="decimal" value={amountInput} onChange={e => setAmountInput(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 rounded-2xl p-4 font-bold outline-none text-slate-900 dark:text-white transition-all" placeholder="0.00" /></div>
