              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2"><label className="block text-xs font-bold text-slate-500 uppercase mb-2 pl-1">Concepto</label><input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 rounded-2xl p-4 outline-none font-medium text-slate-900 dark:text-white transition-all" placeholder="Cena..." required /></div>
