              <div className="flex gap-3 pt-4"><button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 font-bold rounded-2xl">Cancelar</button><button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-bold rounded-2xl active:scale-95 shadow-xl">Crear</button></div>
            </form>
          </div>
        </div>
      )}
      {selectedRefund && (
        <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4" onClick={() => setSelectedRefundId(null)}>
            <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100 dark:border-slate-800" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-8"><div><h3 className="text-2xl font-black text-slate-800 dark:text-white">{selectedRefund.name}</h3><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{selectedRefund.category}</p></div><button onClick={() => setSelectedRefundId(null)} className="p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={24} /></button></div>
                <div className="space-y-4 mb-8"><div className="bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl border border-slate-100 dark:border-slate-800 flex justify-between items-center"><span className="text-xs font-black text-slate-500 uppercase">Mi Parte</span><span className="text-lg font-black text-slate-800 dark:text-white">{selectedRefund.paidByMe.toLocaleString()}€</span></div><div className="bg-blue-50 dark:bg-blue-900/20 p-5 rounded-2xl border border-blue-100 dark:border-blue-800 flex justify-between items-center"><span className="text-xs font-black text-blue-600 uppercase">Total Operación</span><span className="text-lg font-black text-blue-700 dark:text-blue-300">{selectedRefund.totalAmount.toLocaleString()}€</span></div></div>
                <div className="space-y-3"><label className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest"><AlignLeft size={14} /> Notas</label><textarea className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 rounded-2xl p-4 text-sm outline-none resize-none h-32 text-slate-700 dark:text-white transition-colors" placeholder="Detalles de la deuda..." value={modalNotes} onChange={(e) => setModalNotes(e.target.value)} /></div>
                <button onClick={handleSaveNotes} className="w-full mt-6 py-4 bg-slate-900 dark:bg-blue-600 text-white font-black rounded-2xl shadow-xl hover:bg-slate-800 transition-all active:scale-95">GUARDAR NOTAS</button>
            </div>
