import { GoogleGenAI, Type, FunctionDeclaration, GenerateContentResponse } from "@google/genai";
import { Transaction, Budget, AIChallenge } from "../types";

export interface ScannedTransaction {
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  isTransfer: boolean;
  isSaving: boolean;
  isRefund: boolean;
  suggestedAccount?: string;
}

// Analiza una captura de pantalla o ticket extrayendo múltiples líneas y categorizando inteligentemente.
export const analyzeReceipt = async (base64Image: string): Promise<ScannedTransaction[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: `Analiza esta captura de pantalla de movimientos bancarios (especialmente Revolut) o ticket. 
        Extrae UNA LISTA de todas las transacciones visibles. 
        IMPORTANTE PARA REVOLUT: 
        - Los pagos en comercios son 'expense'.
        - Los abonos o transferencias recibidas son 'income'.
        - Los movimientos a "Pockets" o "Vaults" solo son 'isSaving: true' si el usuario los guarda, si es un pago directo desde allí es un 'expense'.

        Para cada transacción, determina:
        1. description: concepto claro y conciso.
        2. amount: importe positivo (usa punto para decimales).
        3. date: fecha en formato YYYY-MM-DD. Si no aparece el año, usa el año actual.
        4. category: categoría que MEJOR encaje con gastos comunes (Alimentación, Transporte, Ocio, Vivienda, Salud, Compras, Suscripciones).
        5. type: 'income' para entradas, 'expense' para salidas.
        6. isTransfer: true si es entre cuentas del mismo titular.
        7. isSaving: true solo si es dinero destinado específicamente a ahorro/inversión.
        8. isRefund: true si es un cobro de deuda compartida o Bizum recibido por un gasto previo.
        9. suggestedAccount: nombre del banco/cuenta que aparece.` }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            type: { type: Type.STRING, enum: ['income', 'expense'] },
            isTransfer: { type: Type.BOOLEAN },
            isSaving: { type: Type.BOOLEAN },
            isRefund: { type: Type.BOOLEAN },
            suggestedAccount: { type: Type.STRING }
          },
          required: ['description', 'amount', 'date', 'category', 'type', 'isTransfer', 'isSaving', 'isRefund']
        }
      }
    }
  });
  return JSON.parse(response.text || "[]");
};

