        </div>
        <div className="w-full overflow-hidden">
          <table className="w-full border-collapse">
            <thead><tr className="bg-slate-50/50 dark:bg-slate-800/30 text-[10px] uppercase tracking-[0.15em] text-slate-400 dark:text-slate-500 font-black border-b border-slate-100 dark:border-slate-800"><th className="px-6 py-5 text-left">Fecha</th><th className="px-6 py-5 text-left">Detalle</th><th className="px-6 py-5 text-right">Importe</th></tr></thead>
            <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
              {filteredTx.map(tx => {
                const style = getTxStyle(tx);
                return (
                  <tr key={tx.id} onClick={() => { setViewingTx(tx); setConfirmDeleteInModal(false); }} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-all cursor-pointer">
                    <td className="px-6 py-6 text-[11px] font-black text-slate-500 uppercase">{new Date(tx.date).toLocaleDateString('es-ES', { day: '2-digit', month: 'short' })}</td>
