                    <td className={`px-6 py-6 text-right font-black text-lg ${style.color}`}>{tx.type === 'income' ? '+' : '-'}{Math.abs(tx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {isAdding && (
         <div className="fixed inset-0 bg-slate-900/90 z-50 flex items-center justify-center p-4">
             <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-lg p-10 shadow-2xl border border-slate-200 dark:border-slate-800 overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center mb-10">
                  <div className="flex flex-col">
                    <h3 className="text-3xl font-black text-slate-900 dark:text-white">
                      {editingTx ? 'Editar' : scannedQueue.length > 0 ? 'Confirmar Escaneo' : 'Nuevo'} Movimiento
                    </h3>
                    {scannedQueue.length > 0 && (
                      <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest mt-1">
                        {totalScannedCount - scannedQueue.length + 1} de {totalScannedCount} analizados
                      </span>
                    )}
                  </div>
                  <button onClick={() => { setIsAdding(false); resetForm(); setScannedQueue([]); }} className="p-4 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full text-slate-400"><X size={28} /></button>
                </div>
                <form onSubmit={handleManualSubmit} className="space-y-8">
                  <div className="flex bg-slate-100 dark:bg-slate-800 p-2 rounded-[1.8rem] border border-slate-200 dark:border-slate-700">
                    <button type="button" onClick={() => {setType('expense'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'expense' && !isTransfer ? 'bg-white dark:bg-slate-700 text-rose-600 shadow-md' : 'text-slate-500'}`}>GASTO</button>
                    <button type="button" onClick={() => {setType('income'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'income' && !isTransfer ? 'bg-white dark:bg-slate-700 text-emerald-600 shadow-md' : 'text-slate-500'}`}>INGRESO</button>
                    <button type="button" onClick={() => {setType('saving'); setIsTransfer(false);}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${type === 'saving' ? 'bg-white dark:bg-slate-700 text-amber-500 shadow-md' : 'text-slate-500'}`}>AHORRO</button>
                    <button type="button" onClick={() => {setIsTransfer(true); setType('expense');}} className={`flex-1 py-4 text-[12px] font-black rounded-2xl transition-all ${isTransfer ? 'bg-white dark:bg-slate-700 text-blue-600 shadow-md' : 'text-slate-500'}`}>TRASPASO</button>
                  </div>
                  {type === 'saving' && (
                    <div className="bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl border-2 border-amber-100 dark:border-amber-800 grid grid-cols-2 gap-2 animate-in slide-in-from-top-2">
                        <button type="button" onClick={() => setSavingDirection('deposit')} className={`py-3 rounded-xl text-[10px] font-black ${savingDirection === 'deposit' ? 'bg-amber-500 text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-amber-500 border border-amber-200'}`}><ArrowUpCircle size={14} className="inline mr-1"/> APORTACIÓN</button>
                        <button type="button" onClick={() => setSavingDirection('withdraw')} className={`py-3 rounded-xl text-[10px] font-black ${savingDirection === 'withdraw' ? 'bg-amber-600 text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-amber-600 border border-amber-200'}`}><ArrowDownCircle size={14} className="inline mr-1"/> RETIRADA</button>
                    </div>
                  )}
                  <div className="space-y-6">
                    <input type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white transition-all" placeholder="Descripción..." required />
                    <div className="grid grid-cols-2 gap-6">
                      <input type="number" step="0.01" inputMode="decimal" value={amount} onChange={e => setAmount(e.target.value === '' ? '' : Number(e.target.value))} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-black text-xl outline-none text-slate-900 dark:text-white" placeholder="Importe (€)" required />
                      <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required />
                    </div>
                    <select value={accountId} onChange={e => setAccountId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white transition-colors">{accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}</select>
                    {isTransfer ? (
                        <select value={transferTargetId} onChange={e => setTransferTargetId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required>
                          <option value="">Selecciona destino</option>
                          {accounts.filter(a => a.id !== accountId).map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                        </select>
                    ) : type === 'saving' ? (
                      <select value={selectedSavingId} onChange={e => setSelectedSavingId(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required><option value="">Selecciona hucha</option>{savings.map(s => <option key={s.id} value={s.id}>{s.emoji} {s.name}</option>)}</select>
                    ) : (
                      <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-2xl p-5 font-bold outline-none text-slate-900 dark:text-white" required>{availableCategories.map(c => <option key={c} value={c}>{c}</option>)}</select>
                    )}
                  </div>
                  <div className="flex flex-col gap-3">
                    <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl active:scale-95 transition-all">
                      {scannedQueue.length > 1 ? 'CONFIRMAR Y SIGUIENTE' : 'CONFIRMAR'}
                    </button>
                    {scannedQueue.length > 0 && (
                      <button type="button" onClick={handleDiscardCurrentScanned} className="w-full py-4 bg-slate-100 dark:bg-slate-800 text-rose-600 font-black rounded-2xl transition-all">DESCARTAR ESTE MOVIMIENTO</button>
                    )}
                  </div>
                </form>
             </div>
         </div>
      )}

      {viewingTx && (
        <div className="fixed inset-0 bg-slate-900/90 z-[80] flex items-center justify-center p-4" onClick={() => setViewingTx(null)}>
          <div className="bg-white dark:bg-slate-900 rounded-[3rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in duration-300 border border-slate-100 dark:border-slate-800" onClick={e => e.stopPropagation()}>
            <div className="flex flex-col items-center text-center gap-8">
              <div className={`w-24 h-24 rounded-[2rem] flex items-center justify-center shadow-lg ${getTxStyle(viewingTx).bg} ${getTxStyle(viewingTx).color}`}>{React.cloneElement(getTxStyle(viewingTx).icon as React.ReactElement<{size: number}>, { size: 48 })}</div>
              <div><p className="text-[11px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em] mb-2">{viewingTx.category}</p><h3 className="text-2xl font-black text-slate-900 dark:text-white leading-tight transition-colors">{viewingTx.description}</h3></div>
              <div className="w-full bg-slate-50 dark:bg-slate-800 rounded-[2.5rem] p-8 space-y-5 border border-slate-100 dark:border-slate-700 transition-colors"><div className="flex justify-between items-center"><span className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase">Monto</span><span className={`text-3xl font-black ${getTxStyle(viewingTx).color}`}>{viewingTx.type === 'income' ? '+' : '-'}{Math.abs(viewingTx.amount).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€</span></div></div>
              <div className="grid grid-cols-2 gap-4 w-full">
                <button onClick={() => startEdit(viewingTx)} className="py-5 bg-white dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 text-slate-800 dark:text-slate-200 font-black rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-50 transition-all"><Edit2 size={18} /> EDITAR</button>
                {confirmDeleteInModal ? <button onClick={() => handleDeleteFromModal(viewingTx.id)} className="py-5 bg-rose-600 text-white font-black rounded-2xl animate-in zoom-in">CONFIRMAR</button> : <button onClick={() => setConfirmDeleteInModal(true)} className="py-5 bg-rose-50 dark:bg-rose-900/40 text-rose-600 dark:text-rose-400 border-2 border-rose-100 dark:border-rose-900/50 font-black rounded-2xl flex items-center justify-center gap-2 transition-all"><Trash2 size={18} /> BORRAR</button>}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import { GoogleGenAI, Type, FunctionDeclaration, GenerateContentResponse } from "@google/genai";
import { Transaction, Budget, AIChallenge } from "../types";

export interface ScannedTransaction {
  description: string;
  amount: number;
  date: string;
  category: string;
  type: 'income' | 'expense';
  isTransfer: boolean;
  isSaving: boolean;
  isRefund: boolean;
  suggestedAccount?: string;
}

// Analiza una captura de pantalla o ticket extrayendo múltiples líneas y categorizando inteligentemente.
export const analyzeReceipt = async (base64Image: string): Promise<ScannedTransaction[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: `Analiza esta captura de pantalla de movimientos bancarios (especialmente Revolut) o ticket. 
        Extrae UNA LISTA de todas las transacciones visibles. 
        Para cada una, determina con precisión:
        1. description: concepto claro y conciso.
        2. amount: importe (siempre positivo, usa punto para decimales).
        3. date: fecha en formato YYYY-MM-DD. IMPORTANTE: Si el año no es explícito en la imagen, utiliza SIEMPRE el año actual.
        4. category: categoría lógica que encaje con gastos comunes (Alimentación, Transporte, Ocio, Vivienda, Salud, Compras, Suscripciones).
        5. type: 'income' si entra dinero a la cuenta, 'expense' si sale.
        6. isTransfer: true si es un movimiento entre tus propias cuentas.
        7. isSaving: true solo si es dinero que guardas específicamente para ahorrar (Vaults/Pockets).
        8. isRefund: true si es un Bizum recibido o cobro de deuda.
        9. suggestedAccount: nombre del banco/cuenta (ej: Revolut).` }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            description: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            category: { type: Type.STRING },
            type: { type: Type.STRING, enum: ['income', 'expense'] },
            isTransfer: { type: Type.BOOLEAN },
            isSaving: { type: Type.BOOLEAN },
            isRefund: { type: Type.BOOLEAN },
            suggestedAccount: { type: Type.STRING }
          },
          required: ['description', 'amount', 'date', 'category', 'type', 'isTransfer', 'isSaving', 'isRefund']
        }
      }
    }
  });
  return JSON.parse(response.text || "[]");
};

/**
 * Genera retos financieros personalizados basados en el contexto presupuestario y patrimonial del usuario.
 */
export const generateAIChallenges = async (context: string): Promise<AIChallenge[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Actúa como Aura, asesora financiera experta. Basándote en el siguiente contexto financiero del usuario, genera 3 retos (AIChallenge) realistas y motivadores: ${context}`,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            title: { type: Type.STRING },
            target: { type: Type.NUMBER },
            type: { 
              type: Type.STRING, 
              enum: ['spending_limit', 'savings_goal', 'income_target']
            },
            category: { type: Type.STRING },
            completed: { type: Type.BOOLEAN }
          },
          required: ['id', 'title', 'target', 'type', 'completed']
        }
      }
    }
  });
  return JSON.parse(response.text || "[]");
};

