          soloHuchas: Math.round(totalSavingsYear),
          soloLiquido: Math.round(liquidCapital)
        });
      }
    }
    return data;
  }, [savings, extraSavings, manualContributions, metrics.totalInAccounts, getSavingHistoricalBalance, currentDate]);

